window.SHINAGAWA_DB.years.r08.committeeSessions.push(...[{"id":"r08-20260414-8","meetingId":"r08-m0405","date":"2026年4月14日","dateIso":"2026-04-14","committee":"建設委員会","time":"午後 １時００分～午後 ５時３１分","status":"正式会議録","sourceType":"formal","overview":"建設委員会の会議録から、実質的な質問・確認・意見・要望と答弁・対応を67件整理しています。","topics":[{"id":"topic-01","title":"査を行います。 令和８年陳情第１３号、品川浦周辺地区まちづくりガイドライン策定にあたり、再開発対象地域の住民本位の縮小と、適正かつ公正な居住者の知る権利と居住権の保護を明文化し盛り込むことを求める陳情","agenda":"査を行います。 令和８年陳情第１３号、品川浦周辺地区まちづくりガイドライン策定にあたり、再開発対象地域の住民本位の縮小と、適正かつ公正な居住者の知る権利と居住権の保護を明文化し盛り込むことを求める陳情","exchanges":[{"speaker":"安藤委員","kind":"質問","question":"最初に細かい質問であれなのですが、別紙２の３ページの下から２番目の黒丸で、「品川区が所有している大きい土地を防災施設にしてほしい」とあるのですが、区が、現在、開発区域内に所有しているまちづくり用地とは、どこに、どれぐらいあって、それをどう使おうとしているのかを伺いたいと思います。併せて、まちづくりガイドラインの範囲、４地区を対象にという説明もあったと思うのですけれども、このまちづくりガイドラインの範囲と、この４つの再開発準備組合の地域範囲がなぜ全く同じなのかということを伺いたいと思います。再開発を進めるということが至上命題というか、目的になっている組織なのですけれども、区域が全く同じだとなると、行政も協力して再開発を進めていくというふうに住民がとるということも当然なのではないかと思うのですけれども、品川区としては、そういう意図を持ってこの範囲を合わせたのか伺いたいと思います。併せて、３点目も言ってしまいますが、このまちづくりガイドラインをつくる理由について、改めて伺いたいのですけれども、上位計画があると思うのですけれども、区は上位計画の何を実現するために、このまちづくりを進めようとしているのか、ガイドラインをつくろうとしているのか、改めて伺いたいと思います。","respondent":"大石まちづくり立体化担当課長","answer":"まず、区の用地はどのように使っていくのかというところでございます。恐らくこちらの意見につきましては、今現在、北品川の駅前広場、併せて、任意取得でまちづくり事業用地を旧東海道沿いで進めているところでございまして、こちらのお話をされているのかと考えているところでございます。現在、ここにつきましては、まだどのような活用をするかといったところまでの話はしておらず、今後、地域の皆様としっかりと意見交換をした後に、区として行政需要等を踏まえて今後決定してまいりたいと、このように考えているところでございます。２点目のガイドラインの範囲と再開発準備組合による事業範囲が全く同じなのか、再開発の意図があるのではないかでございます。まず、ガイドラインにつきましては、現在、まちづくりの検討が進められている地域に対しまして、区としての市街地将来像だとか、その具体的な方策等をしっかりと明示するために検討しているものでございまして、原則的には、まちづくりの検討が進められている範囲、今回につきましては再開発の範囲という形で決めているところでございます。だからといって、再開発を引っ張っていくというところの意図は特にございませんで、あくまで再開発ではなく、再開発も含めて、まちづくりに関する将来像をしっかりと区として示していくことが必要と考えているところでございます。３点目の上位計画に書いてある何をつくっていくのかというところでございます。そこの拠点の目指すべき将来像をしっかりと今回のガイドラインでも落とし込んで、区として、地域の将来像の明確な基準になるように、しっかりと示していければと考えているところでございます。","id":"exchange-001"},{"speaker":"安藤委員","kind":"質問","question":"今の質問に対するご答弁といいますか、なぜ品川区がここの地域でまちづくりをしていくのかというのが、正直、見えてこないなと思います。このまちづくり用地について、そういった意見があるのですけれども、これをなぜ再開発種地として取得したのか伺いたいと思います。それでもいいとお考えなのでしょうかとか、「○○をつくりたいから再開発を使って住民をどかせようというのは、乱暴かつ住民の人権を無視した発想」だというようなことが書いてあります。先ほどの陳情者の問いかけ、そうした上位計画や、何々をつくりたいから、今住んでいる方の暮らしを壊すというのは違うのではないかというこの陳情者の問いかけには、区はどのように答えるのか、伺いたいと思います。","respondent":"大石まちづくり立体化担当課長","answer":"先ほどは、説明が不足して申し訳ございません。まず１つは、旧東海道の歴史的町並みの保全や道幅の確保およびにぎわいの維持向上といったところを目的としてございまして、これに当たりましては、地域住民から意見がございましたので、区として、任意取得という形で進めているところでございます。一方で、今後の整備の検討に当たりましては、実際にどのような施設がこの地域にふさわしいのかというところにつきましても、先ほどご答弁したとおり、地域としっかりと話し合って、具体な施設の検討については、今後、区として決定していきたいと考えているところでございます。２点目の上位計画を振りかざしてというところでございますけれども、まず、まちづくりにおきましては、まずは地域住民が主体となって、まちのあるべき姿について、しっかりと課題や将来像を共有し、将来どのような方法で解決していくか、しっかりと話合いを積み重ねていくことが重要と考えているところでございます。また、区といたしましては、今回の陳情もそうですけれども、地域住民からの意見については、しっかりと耳を傾けて、必要に応じて関係者へ伝えるなど、真摯に受け止めてまいりたいと考えているところでございます。","id":"exchange-002"},{"speaker":"安藤委員","kind":"質問・要望","question":"種地ではないということでした。再開発の地域の中にあるものですから、これをどういうふうに活用していくのかというのは、大変重要だと思うので、区としてきちんと主体性を持って、ぜひ住民の意見を聞いて進めていくということを堅持していただきたいと思います。ですから、品川区が、やはり住民の声をまず主体で話し合ってもらう。そのことを踏まえて、再開発準備組合に意向を伝えるというだけではなくて、やはりもっと主体性を持って、ときには住民の方が再開発を本当に望まないと、このようなものは困るのだとなったら、それをストップするぐらいの主体性を私は発揮すべきだと思うのです。それで、意見交換会の報告がありましたけれども、意見交換会当日の冒頭の説明では、なぜか現にある再開発準備組合の検討内容や動きには一切触れないで区が主催しているのです。本日は特定の事業を対象とした説明会ではなく、日頃感じている課題や理想などを伺うものですと案内しているわけです。であるにもかかわらず、この資料を見ますと、別紙２の資料には、再開発について、私は意見はもう完全に二分しているように見えるのです。準備組合への加入も、前回の審査で、７割程度が加入しているので、それは地域の声だみたいな説明もありましたけれども、準備組合の加入は７割程度にとどまっていて、かつ、その７割も、不安だから情報を得るために取りあえず加入している方もいるという現状を見ると、再開発に懸念や反対を示す意見がこれだけ出されているということだと思うのです。これについて、品川区の意見を、受け止めを伺いたいと思います。","respondent":"大石まちづくり立体化担当課長","answer":"１点目の準備組合ではなく区が主体となってというところでございますけれども、当然、区といたしましても、再開発事業に対して不安や懸念があって準備組合と直接お話しすることが難しい方、こういった方につきましては、個別に区にお問合せいただければ、可能な限りのご回答をするとともに、必要に応じて、いただいたご意見やご要望等を私たちが仲介してしっかりと準備組合に届けるなど、私たちとしても丁寧な対応を図ってまいりたいと考えているところでございます。意見交換会で再開発に反対する声が多数あったことに対する区の受け止めは、というところでございますけれども、私も３日間とも参加させていただきまして、当日の熱量等をしっかりと把握してきたつもりでございます。そちらもしっかりと別紙２のほうに書かせていただいておりまして、別紙２のホームページに載せている資料は、出た意見を全て網羅させていただいているという状況でございます。一方で、まちづくりの中で、再開発と切り離してということで、冒頭お話しさせていただいた中で、区が考える課題に対して意見交換を行っていただいたのですけれども、それに対してもしっかりと熱量を持って、皆さん、自分たちのまちは自分たちでこうしていくのだ、こういった課題があるからこうしていこうというところもしっかりと議論されていたと感じているところでございます。そこにつきましては、準備組合がまずは丁寧に対応する。それは準備組合に加入・非加入関係なく丁寧に対応するということをまずは第一に考えなければいけないところでございます。一方で、区といたしましても、先ほど申したとおり、直接お声が届けられないという方に対しては、しっかりと区のほうでも、できる限りの対応はさせていただきたいと、このように考えているところでございます。","id":"exchange-003"},{"speaker":"安藤委員","kind":"質問・要望","question":"やはりまちづくりガイドラインの範囲が、４つの開発区域内とイコールということが、それが少し矛盾をきたしているなと思っています。まちづくりガイドラインというのは、もっと本当は広い大きな概念なのではないかなと思っていまして、一開発企業が主導して行うような、しかも、手法が限定されているような、再開発するかしないかということにとどまらない、もっと大きな住民側の視点を行政はやはり持つべきなのではないかと思うのです。ですから、今のご答弁でも、やはり最終的には、準備組合に要望を伝えますみたいな感じで、それでは、私は、いいまちづくりにはならないと思いますし、あまりに行政の役割としては、範囲を狭め過ぎているというふうに思いますので、しっかり意見交換会でも一定数の反対の声があったことは事実だという把握もしているのだという話でしたので、これが法定のような形で、一定数の賛成数を集めて、どんどん進んでいくというような方向にならないように、品川区としても、しっかり指導性を発揮していただきたいと思います。陳情項目のほうに移りたいのですけれども、項目の１番で、まちづくりガイドラインで再開発手法を望まない住民宅は開発事業に含めないですとか、再開発の対象地域範囲の住民要望に対応した見直しは、地域範囲を住民要望に対応して見直しをということを盛り込むべきだというふうに書いているのです。私もそう思うのですけれども、そういう陳情項目１は、やはり私も盛り込むべきだと思うのですけれども、いかがでしょうかという質問をしたいと思います。陳情項目２については、いろいろ書いてあるのですけれども、その中で、まずは、準備組合の総会の定足数について書かれています。今後は、区として、こういったところを把握、必要な場面では発表するという姿勢になったのだと、そういう姿勢になりましたよということでいいのか、そこについては、少し確認をさせていただきたいと思います。","respondent":"大石まちづくり立体化担当課長","answer":"まずガイドライン策定に当たりまして、説明することを明文化するなどといったお話でございます。まず、ガイドラインは、地域の将来像だとか、まちづくりの目標を示すものでございますので、説明等についてはガイドラインに記載するという性質のものではないというふうに考えているところでございます。一方で、いただいたご意見につきましては、しっかりと区としても受け止めて、まずはまちづくりの前提となる、例えば、合意の形成の仕方など、そういったところをしっかりと準備組合に指導していくというところから、まず、そこから始めなければいけないのかなというふうに考えているところでございます。このため区といたしましては、いただいたご意見も踏まえまして、改めて準備組合に対して丁寧な対応を行うよう指導してまいりたい、このように考えているところでございます。２点目の定足数というお話でございますけれども、定足数につきましては、あくまで準備組合が規約に基づきまして、総会を適正に運営しているものと承知いたしているところでございます。区といたしましては、出席するかしないかというところも、業務の関係上いろいろあって、できるかできないかはあるのですけれども、区としては、しっかりと定足数が規約に諮られて、適正に運営されているものというところはしっかりと把握していきたいと、このように考えているところでございます。","id":"exchange-004"},{"speaker":"安藤委員","kind":"質問・要望","question":"すみません、まちづくりガイドラインのことですけれども、陳情項目１に書いているのは、要するに、住民、再開発を望まない住民の家を外してということだと思うのです。なので、正確には、という話がありましたけれども、私は、そのガイドラインが今再開発の準備組合の区域とイコールになっているので、これ自体もどうなのかなと思います。ですから、ガイドラインに、そういう住民要望に応じて対象地域を柔軟に変えていくとか、そういったことはやはり盛り込むべきなのではないかと、盛り込んでいただきたいなというふうに思います。陳情項目２の把握していきたいということでしたので、どうやって把握するのかということはあるかもしれないのですが、ぜひここは、区として把握していきたいという答弁が出ましたので、ぜひ把握していっていただきたいですし、必要な場面で発表していただきたいと思います。陳情項目２に関わって、都市計画審議会についても書かれているのですけれども、こちらも前回の違う陳情で出されて審議もされました。先日の予算特別委員会でも私も質問させていただきました。現状、人選の改善や、また、現在、品川区の元まちづくり担当の部長が委員長を務めているという点について、改善される方向性が今あるのか、改めてこれについて伺いたいと思います。あと、陳情項目２の内容に関わって、もう一つ伺いたいのですけれども、不利益な情報がたくさんあるのだと、でも、隠されているのだという記述があります。タワーマンションの再開発では、弱小権利者の方々が、マンションに入るために膨大な持ち出しが求められたり、入った後も、住み続けるためには、従来かからなかった高額の管理費や修繕積立金などの負担が必要になったり、結果的に住み続けられなくなるというデメリットがあると思うのです。そうなのではないかなと思うのですけれども、区としては、住民の不利益事項は一体何だと考えているのか、どういうことが不利益だと考えているのか伺いたいですし、それらが住民に十分に説明されないまま進められているという点について、問題と思っているのか伺いたいと思います。","respondent":"大石まちづくり立体化担当課長、高梨都市計画課長","answer":"私からは、再開発の区域と都市計画審議会以外のご質問についてお答えさせていただければと思います。まず、まちづくりガイドラインの地区でございますけれども、こちらは冒頭に申し上げたとおり、現在、まちづくりの検討が進められている地区を対象に設定したところでございます。この再開発の地区は誰が決めているのかというところでございますけれども、こちらにつきましては、あくまで地域の皆様が話合いの中で決めたと聞いているところでございまして、準備組合の設立総会のときにも、規約に載せまして、決議をとってこの範囲を決めていると認識しているところでございます。区といたしましては、その中でまちづくりの検討が進められているということを前提に、再開発とは限らないのですけれども、まちづくりの将来像をしっかりと提示することが必要だと考え、この地域を指定しているところでございます。２点目の住民にとっての不利益となることでございますけれども、こちらにつきましては、各個人に置かれる状況によって異なると思いますので、一概に申すことはできないのですけれども、例えば、先ほど委員がおっしゃられたとおり、タワーマンションでの固定資産税の増加だとか、管理費の増加、こういったところも１つあるのかなと認識しているところでございます。ただ一方で、こういったことを準備組合がしっかりと説明をすることがまずは重要なことであると考えておりますので、区といたしましては、準備組合に対しまして、改めて再開発の事業とは一体どういったものなのか、こういったところをしっかりと権利者の皆様にお伝えするように、改めて指導してまいりたいと、このように考えているところでございます。都市計画審議会についてのご質問に私のほうからお答えをさせていただきます。この会長は、改選が行われた際に都市計画審議会の委員の互選により指名がされているというような形で選ばれているものでございまして、今後の方向性といたしましては、今年の７月が委員の改選の時期に当たりますので、そのときにまた新しい会長が選ばれるということですので、私のほうでは、会長が代わるかどうかといったことについてはコメントできない状況でございます。ただ、この間、議会のほうから、そういったご意見があるといったところにつきましては、委員のほうにはお伝えしてまいりたいと、このように考えていることでございます。都市計画審議会の委員につきましては、この間、議会のほうから、いろいろお話が出ているといったような状況を受けまして、昨年、学識経験者を２名増員いたしまして、今まで１７名の委員の体制だったところを１９名の委員ということで増員するなど、必要な改革を行ってきているような状況でございます。","id":"exchange-005"},{"speaker":"安藤委員","kind":"質問","question":"分かりました。繰り返し説明を聞いていると、やはりまちづくりの検討が進められている地域を対象に、区としては、まちづくりガイドラインの区域を設定して、その区域は地域の方が話合いの中から決めたものだと認識していて、それを前提にして、区としては、まちづくりの将来像をそこに示すことが必要だからということなのですけれども、やはり少し出発点が間違っているといいますか、やはり再開発の準備組合は７割の人しか入っていない。しかも、さっき言ったように、７割の人の中でも、みんながみんなもろ手を挙げて入っているわけではない、入らないと情報が出ないのではないかということで入っている人もいる。ですから、そこの再開発の準備組合の動きに区がかぶせていくような動きをしてしまうと、品川区自体が、行政が再開発を後押ししているように当然見えるわけです。そういったことが再開発を推進する力にもなってしまいかねないというところもあるので、私は、そうしたところからは、やはり脱皮をして、そもそもまちづくりガイドラインというものでありますから、もっと広い概念で、一住民の立場に立って、再開発するかしないかというところに立たない、そこにとどまらないまちづくりを検討すべきだと思うのです。それはしっかり説明することが必要だと考えているのだと、そういう指導はしていくということなのですけれども、この陳情者の方が陳情項目２で言っているのは、現在、住民が悩まされている再開発事業についての居住権の配慮ですとか、あるいは、適正かつ公平な情報を取得する権利ですとか、それを盛り込んでもらいたいと、文字どおりの広い意味でのまちづくりのガイドラインにしてほしいということを書いていると思うのです。これについては、ぜひ盛り込むべきなのではないかと思うのですけれども、最後に伺います。","respondent":"大石まちづくり立体化担当課長","answer":"居住権への配慮でございますけれども、先ほど申したとおり、このガイドラインが、まずはまちづくりの将来像をしっかりと示すもので、いわゆるまちづくりの計画に当たるものでございます。このようないただいた居住権の配慮は、その前提になるものだと考えてございます。しっかりとそこは地域で、今、準備組合等としっかりと話し合って、まずは住民理解を得るということが重要だと考えてございます。その上で、区としてまちづくりの将来像をしっかり示すことで、地域住民の意見が反映されたまちとなるように、ガイドラインの策定作業を進めているのですけれども、様々地域から意見をいただいているところでございまして、当初予定しておりました令和７年度末の策定につきましては見直しをしておりございます。今年度も意見交換会の開催、幅広く地域からの意見を吸い上げて、より皆様の意見を反映できるような形でガイドラインの策定を進めていきたいと考えているところで、現在、策定の時期につきましては、まずはまちづくりの状況を踏まえながら、今後、考えてまいりたいと考えているところでございます。","id":"exchange-006"},{"speaker":"中塚委員","kind":"質問・要望","question":"品川浦の再開発ということで、対象地域の住民本位の縮小、知る権利、居住権の保護の明文化を求める陳情であります。今回の陳情者は、２回目の陳情ということで、それだけに強い決意、気持ちを私は感じております。住民の皆さんが議会に陳情する際に、とても勇気が要るという話も伺います。藁をもつかむ思いで陳情されるというお話も伺います。ぜひその気持ちに私自身も応えたいと思いますし、品川区に至っては、それだけの強い決意、切実な声、切実な訴えだということを、まず正面から受け止めていただきたい。また、建設委員の方々には、前回、この陳情者の方の陳情に対して、反対をしたのは、自民党と公明党としながわ未来ということで、反対多数で不採択となりましたけれども、今日の質疑を通じて、ぜひ区民の声に向き合って賛成していただきたいと、まず呼びかけたいと思います。つまり、この意見交換会において、タワーマンションをつくってほしい、高層化を進めてほしい、再開発を進めてほしいと、そういう意見はなかったということでよいのか伺います。私も先ほどから区が全てホームページに掲載しておりますという資料、この別紙２を見て、様々住民の言葉が寄せられておりますけれども、さっき私が紹介したタワーマンション建設を進めてほしい、高層化を進めてほしい、再開発を進めてほしいという意見は、どこを見ても私には見当たらないのです。なので、品川区に伺いたいと思いますけれども、そうしたタワーマンション建設などの高層化や再開発を進めてほしいという意見はあったのか、なかったということでよいのか伺います。","respondent":"大石まちづくり立体化担当課長","answer":"意見交換会において、いわゆるタワーマンションの建設を進めるという意見があったのかというところでございますけれども、こちらにつきましては、冒頭申したとおり、再開発とは切り離して意見交換会を開催してございまして、区が考える４つのテーマ、４つの課題でございますけれども、こちらを区から説明をして、これに対して主な意見をという形で意見交換をしていただいたというのが流れでございます。なので、「再開発」というワードは、キーワードとしては、反対されている方につきましては、しっかりとお声はいただいたところでございますけれども、そのほかの方につきましては、再開発を前提に話を進めている意見交換会ではないということがありますので、タワーマンション化の推進という言葉としては出てきておりませんが、そういった趣旨で開催したものではないということだけはお伝えさせていただければと考えてございます。","id":"exchange-007"},{"speaker":"中塚委員","kind":"質問","question":"「タワーマンション」という言葉も「再開発」という言葉もなかったという説明です。ただ、冒頭に説明があって、区の４つのテーマがあって、それについての意見交換をしたということですけれども、その４つのテーマというのは何だったのか改めて伺いたい。そのテーマ、課題を解決する手段として、再開発を進めてほしいという意見がなかったということでよいのか伺います。恐らく防災とか、にぎわいとか、水辺とか、いろいろなことがこの４つの中に入っているのかなと思うのだけれども、その課題解決のための手法として、再開発をやってほしいという意見はなかったということでよいのか伺います。ざっくりと聞いても、区ははっきりなかなかおっしゃってくれないのだけれども、陳情者も知りたいでしょうし、私も知りたいので、反対多数の意見交換会は、今後、まちづくりガイドラインにどう反映するのか伺います。","respondent":"大石まちづくり立体化担当課長","answer":"まず、意見交換会でのテーマでございますが、別紙１の資料の２枚目に書かせていただいてございまして、まず１点目が「水辺の魅力を活かせていない」のではないか、２点目が「安全・快適な自動車・歩行者ネットワークが形成されていない」、３点目が「防災性に不安を抱えている」、４点目が「人が集まれる施設が不足」していると。こちらはあくまで区のほうで考えた今の現状分析という形で提示させていただいたものでございます。委員からご指摘のありました、では、こちらの課題を再開発で解決するという意見はあったのかなかったのかというところでございますけれども、再開発でというよりは、この町をどうしていきたいのかというところに主眼を置いている意見交換会なので、そういったご意見はありませんでしたけれども、まちづくりでどのように解決していくか、それはこの後のどういった手法を選んでいくかというところの次のフェーズだと考えてございます。あと、この意見は、今後どう反映されるのかというところでございますけれども、先ほど申したとおり、今年も意見交換会やアンケート調査等をやっていく予定でございます。というのも、前回、昨年１２月に開催した意見交換会でも、やはり参加人数が少ないのではないかといろいろ意見をいただきまして、陳情もいただいたところでございます。そういった中で、区として、より多く、よりきめ細やかに意見を把握するためには、１つアンケートという手法も検討しているところでございますので、それらの意見を集約した上で、今後、どのように記載をしていくかは考えていきたいと考えているところでございます。","id":"exchange-008"},{"speaker":"中塚委員","kind":"質問・要望","question":"４つのテーマは、水辺の魅力、交通ネットワーク、防災、人が集まれる施設、また、これではないのではないかという意見に対して、自由闊達に意見交換がされた上で、再開発でこれを解決してほしいという意見はなかったというのが今の区の説明です。今後、手法については次のフェーズだということですが、次のフェーズに移行するまでもなく、この魅力、ネットワーク、防災、人が集まれる、この課題解決に再開発という手法、そのようなことを言っている人は１人もいなかったわけです。次のフェーズで議論するまでもなく、再開発という手法はやめるべきだと、これが区民の声だと、地域の声だと、区が主催した中で１人もいなかったのですから、今の課長の説明では。ですから、手法については次のフェーズだという説明がありましたけれども、次のフェーズにて再開発という手法はとるべきではないと、次のフェーズで再開発という手法を検討する必要はないと思いますが、いかがでしょうか。反対多数の意見交換会、今後どうするのか、きめ細かいアンケートということですけれども、ぜひ反対されている方々の理由だったり、ご事情だったり、でも、一方で、こういう方法もあるのではないかと。様々な意見もあると思いますので、そこは丁寧に聞き取っていただきたいと思いますが、このアンケートは、スケジュール的には今後どのように考えているのか、アンケートの内容とともに伺いたいと思います。","respondent":"大石まちづくり立体化担当課長","answer":"再開発という手法をとるべきではないというご意見でございますけれども、あくまでまちづくりの手法につきましては、地域の皆様が主体となって、何を選択していくかというところが重要かと考えてございます。まず、区といたしましては、そもそもどのような手法を使うかというよりかは、どのようなまちを目指していくかというところに視点を当ててございますので、このようなガイドラインにつきましては、地域の将来像をしっかりと地域の意見を踏まえた上で策定していきたいと考えているところでございます。２点目のアンケートのスケジュールでございますけれども、現時点では、いつやるかというところはまだ決まってはいないのですけれども、現時点で、まずは意見交換会を開催した後に、アンケートを聴取したいと考えているところでございます。また、意見交換会につきましては、昨年、年末は忙しいという、いろいろ意見もございましたので、少し早めに秋頃の開催を予定しているところでございます。目標といたしましては、年内にアンケートの配布をしたいなと考えているところでございますが、具体的な日程については、これから検討してまいりたいと考えているところでございます。また、アンケートの対象範囲や設問数、どういった項目にするのかというところも、今はまだ検討しているところでございます。","id":"exchange-009"},{"speaker":"中塚委員","kind":"質問・要望","question":"手法については、地域の方々が主体的に選択していくとおっしゃいますけれども、区が主催した意見交換会の中で、先ほども強調しましたが、一人も再開発を進めてほしいという人はいなかった、タワーマンションを建ててほしいという方もいなかった、高層化をしてほしいという意見もなかったというわけです。これをゆがめて、今後、再開発に区が誘導していくことは決してあってはならないと強く求めておきたいと思います。そして２つ目ですけれども、陳情の中に、再開発の対象地域の範囲を決めたときに、何の話合いの場もありませんでしたとあります。その上で、品川区としては、この決定に賛成しているのか、別な言い方をすると、容認しているのか、ほかの言い方をすると、決定は決定だと思っているのか、尊重しているのか、いろいろな言い方があるかと思いますけれども、少なからず、何の決定権もなく勝手に決められたものだと私は思っておるのですけれども、品川区としては、要するに、決められたものだというふうに受け止めているのか、そこを伺いたいと思います。それに関わって、陳情者の方は、何の話合いもなく、聞き取りもありませんでしたということで書いておられますけれども、なぜ話合いもなく範囲が決められたのか。もっと言ったら、全て対象者の方々に、こういう決定をするのですけれども、賛成ですか、反対ですかと、準備組合なのか、その会議の場なのか、様々な場で、何の話合いもなく決められたのかと。なぜ話合いもなく範囲が決められたのか、そこについても伺いたいと思います。","respondent":"大石まちづくり立体化担当課長","answer":"準備組合の範囲につきましては、先ほどもご説明したとおり、準備組合の設立時点において、対象範囲を規約に定め、総会において承認されているものと、区としては認識しているところでございます。区が賛成している、容認しているというお話がございましたが、こちらにつきましては、私たち区が、ここにしてくださいとか、ここは駄目ですというものではなく、あくまで地域が主体で検討しているものでございますので、そういった受け止めをしているところでございます。また、設立時点で約７割の方が参加されているというところで、一定のまちづくりの機運が高まっているのかなというところで、区としては、賛成、反対というところではないのですけれども、そういった形で今後検討が進められていくというふうに受け止めていたところでございます。区といたしましては、当然７割が多いか少ないかという議論もございますので、１人でも多くの方によってまちづくりの議論が交わされるということが望ましい形だと考えてございます。準備組合に加入したからといって賛成ということでは、区としては受け止めておりませんので、まずは１人でも多くの方が参加していただいて、より多くの議論を生んで、よりよいまちをつくっていただければというふうに考えているところでございます。また、なぜ話合いがないまま決められたのかというところがあったかと思うのですけれども、こちらは先ほどの答弁と重複するところがございますが、あくまでこちらは７割の方が加入している準備組合の中で決めたものというふうに認識しているところでございます。","id":"exchange-010"},{"speaker":"中塚委員","kind":"質問・要望","question":"私がここが再開発で一番腹が立つところなのですけれども、７割の方が勝手に決めて、３割の人の意向を無視する。このようなことが許されていいのですか。７割の人がここからここまでと決めたら、そこにいる３割の方は出ていくか、床に残るか。このような決めた方でいいのですか。先ほど、区は賛成しているのかということに対して、賛成しているとは言わないけれども、その７割の人が参加して決めた準備組合の決議で決まったものと、これは区は認めているということですよね。だから、品川浦周辺地区まちづくりガイドラインの範囲は、この７割の人が勝手に決めた範囲を踏襲しているわけですよね。７割の方が参加している準備委員会で、３割の人の財産を奪う。このような決定は決定とは言わない、もっと丁寧にやりなさい、正確にやりなさい、きちんとやりなさい、そういうことが少なくとも開発を所管する担当課の言うべきことではないのかと思いますけれども、いかがでしょうか。「その後の生活がままならなくなってしまう住民宅を再開発区域から除外する方向での見直しを要望します」ということです。先ほどの答弁とも関わってくるのですけれども、ということは、区としては、区域の変更は準備組合には求められないということなのか。いやいや、将来的には補助金を何百億円という税金で投入するわけですから、区も所管する行政として、ここの区域は変更を求めることができるということなのか、陳情者の方は、要するに、再開発区域から除外してほしいということだと思いますけれども、区は準備組合に、区域の変更、つまり、仕組みとして除外を求めることができるのか。それができるというのは、お願いベースなのか、それとも強い権限を持つ区の要請なのか、そこも踏まえて伺いたいと思います。結論だけではなくて、どういう質問があって、どういう答弁を区がしたのか、そういう質疑の様子は、ぜひ品川区都市計画審議会の委員に資料として渡していただきたいし、対面での説明もしていただきたいし、品川区都市計画審議会の質疑が、私も淡々としているなといつも思うのですけれども、この議会の熱量、区民の熱量が伝わっていないなと思うのです。それだけに、本会議や建設委員会での質疑をぜひ伝えていただきたいと、前も要望したと思うのですけれども、そこのところはいかがか、まとめてになりましたけれども、それぞれご答弁ください。","respondent":"大石まちづくり立体化担当課長、高梨都市計画課長","answer":"まず、７割の方で決めた範囲を区は容認しているのかという点でございます。こちらは繰り返しになりますけれども、あくまでも準備組合に加入されている７割の方たちが総会で決めたというところが事実としてはございます。区が容認するとか、そういうものではなくて、区がこれからここでいろいろな方の話合いが行われてまちづくりが進められていくというところは、区としては認識しているところでございます。これに対して、区が範囲から外せというところを指導できるのか、仕組み上できるのかというところにもつながるのですけれども、こちらは、仕組みとして、できる、できないというところよりは、皆様の話合いの中で、ここをどうしていくかというところで、その中で、例えばスリム化、陳情書にもありますとおり、スリム化されるのであれば、まちづくりのガイドラインにつきましても、それと連動して、そういったスリム化を図っていくことも検討してまいりたいと考えているところでございます。なお、補助金というお話がございましたけれども、現状、こちらの地区につきましては、令和８年度までの都市計画決定が、一応、今のところされる予定ではございませんので、現状としては、外れる地区になっているところでございます。都市計画審議会への議会や委員会での議論の内容の伝達につきましては、前回も答弁させていただきましたが、現在、都市計画審議会の各委員には、各案件について事前の説明に伺う、もしくは区のほうに来ていただいて、お時間を頂戴して説明をさせていただいているところでございます。そこで一定程度、議会の動き等についても情報提供をしているところでございますが、答弁や質疑の資料提供については、今後、説明の中で、どのような形でできるか検討してまいりたいと考えてございます。","id":"exchange-011"},{"speaker":"中塚委員","kind":"質問・要望","question":"７割の方が３割の方の財産を奪うという問題ですけれども、その決定については、容認するものではないと、今、課長がおっしゃいました。ぜひ品川区として行政を担っているわけですから、少なくとも地域の方々が強く反対しているこの品川浦の再開発は、１ミリも進めるべきではないと、まずはアンケートの話、スケジュールはまだということですけれども、丁寧な住民の意見の聞き取りを強く要望したいと思います。今以上に丁寧な対応を強く求めておきたいと思います。なぜ私たちは追い出されなければいけないのかと声があがっている。端的に、今後どう進めていくのか、体制であったり、スケジュールであったり、まずは何よりも反対をされている、疑問をお持ちでいる、追い出されると声を上げている、こうした進め方はおかしいのではないかと、くくれば批判的な区民の方々の意見を丁寧に酌み取っていただきたいと思いますが、最後の検証分析のところ、どういう体制なのか、スケジュールなのか、現状をお示しいただきたいと思います。","respondent":"中道都市開発課長","answer":"先日の予算特別委員会で、構造的な課題があるということは区のほうから答弁させていただきました。都市再開発法の中では、いわゆる３分の２以上の同意の中で事業を進めていくという法律があって、区としては、より多くの方の同意を得て進めていくというところにはなりますけれども、一方で、逆に読むと、３分の１の反対者がいても進めていけるというようなところ、反対者がいても進めていけるというところが、反対、様々な陳情にもつながっているのかなと解釈はしているところでございます。法律のことになりますので、こちらは、まずは国と様々な場を踏まえまして、そういったところで意見交換をしていきたいと考えてございます。国との意見交換場も、そう度々あるものではないので、そういった機会を捉えて、意見交換ができればと考えてございます。それにつきましては、区といたしましても、まちづくりニュースの中でそういったご説明をする、または、疑問等がありましたら、区にどんどんご連絡いただいて、ご理解、内容の把握に努めていければと考えるとともに、予算特別委員会の場でもご説明したとおり、また、専門家の方々の相談窓口も設置していって、そういった事業の理解の促進を図っていきたいと考えてございます。","id":"exchange-012"},{"speaker":"ゆきた委員","kind":"質問・要望","question":"１点だけ確認させていただきたいと思います。陳情項目の２のところで、「地上げ屋による放火等の防犯も要望します」ということで記載されていますが、こういった不安の声について、区で行っている支援とか、情報提供などを行っていく、区として対応をされるのか、こういった点についてお聞きできればと思います。","respondent":"大石まちづくり立体化担当課長","answer":"昨年、品川区小山で発生いたしました放火事件に関する開発につきましては、まずは、こちらは民間の開発行為でございまして、いわゆる法定の市街地再開発事業ではないということは確認しているところです。一方で、陳情書でご不安の声が寄せられているところでございまして、この１件が、まちづくりに対する区民の不安を大きくする事象であったと区も捉えているところでございます。また、町会・自治会や商店街などの地域団体が防犯カメラを設置する際に、補助金で支援を実施するとともに、個人宅において防犯対策品を購入、設置した場合に、費用の一部を助成するといった対策をしてございます。こういった取組を、区にご不安が寄せられた際には、必要に応じて情報共有を行ったり、寄せられた方にご紹介するなど、区として、実施している事業をしっかりと積極的にアピールして、しっかりと防犯対策にも寄与していきたいと考えているところでございます。","id":"exchange-013"},{"speaker":"せお副委員長","kind":"質問・要望","question":"本日結論を出すで、不採択でお願いします。そこの相互理解だったり、合意形成だったりというところがなされるように、基本的には、地域準備が中心となるわけですけれども、区が引き続き間に入って、１２月にもワークショップを開催してくださいましたし、これからアンケートもするということですので、引き続き、できるだけの対応をお願いしたいということは要望しておきます。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-014"},{"speaker":"松永委員","kind":"質問・要望","question":"本日結論を出すで、不採択でお願いいたします。また、個別の調整については、今後の具体的な計画づくりの段階で、地権者の皆さんが主役となって、じっくりと話合いを重ねてつくっていくべきものであります。現段階で、特定の除外のルールを急いで決めるものではなくて、かえって将来の１０年的な話合いで、私たちは決めていくべきではないかと思います。先ほど、ゆきた委員からもありましたように、区の指導とか監督については、今後も法令に基づいてしっかりとやっていただきたいと思っております。最後に、先ほども意見交換の後にアンケートを皆さん一人ずつとっていく、または、先ほど、せお副委員長もありましたけれども、全体に、ぜひ皆さんが、方向性をどう求めているのかということを把握しながら進めていくべきだということを考えております。ということで、今すぐこうしたところで決めていくというのではなく、またしっかりと話し合いながら決めていくべきだということを理由として不採択とさせていただきます。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-015"},{"speaker":"ゆきた委員","kind":"確認","question":"本日結論を出すで、不採択でお願いいたします。陳情項目１については、再開発地域については、地域全体の一体的なまちづくりを前提として策定されるものであり、地域主体の合意に基づいた検討区域を基本としているということを確認させていただきました。また、陳情項目２についても、ガイドラインに合わせてとありますが、ガイドラインでは、あくまでまちづくりの方向性を示すものであるということも確認させていただきました。最後に、防犯についても、先ほど答弁がありましたが、不安の声について、区で行っている支援については、情報提供する中で、寄り添った対応を進めていくという姿勢を確認できましたので、本陳情については、不採択でお願いいたします。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-016"},{"speaker":"安藤委員","kind":"質問・要望","question":"本日結論を出すで、採択なのですが、やはり開発企業主導の超高層開発は、イコールまちづくりでは決してないと思うのです。先ほどのやり取りの中で、一人でも多くの住民の方に準備組合に参加してまちづくりについて話し合ってもらいたいという区の答弁もありましたけれども、やはり再開発準備組合は、もう再開発を推進するための組織なので、これがまちづくりとイコールのような、そういった認識は、私は改めていただきたいなと思います。区長も、まちづくりの主体は、そこに住む地域住民と述べているわけですから、それを仮に現実とするのであれば、やはり陳情者がここで求めているような再開発地域の住民意見に応じた見直しですとか、圧倒的に有利な立場に立つ開発企業の横暴を抑える適切なルールやガイドラインを区が持つということは私は必要なことだと思います。したがって、本日の陳情は採択すべきだと考えます。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-017"},{"speaker":"中塚委員","kind":"質問・要望","question":"今日結論を出すということと、採択でお願いします。陳情のタイトルにも書いてあるとおり、「品川浦周辺地区まちづくりガイドライン策定にあたり、再開発対象地域の住民本位の縮小と、適正かつ公正な居住者の知る権利と居住権の保護を明文化し盛り込むこと」を、私も品川区に求めるべきだと思います。今日のやり取りの中でも、陳情者の方々の思いが区に届いていない、受け止めてもらえていないということが明らかですので、品川区議会として、建設委員会として、これらを品川区に求めるべきだと思いますので、採択でお願いいたします。最後に、都市開発課長から、今後、国と意見交換の場があると、あとまた、窓口も設置するということでしたので、ぜひ建設委員会に、動きがある場合にはご報告いただきたいと思います。区が何を求めて、国がどのような回答があったのか、窓口がどのように設置され、運用されているのか、見通しがついた時点で、建設委員会に報告していただきたいと要望しておきたいと思います。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-018"}]},{"id":"topic-02","title":"報告事項を聴取いたします。 初めに、(1)東京における都市計画道路の整備方針の策定","agenda":"報告事項を聴取いたします。 初めに、(1)東京における都市計画道路の整備方針の策定","exchanges":[{"speaker":"安藤委員","kind":"質問","question":"２点伺いたいのですが、まず、補助１６３号線が優先整備路線になったのですが、現に生活を営んでいる住民もいらっしゃる路線だと思うのです。その中で、どうしてもこれを整備しなくてはいけないとは、私たちは認識していないのですけれども、具体的な整備事業効果について、区としては、どのように認識しているのか、改めて伺いたいと思います。把握していないとしたら、今回の優先整備路線の決定を受けて、行政としては、いつ当事者の声を伺う考えなのか伺いたいと思います。","respondent":"高梨都市計画課長","answer":"補助１６３号線につきましては、これまでも補助２０５号線から区役所に至る路線について整備を進めてきた。また、大井町と大崎を結ぶ重要な道路であるというように認識してございます。現在、住宅の戸数が何戸かにつきましては、今後、事業化に向けた検討を行う中で把握してまいりたいと考えてございます。","id":"exchange-019"},{"speaker":"安藤委員","kind":"質問・要望","question":"大井町と大崎を結ぶ重要な道路とだけ言われても、特にそれで、今、あそこを拡幅と言っても、何路線にもなるわけではないわけですし、路線が、車線が増えるわけでもないと思うのです。今のままでは、私たちとしては、これを整備する必要性に当たらないのではないかなと思っているので、もう一度、そこについて、必要性をどういうふうに考えているのか、整備事業効果は何だと考えているのか、もう１回ご答弁いただきたいと思います。それともう一つは、補助２９号線とか放射２号線などの特定整備路線なのですが、こちらはもう本当に住民の反対運動もありますし、また、道路整備が地域コミュニティや環境に与える悪影響ですとか、延焼遮断の防災のためというのですけれども、効果も非常に限定的だという点から、むしろこれは事業を廃止して、住民のために活用する事業用地、そういったことこそ必要だと考えているのですけれども、今回は検討の対象にも入らないということなのですよね。事業中であっても、私は、こういう特定整備路線も、必要性などを踏まえて廃止するかどうか検討すべきなのではないかなと、今回なぜ検討の対象外とされたのか。私は、廃止も含め検討すべきだったのではないかなと思うのですけれども、そうしたことに対して、区として何か意見を言ったということもあるのかということも含めて、この辺の区の認識を伺いたいと思います。","respondent":"高梨都市計画課長","answer":"最初に、補助１６３号線についてでございます。こちらについては、計画幅員１２ｍの計画道路ということで、現状も、両車線、１車線ずつ、合計２車線の道路ということで、車道については供用がされているところでございます。安全な歩行者空間の確保等々を含めて、大井町と大崎を結ぶ当該道路は必要な路線である、早期に事業化を図っていくべき路線であると、区としては認識しているところでございます。今回、都市計画道路の整備方針について、前提としては、未着手の都市計画道路について、必要性や優先的に整備を進めていく路線について検討する。もしくは、必要性がないものについては廃止や計画内容を変更していくというところで、検討を進めたところでございます。事業化に当たりましては、必要性が確認され、国から事業認可を取得して事業が進められているものでございますので、それらの路線について、今回の検討対象から除外するといったことは、区としても同意をしているところでございまして、この点について、会議の中で発言をした等のことはございません。","id":"exchange-020"},{"speaker":"安藤委員","kind":"意見","question":"他県とかでは、事業化後でも見直しをするとか、事業化後どころか、かなり道路を造って整備したにもかかわらず、廃止するというところもやはりありますので、そこら辺は柔軟に対応していく必要があるのではないかなというふうに思いましたので、意見を述べさせていただきます。最後に少し補助１６３号線の、これ、道路行政のこれからの手続の話になってくるかもしれないのですけれども、実際にそこに住んでいる方への働きかけというか、意見聴取とかは、具体的には、どの段階で、これ、優先整備の路線に引き続き指定されたということは、１５年の間に事業着手するということが予定されていると思うのですけれども、具体的にどういうところで、どういう働きかけがいつ行われるのかというところだけ最後にお聞かせください。","respondent":"森道路課長","answer":"都市計画道路を実際に、具体的に進めていこうと考えたときには、事業認可を取得することがまず一つ、動きとしてございます。こちらにつきましては、東京都に、この路線をこの区間内でやっていくというようなところを申請して、事業を具体的に進めていくことになります。その事業認可がおりますと、用地の取得に関わってくるわけなのですけれども、その用地に実際に関わってくる方に対して、具体的なお話として用地の測量や用地をお売りいただくことについての説明が、出てくるかなと思います。具体的に補助１６３号線につきましては、広町の新庁舎、それから新設道路の建設が進んでおります。また、昨年度、債務負担行為等の議決をいただきましたけれども、そこの大崎線の交差部、そこにつきましても、今、ＪＲと具体的なお話をさせていただいているところでございますので、１５年のうちで着手を目指すというところで、具体には、まずは庁舎の前からになってくるのかなと思っておりますが、関係する方も多いと思われますので、丁寧な説明をさせていただければと思っています。","id":"exchange-021"},{"speaker":"中塚委員","kind":"質問","question":"東京における都市計画道路の整備方針ということで、この間、何回か質疑をさせていただきました。振り返ってみれば、今、道路課長が最後のほうにおっしゃった補正予算の負担行為に、かれこれ１年半ぐらいですか、この計画を議論させていただきまして、私もいろいろ述べさせていただきました。この計画は中止すべきだと思っております。それを述べた上で、品川区としては、新たな整備方針に何を期待しているのか、冒頭説明がありましたけれども、具体的に、補助１６２号線、補助１６３号線、補助２０５号線については変更ということですけれども、この３路線について、この１５年間で何を期待しているのか。２０５号線については、１５年以降と言ったほうがいいのかもしれませんけれども、それぞれ整備方針で何を期待しているのかを伺いたいと思います。私は、期待しているものの中の重要な１つが、再開発事業だと思います。こうしたものは進めるべきではないと多くの住民が願っていると思いますが、その点も伺いたいと思います。","respondent":"高梨都市計画課長","answer":"昨年度末になりますが、このたび、東京における都市計画道路の整備方針（案）、東京都とともに、関係区市で公表いたしまして、向こう１５年間で効率的に進めていくべく計画を発表させていただきました。何を期待するのかといったところでございますが、こういった形で、東京都、都市計画道路を有する自治体全体で計画を公表しているわけですから、しっかりと優先整備路線であるとか、また、廃止候補路線等も、今ご説明させていただきましたとおり、品川区の区が担当する路線として載せさせていただいている路線がございますので、この計画期間内に事業着手であるとか、また、計画廃止であるとかといったような手続がしっかりと進められていくように、所管としては、しっかりと計画的に進めていきたいと、このように考えているところでございます。","id":"exchange-022"},{"speaker":"中塚委員","kind":"質問","question":"補助１６２号線、補助１６３号線、補助２０５号線、具体的にこれらの路線は、この計画上は再開発を念頭に置いたものではないと改めてご説明がありました。今年、１月１９日の建設委員会でもこの議論をさせていただいて、今日の資料にも載っているのですけれども、整備方針の概要版の４ページに、基本目標４、都市環境の向上に、都市の再開発ということで事業が掲載されていると。ここに載っていることは区はお認めになるけれども、補助１６２号線、補助１６３号線、補助２０５号線は、個別具体的なものは念頭にないということです。そこで伺いたいのですけれども、１月１９日の答弁も改めて見ましたけれども、課長の説明で、優先整備路線の選定の中でも持続可能な地域へのまちづくりの貢献ということで、市街地再開発事業や鉄道立体化事業などの連携を図っていくような地区については、優先的にそういったところに関して、路線は優先整備路線に選定されるということが、この計画の中に位置づいているとおっしゃっております。つまり、再開発事業や鉄道立体化交差に連携している場合は優先整備路線に位置づいていくという計画だとすれば、まさに補助１６２号線の品川浦、補助２０５号線の原踏切のところが、再開発、そして立体化交差そのものだし、補助１６３号線も再開発そのものだと思います。そうした事業が行政計画の上位計画として存在しているから、優先整備路線として優先的に路線が選定されたという関係に私はあると思うのですが、いかがでしょうか。","respondent":"高梨都市計画課長","answer":"まちづくりの進捗に合わせて、各自治体で、都施行であれば東京都が、各路線の優先的に整備を進めていく。その背景に様々な事業があり得るといったところは、今、委員からご紹介があったとおりだと考えてございます。一方で、品川区の路線で、実際に、今回、補助１６２号線、補助１６３号線、優先整備路線、区施行の路線につきましては、記載をさせていただきました。ご案内のとおり、実際、建物を建てる際には、前面等の幅員であるとか、そういったところが大きなファクターになっているといったところは事実でございますけれども、まだ、機が熟していないような段階で、品川区として優先整備路線を特例の再開発事業を念頭にした上で、仮に設定をするのであれば、例えばで申し上げますと、補助１６２号線につきましては、先ほども陳情審査で議論がございましたが、品川浦周辺地区のまちづくりが今検討されている地区外の部分も優先整備路線として区間が指定されているところでございます。逆に、検討されている区域の中に入っている路線は、優先整備路線に指定されていないといったようなところもございます。","id":"exchange-023"},{"speaker":"中塚委員","kind":"確認","question":"そろそろ終わりにしますけれども、まちづくりの進捗に合わせて都市計画道路を整備していることはそのとおりだと。しかし、補助１６２号線、補助１６３号線、補助２０５号線などを具体的には念頭にはないとおっしゃいます。例えば、今おっしゃった補助１６２号線については、確かに、品川浦の、いわゆる区域の外である。また、区域の中は優先整備路線としては指定されていないと私も確認しております。しかし、それは裏返すと、品川裏の中の都市計画道路は、補助１６２号線につながっているのです。例えるならば、補助２９号線が進むことによって補助３１号線につながっていくという、補助３１号線だけ先に決定するということは、道路の入り口と終わりがありませんから、やはり一筆書きなのです、道路事業というものは。それは私が言うまでもなく、区の理事者のほうがよくご存じだと思いますけれども、そういう意味で、品川浦の補助１６２号線は、まさに今後、品川浦の再開発が進むインフラ整備の第一段階だと私は思っております。いずれにしても、補助１６２号線の今回の整備は、まさに品川浦を今後進めるに当たっての第一弾だと私は思います。補助１６３号線については、まさに区役所前ですから、ここが事業認可されないと、区の現庁舎の跡の建物の建築許可が下りないわけです。そういう関係で、補助１６３号線も新たな再開発につながるものだと思います。補助２０５号線については、現状の計画ではどうしても原踏切が横須賀線と新幹線の関係で難しいというところで、立体化交差という手法をつくって、さらに規模を大きくすることで道路の道幅を広くしたり、もちろん歩道を造ったりという考え方もあるでしょうけれども、新幹線の橋脚に沿って計画を進めていく。いずれにしても、新たな再開発をつくっていく地域を広げていく本計画は、中止すべきだと述べて終わりたいと思います。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-024"},{"speaker":"ゆきた委員","kind":"確認","question":"東京における都市計画道路の整備方針の１３８ページに、大井町駅前中央通りについて、先ほども議論がありましたように、補助１６３号線、来街者の増加を見据えたにぎわい創出や回遊性向上の取組として社会実験が実施されていると記載があります。一方で、整備方針に関するパブリックコメント、資料の別紙３に、パブリックコメントでは、この路線に関する具体的な意見が、私が見つけられなかっただけかもしれないのですけれども、確認できなかったところです。前回の委員会では、区において、約３週間にわたり社会実験を実施し、約１２０件の意見を把握しているとのことで、４月のまちづくり特別委員会にて報告するとも伺っていましたが、現時点で把握している範囲でどのような傾向が見えてきているのかお聞きしたいと思います。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-025"}]},{"id":"topic-03","title":"(3)令和８年度からの不燃化特区支援制度等","agenda":"(3)令和８年度からの不燃化特区支援制度等","exchanges":[{"speaker":"安藤委員","kind":"質問","question":"不燃化特区支援制度と整備地域等不燃化集中促進制度との違いが何なのかということを伺いたいのですけれども、例えば、利用する区民から見て、助成金額の差がどれぐらいあるのかとか、あるとしたら、どれぐらいなのかを伺いたいことが１点です。それと、放射２号線と補助２８号線の沿道地区は、不燃領域率が７０％に達したため除外とあるのですけれども、７０％という数字は、どのような効果があるのかを伺いたいと思います。","respondent":"小川木密整備推進課長","answer":"１点目の不燃化特区支援制度と整備地域等不燃化集中促進支援制度との違いでございます。資料裏面に記載しているところでございますが、不燃化特区支援制度に関しましては、工事費が助成対象となりますけれども、集中促進支援制度に関しましては、工事費は対象外という形になります。金額に関しましては、不燃化特区支援制度、それと整備地域等集中促進支援制度に関しましては金額に違いはございません。２点目の放射２号線および補助２８号線で達成いたしました整備目標、不燃領域率７０％の効果でございますが、こちらに関しましては、不燃領域率というのは、市街地の燃えにくさを表す指標でございまして、この不燃領域率が７０％に達成しますと、延焼による火災被害が、ほぼゼロになるといったところで、阪神・淡路大震災から得られた知見として示されている指標でございます。","id":"exchange-026"},{"speaker":"安藤委員","kind":"質問","question":"ありがとうございます。７０％で延焼がゼロになるということなのですが、この２つの地区は、沿道地区全体が７０％に達したということです。ですから、私は、道路そのものを造る必要性がもうなくなったのだと思うのです。なので、この２つの路線については、事業廃止を東京都に働きかけるべきなのではないかと思いますけれども、特に放射２号線などは、現道がない住宅地を買収していますし、住民の反対の声も特に強いという路線です。なおさらだと思いますので、いかがでしょうか。１つ目の質問です。不燃化特区における手厚い支援である住宅の建て替え、不燃化支援事業を、全区にやはり拡大するということが耐震化を徹底的に進めることになると思うのですけれども、そういう点での、この不燃化特区の拡大に関する区の認識を伺いたいです。それが耐震化を徹底的に進めることになると思うのかどうかという認識を伺いたいのと、仮に、その実現に向けての課題といいますか、こういった手厚い建て替え支援を全区に広げていく上での課題は何だと考えているのか伺いたいと思います。","respondent":"高梨都市計画課長、小川木密整備推進課長","answer":"私からは、特定整備路線について、答弁をさせていただきます。特定整備路線、補助２９号をはじめとする区内の路線でございますけれども、特定整備路線は道路整備とともに、沿道の建物を不燃化を図ることで、延焼遮断帯を形成するとともに、道路自体も避難路や緊急車両の通行路となるため、防災上非常に必要な道路であるというふうにとしても認識しているところでございます。市街地の不燃化、耐震化と、延焼遮断帯や避難物、緊急車両の通行路となる特定整備路線を複合的に重層的に進めていくことが防災まちづくりとして重要なことである、このように認識しているところでございます。建物の不燃化促進に当たりましては、委員おっしゃられたとおり、建て替えをすることと同時に、耐震にも期するといったところで効果が出てくるといったところでは、そういった効果もあると認識しているところでございます。我々不燃化促進に関しましては、まずは危険な場所から集中的に、そして、重点的な取組を行って、不燃化促進を図っているといったところで進めているところでございまして、まずは、特に危険度の高い不燃化特区において取組を行っているところでございます。全区的に行うに当たっての課題でございますが、不燃化特区支援制度につきましては、非常に充実した助成内容、金額の設定をさせていただいておりまして、そういったところでは、区域を拡大することによって、財政的な負担が大きくなるといったところが、課題の１つとして考えられるのかなといったところで認識しているところでございます。","id":"exchange-027"},{"speaker":"安藤委員","kind":"質問","question":"ありがとうございます。すみません、最初に聞けばよかったのですけれども、放射２号線と補助２８号線の沿道地区は、除外ということで７０％に達したということなのですが、補助２９号線沿道地区の不燃化領域率は、現在、何％なのか、それだけ最後にお伺いします。","respondent":"小川木密整備推進課長","answer":"最新の時点が令和７年１２月時点の不燃領域率の数値になりますけれども、補助２９号線沿道に関しましては、５４.８％でございます。","id":"exchange-028"},{"speaker":"中塚委員","kind":"質問・要望","question":"不燃化特区支援制度ということで、木造住宅密集地域における地震火災およびこれに起因する延焼火災等の被害を防ぐため、とても必要な事業だと理解しております。また、裏面の新たに実施する支援ということで、高齢者・障害者等居住世帯への建て替え加算助成が２３区では初めて品川区で始まったということで喜ばしいと思います。先ほどの質疑で、なぜできないのかというところで、支援が充実しているので財政負担だという説明がありました。財政負担とおっしゃるのであれば、例えば、この1)、2)、3)、新たな支援事業、それぞれ全区で実施する場合は、１年間の中で幾らぐらいの財政負担となるのか伺いたいと思います。区の予算は２,０００億円を超えていますので、先ほど財政負担だとおっしゃったので、新たに支援する事業1)、2)、3)、それぞれ区内全域に拡大した場合は、年間で幾らの予算が追加で必要になるのか、そこをご説明いただきたいと思います。区内全域でということですが、昔から集中的にするのか、区内全域でやるのかといろいろ議論を重ねてきたところなのですけれども、木造住宅密集地域は、火災が発生した際、広がりやすいから集中的にやるという話はよく伺います。しかし、準耐火建築物、つまり、木造の新築の建物であれば、隣で火災が発生しても、建築課に伺いたいのは、何時間耐えられるのかということを伺いたいのです。防火の窓ガラス、軒下の防火、あと、壁自体の防火、いわゆる準耐火建築物は、たしか１時間とか２時間かかる、これも建築課長に教えていただきたいのですけれども、一定期間、隣の火災を防ぐだけの素材を使っているというお話を伺うのです。そう思えば、木造住宅密集地域に集中するということも大事なことではあるのだけれども、やはり区内全域に広げて、一つ一つの建物を耐火にしていく、更新していく、建て替えていく、耐火補強をしていく、こうした考え方に立つべきだと思うのですけれども、いかがでしょうか。３つ目、ここの関わりなのか、私の勘違いだったら言ってほしいのですが、感震ブレーカーが木造だけだったものが、非木造、つまり、マンションも対象になりました。これも区内全域に広げていただきたいのですけれども、ごめんなさい、私の勘違いで、もう全域になっていたらご説明いただけたらと思います。","respondent":"小川木密整備推進課長、森建築課長、遠藤防災体制整備担当課長","answer":"私からは、１点目の区内全域に広げた場合、幾らになるかといったご質問についてでございます。こちらは試算しているわけではございませんので正確な数字を申し上げることはできませんけれども、こちらの資料の２ページ目の３つの加算助成を行うに当たっては、この資料の上にも記載してございますが、今現在、実施をしている、除却であったり、設計であったり、工事費の助成金も対応しなければいけないというふうな形になってございます。今年度、おおよそで８億３,０００万円ほどの予算を不燃化特区でいただいているところでございます。８地区でこの数字でございますので、これを区内全域に広げた場合は、相当な金額がかかると、私どもとしてはイメージをしているところでございます。準耐火建築物が耐えられる時間ですけれども、準耐火建築物は、通常の火事等に４５分間耐えられるようにしなければならない、構造的なクラック等が入らないようにしなければならないとなってございます。私からは、感震ブレーカーの区内全域への展開についてでございます。また、東京都も感震ブレーカーの動き、また、今年度、東京都が新たに被害想定を示すといったところで、国や都の動向を踏まえながら、全域に展開していくべきかどうか、今後、検討していきたいと考えています。","id":"exchange-029"},{"speaker":"中塚委員","kind":"質問・要望","question":"まずは、新たに実施する支援ということで、試算はしていないということです。ただ、後半の説明で、３つの事業で、年間で８億３,０００万円ということです。地図を見た感じでは、これを５倍ぐらいにすれば区内全域になるのかなと。ぱっと見た感じですけれども、４２億円ぐらいでできるとするならば、区の財政力を思うと、また、区民の安全安心を思うと、財政的にこれが負担だということにはならないと思うのです。なぜならば、これ、全部区の負担ではありません。一般財源ではありませんから、これを財政上の理由でできないというのはぜひ改めていただきたいと思います。改めて、ぜひ試算をした上で、区の負担がどれぐらい増えるのか、財政負担という根拠は、ぜひ試算をしていただきたいと思いますが、いかがでしょうか。２点目の木造住宅密集地域のことですけれども、そうなのです、４５分間。隣の家で火災があっても、窓を閉めていれば、準耐火建築物であれば、４５分間、燃え広がらない、そういう設計になっているのです。ですから、準耐火建築物にお住まいの方は、家を出かけるときには窓を閉めて出かけていただきたいと。つまり、その４５分間の間に消防が、また、ご近所の方々が火元を消し止めることができれば、燃え広がらないということになるのです。なぜならば、消防士の方の前で言いづらいのですけれども、消防士が活動するエリアを保障しないと、ポンプを持って消火活動はできませんから、燃えている家の結構離れたところにポンプ車を置いて、そこからポンプでつないで火を消すのが消防隊の動きだと聞いたことがあります。ぜひ区内全域に広げていくということを考えていただきたいのです。質問としては、効果はあるけれども、財政負担だけが原因なのか、効果としては全区に広げたほうがいいと思っていらっしゃるのか、この点を伺います。３点目、最後、感震ブレーカー、ぜひ区内全域に広げていただきたいと思います。マンションまで対象になったことはうれしい前進だと思いますけれども、先ほども述べたように、一つ一つの建物を安全にしていくことが何よりも必要ですので、こちらは要望しておきたいと思います。最後に、さっき、放射２号線と補助２８号線の沿道の不燃化率が７０％で、もう燃え広がらないから、道路を造る必要がないという指摘があって、私もそのとおりだと思いました。ただ、補助２８号線は、池上通りでありまして、池上通りが廃止されてしまうと車が通れないので、廃止は、あくまで現行から広げる部分と私は思っております。その点は要望だけしておきたいと思います。","respondent":"小川木密整備推進課長、遠藤防災体制整備担当課長","answer":"不燃化特区の区域、区内全域への拡大についてのご質問でございます。東京都と協調補助で取り組む支援制度になっておりまして、都の指定基準では、整備地域という、特に震災時、甚大な被害が想定される地域にまずは絞って、そこで特に危険な地域を指定して、まずは危険度の高いところを早急に、そして効果的に不燃化を促進していくということで取り組んでいるところでございます。我々区といたしましても、まずは危険なところから集中的に、重点的に、かつ早急的に、そういったような危険を取り除いていきたいと考えているところでございます。区内全域に広げれば、それはそれで、やるに当たっては効果は一定あるのかなと思いますけれども、やはり時間といったところの時間軸も見ていかなければいけないとは捉えておりますので、まずはそういった危険な地域を集中的に早急な改善を行っていくといったところで取組を引き続き行っていきたいと考えてございます。先ほど、感震ブレーカーの区内全域への支援の展開の検討の件で、１点訂正といいますか、まず、感震ブレーカーに関しましては、現在、木造住宅を中心に支援をしているところでございます。また、東京都におきましても、今年度、新たな被害想定の検討を始めるといったところで、国や東京都の動向を見ながら、今後、区全体で感震ブレーカーを非木造についても導入するかどうかの検討を進めていくといったところで、現在、採用しているものではないといったところを改めてご答弁させていただきたいと思います。","id":"exchange-030"},{"speaker":"中塚委員","kind":"質問・要望","question":"感震ブレーカーについては、早急に検討を加速していただいて、区内全域で、マンションも含めて、感震ブレーカー補助が実施されるように強く要望しておきたいと思います。冒頭の不燃化特区支援制度の財政負担についてなのですけれども、財政負担というのであれば、改めてきちんと試算を示すべきだと質問しましたので、この点は答弁いただきたいと思います。なのに、なぜ東京都の協調を強調するのか私は分かりません。大きな火災や地震から区民を守るためには、東京都の協調というよりも、区民の暮らしや生活こそ直視すべきだと思いますが、いかがでしょうか。震災の被害が甚大とおっしゃいますけれども、被害想定の出し方は、簡単に言うと、道路幅だったり、木造・非木造の割合であったり、あとパーセントであったり、そういう数式によって出てきたものであって、甚大な被害を防ぎたいというのであれば、だからこそ、地域だけではなく、一つ一つの建物を安全にしていくという考え方に立つべきだと思うのです。例えば、前も言いましたけれども、不燃化特区８区、不燃化集中促進地区２区に含まれていない私の住んでいる西大井五丁目ですけれども、では、被害が甚大ではないかと言えば、地震が来れば崩れるような古い建物は残っているわけで、恐らく旧耐震の建物だろうなと見て分かる建物も残っているわけです。被害の甚大さを強調するのであれば、やはり一つ一つの住宅を安全にしていく、この視点に立って考えるべきだと思いますが、最後にいかがでしょうか。","respondent":"小川木密整備推進課長","answer":"区内全域を対象とした場合の試算でございますけれども、こちらに関しては、なかなか全域に対して試算することは非常に難しいのかなといったところで今考えてございます。まずは不燃化特区、今、指定しているところに関して、しっかりと集中的に取組を行っていきたいと考えているところでございます。また、都との協調補助の考え方でございますけれども、この資料の２ページ目2)番、3)番目に関しましては、都の協調補助として一緒に行っているところでございますが、1)番に関しましては、過年度に戸別訪問で区独自で行って、そのヒアリングの中で、やはり高齢者単独の世帯での建て替えが、なかなか費用負担等の要因で進まないといったようなお声を非常に多くいただいたところでございます。そういった声に区独自でしっかりお答えさせていただくと、対応させていただくといったところで、今回、提案をさせていただいて、1)番の加算助成に関しましては、区独自策としてやらせていただくと。都の協調補助をより補填させるために、しっかりと加算助成を行うといったところで取り組ませていただくものでございます。そういうお声はたくさんいただいているところではございますが、まず、現実的にその地域よりも危険なところがありまして、その辺りを優先的にしっかりと取り組んでいきたいといったところで、今、この８地区で取組を行わせていただいているところでございます。","id":"exchange-031"},{"speaker":"ゆきた委員","kind":"質問","question":"今回の取組は、大変意義のある取組だと感じています。一方で、前回の委員会で都市防災不燃化促進事業についても同様の質問をさせていただきましたが、高齢者と障害者の世帯ほど、こうした世帯ほど制度の情報が届きにくく、結果として活用されない懸念もあると感じています。前回の都市防災不燃化促進事業の答弁では、対象者への直接的なパンフレットの配布、福祉系の協議会などでの案内、福祉系イベントでのパンフレットの配布について話がありましたが、対象者へのキーパーソンとなる方々へのアプローチの仕方について、福祉部門とどう連携してアプローチしていくのかお聞きしたいと思います。","respondent":"小川木密整備推進課長","answer":"高齢者の方や障害者の方への周知方法についてでございますけれども、先日の都市防災不燃化促進事業の条例改正のときのご答弁から特に変わったところはないところでございます。福祉部署としっかりと連携して、まだ具体的などこでといったような内容は確定しておりませんが、関係団体の集まるところに出向いていったり、あと、福祉イベント等でチラシを持っていって、周知をしっかりと行っていきたいと考えてございます。その際には、不燃化の促進の事業だけではなく、建築が行っている耐震化の事業であったり、感震ブレーカーの事業であったり、そういったものも連携しながら、一緒に周知を徹底していきたいと考えているところでございます。","id":"exchange-032"},{"speaker":"ゆきた委員","kind":"質問・要望","question":"ありがとうございます。今の段階について、確認できました。日常的に接点のあるケアマネジャーとか、あと地域包括支援センターの職員が個別支援を行う中で制度案内を行うことができれば、さらに活用できる可能性が非常に高くなってくると思いますので、そういったところにもアプローチしていくということを一つ考えていただければと思います。要望で終わりたいと思います。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-033"},{"speaker":"松永委員","kind":"質問・要望","question":"ご説明ありがとうございます。これはしっかりと伝えさせていただきたいと思います。その中で、要望が２つありまして、１つは、先日、ニュースでも報じられたとおり、大手最大メーカーが、中東情勢の悪化によって、原材料不足を理由に新規受注を当面停止するという事態に追い込まれました。設備そのものが手に入らない、あるいは、価格が予測不可能という異常事態に注入している中で、区が今回示す助成額について、しっかりと予算をとっていただいていることは分かるのですけれども、こうした状況も踏まえて、さらなる助成額の引上げを要望いたしますが、いかがでしょうか。２つ目の要望でございますが、こうした行き先不透明な時代の中で、多くの高齢者世帯は不安を感じていると思います。今、建て替えるべきではないかという不安です。","respondent":"小川木密整備推進課長","answer":"まず１点目の物価高等による今の経済情勢等への対応でございますけれども、こちらに関しましては、適宜、工事費であったり、設計費であったり、単価の見直しを行ってございます。直近では、今月の１日から工事費が、今、何％とは具体的には言えないのですけれども、かなりの額を上げして対応をさせていただいております。こちらは東京都と連携して、金額について決定するものでございますので、引き続きしっかり東京都と連携を行いながら、物価高等へ対応していきたいと考えてございます。あと２点目の高齢者への意向調査等につきましては、今、各地域でまちづくり協議会などを設けていますので、そういったところの協議会の中でも、どういったやり方で周知していけばいいかとか、意向をどう捉えていけばいいかということは、地域の皆様と一緒に考えていきたいといったところでございます。","id":"exchange-034"},{"speaker":"松永委員","kind":"質問","question":"ありがとうございます。それもとても大事になるのですけれども、私が言いたかったのは、今度、新規で、高齢者・障害者・要介護者に対して１５０万円の加算助成と書いてあるではないですか。あと、高齢者他多世代同居への２００万円、これをもう少し増やせないかなということでございますので、その辺について伺いたいと思います。","respondent":"小川木密整備推進課長","answer":"こちらの、今年度から新たに行わせていただきます加算助成の額につきましては、本年度の申請状況等を踏まえながら、見させていただいて、額の上乗せが必要かどうかは今後判断していきたいといったところでございます。","id":"exchange-035"},{"speaker":"せお副委員長","kind":"質問・要望","question":"ご説明ありがとうございます。すみません、私が理解できていないのかなと思うのですけれども、この３の（１）の3)の未接道敷地の建て替えのための解消促進加算助成、これ、意味は分かるのです、重要だと思うのですけれども、どういう状況の方がこれを利用できるのかということが少し分からなくてということと、年間どれぐらいの件数を見込んでいるのか教えていただきたいです。","respondent":"小川木密整備推進課長","answer":"3)番の未接道敷地の建替えの状況でございます。この資料の図にありますが、道路に接道していない後ろの建物がございます。こちらは道路に接続しておりませんので、建て替えができない建物になります。ですので、このままの状態ですと、どんどん建物が老朽化して古くなっていって、行き着くところでは空き家になってしまうとか、そういうような一因になってしまうといったところで、非常に課題があるところでございます。こういった建物を少しでも解消するために、こちらの資料で言いますと、接道している右側の建物の土地所有者の方から、土地の一部を譲っていただいたり、貸していただいたり、もしくは、全体を統合するような形で共同住宅を建てたりとか、そういった取組をすることによって、この左側の建物が解消されます。こういった取組に対する測量であったり、仲介費であったり、そういったものに加算助成をさせていただくといった取組の内容になってございます。","id":"exchange-036"},{"speaker":"せお副委員長","kind":"意見","question":"ごめんなさい、どれぐらい件数を見込んでいるのか教えてください。","respondent":"小川木密整備推進課長","answer":"失礼いたしました。今年度に関しましては、８地区、今、不燃化特区をやっているのですけれども、そのうちの１地区は大井二丁目という１町丁目で１地区という指定になって、エリアが非常に狭くなっているので、７地区と捉えまして、７地区で各１件という想定で今年度の予算は組ませていただいているところでございます。","id":"exchange-037"},{"speaker":"せお副委員長","kind":"質問・要望","question":"ありがとうございます。状況は分かるのですけれども、この図でいくと、この２軒は全然違う世帯というか、他人なわけですよね。なかなか、いや、あるのかなと思って、ごめんなさい、少し細かい話で申し訳ないのですけれども、意味としてはすごく重要だなと思っていまして、進めていっていただいて、先ほどの話にも、松永委員からもありましたけれども、進めていただいて、今後、課題とかが出てくれば、見直していただきたいなと考えていますので、よろしくお願いします。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-038"}]},{"id":"topic-04","title":"(4)品川区耐震改修促進計画の改定","agenda":"(4)品川区耐震改修促進計画の改定","exchanges":[{"speaker":"中塚委員","kind":"質問・要望","question":"大きく２つ伺いたいと思います。品川区耐震改修促進計画、これは初めてできたのは何年前だったでしょうか。なので、建て替えも耐震の１つだという位置づけですので、今後、品川区耐震改修促進計画、建て替えへの支援も強めていくことが必要ではないかと思うのですけれども、ぜひ、まずは目標達成に向けて、実態に即して改修していただきたいと思うのですけれども、この間を振り返って、現状と今後を伺いたいと思います。もう１点は、先ほどの議論と重ならないようにしたいのですけれども、品川シェルター設置支援、ここを何とかアイデアと区民への共感というのでしょうか、進める時期にしていただきたいなと思っています。今回から高齢者・障害者等の助成拡大ということで、１０分の１０を掛けて、高齢者・障害者のところに、いわゆる建築部門が接近するわけですよね。お年寄りに話を聞くと、「いや、災害が起きると大変なんだよ」と強調すると、「もうそのときはそのときよ、人の迷惑になりたくないから」という話にどうしてもなりがちなのです。また、ニュースを見ると、心配だけれども、なかなか自分の経済力では建て替えは難しいし、自分が亡くなって相続で受け取った娘、息子たちが建て替えてもらえたらとおっしゃるおじいちゃんやおばあちゃんもいらっしゃって、いやいや、あなたの命が何よりも大切なんだということをどう伝えたらいいのかなと、私も日々悩ましいところでもあるのです。そのときはそのときよという気持ちの方にも、どう接したら分かってもらえるかというところも実践の中で工夫していく。福祉部門は、高齢者への接近に専門的なアプローチの仕方、専門性を持っておりますので、こうした力も借りていただいて、この品川シェルターを、言わば、今期、実績を広げていただきたいと、大きく２点伺いたいと思いますが、いかがでしょうか。","respondent":"森建築課長","answer":"品川区耐震促進計画をいつからやっていたのかというところですけれども、一番最初の耐震診断助成は、平成１６年から助成を開始しております。品川区耐震促進計画自体は平成１９年度より、計画を定めて進めてまいりました。その次に、建て替え支援、建て替えだけでも支援していったらどうかというところなのですけれども、区では、今、除却助成を行っておりまして、もともと建て替え助成も行っていたのですけれども、ほぼ内容が除却助成と同様でございまして、除却助成のほうがかなり申請も多くなっている状態でございましたので、除却助成費を上げて、今、支援しております。ここは委員ご指摘の福祉部門とも連携いたしまして、様々進めてまいりたいと思っております。今年度は、区民の皆様に広く意見を賜れないかと考えておりまして、皆様にお伺いして、どういうふうな進め方がいいのかも含めて、品川シェルターの在り方について考えてございます。","id":"exchange-039"},{"speaker":"安藤委員","kind":"質問","question":"まず、９５％目標達成は、なかなか容易なことではないと思うのですけれども、区の認識はいかがでしょうか。達成に向けては、事業の年次計画なども策定して、年度ごとの達成状況を公表して推進するみたいなことも必要なのではないかと思うのですけれども、いかがでしょうか。それとあと、制度の周知啓発なのですけれども、直接的な働きかけ等もありますけれども、例えば、防災訓練の場ですとか、あるいは講演会を行うですとか、戸別訪問による直接的な情報提供や働きかけなど、大小あらゆる機会を通して制度の周知を徹底するということも必要なのではないかと思うのですけれども、いかがでしょうか。３点目は、今回、２０００年基準で耐震化目標を定めるのは木造住宅のみと書いてあるのですけれども、８割の方はマンションに住んでいたりするわけではないですか。ですから、そういったマンションですとか、あるいは緊急輸送道路沿道建築物も、今回、２０００年基準でとはなっていないのですけれども、影響の大きさとか、居住する人の多さとかを考えると、こちらの建築物が新耐震基準のままでよいのかなということが少し気になったので、そちらについても伺いたいと思います。","respondent":"森建築課長","answer":"耐震目標の数値でございますけれども、数値としては、なかなか達成が難しいかなと思うような数値でございますけれども、しっかりその数字を目指して５年間やっていきたい、意欲的な目標ですが頑張っていきたいと考えてございます。そういう模型を見ていただいたりとか、具体的に見ていただいて周知を図っていきたい、そのように考えてございます。３つ目の２０００年問題、木造だけだけれどもいいのかというところなのですけれども、２０００年問題の木造は、木造の構造計算がそもそも設計者に委ねられていたというところがございまして、木造の部分の金物であったり、壁の配置等で少し不具合が起きていて、木造住宅の新耐震については少し不具合があるというところでございます。鉄筋コンクリートや鉄骨造、そういうところでは、旧耐震と新耐震、かなり違いがございまして、新耐震になっていれば、鉄筋コンクリート、それから鉄骨造は、基本的には倒壊するようなことも少ないとなってございますので、２０００年以前に建設された木造に絞ってございます。","id":"exchange-040"},{"speaker":"安藤委員","kind":"質問・要望","question":"分かりました。それと、周知については、避難訓練等という話もありましたけれども、様々徹底していただきたいと思います。目標達成、率直になかなか難しい数字だという話もありましたけれども、いきなり５年後に９５％というのではなくて、やはり年次、年度ごとの達成状況なども見据えながら進めていくということが、スモールステップをつくっていくというか、そういったことも必要なのではないかと思いますので、建設委員会等にも報告などもしながら、そういった形で、順次、小目標みたいなものを、数値目標みたいなものをつくって、ぜひ達成に向けて頑張っていただきたいなと思います。これは要望です。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-041"},{"speaker":"ゆきた委員","kind":"質問","question":"私からは、耐震改修について、費用とか、あと工事の負担面から、実施が困難な世帯が多いということが現状だと思います。改修できない層の命をどういうふうに守っていくのかということが課題であると思いますし、先ほど議論の中であった品川シェルターについて、私も質疑しようと思っていたのですけれども、もういいやと思う方々をどうやって守っていくか、これも非常に大事だと思います。品川区耐震改修促進計画の３１ページに、品川シェルターについて記載されています。昨年の決算特別委員会で現状をお聞きした際は、これまでの実績が累積で２２件、直近年度は相談もないと課長答弁もありました。ここに書かれている広報紙、ケーブルテレビとか、各種ＳＮＳとか、あと、しながわ防災体験館で模型展示というのは、今までもやってきたことなので、これから、新たに示された５年計画、品川区耐震改修促進計画の中で、これからの５年間の計画のプロセスの中でどういったことが必要で、今後の展開に向けていくのかというところをお聞きしたいと思います。","respondent":"森建築課長","answer":"なかなか費用面等で耐震改修できない方々がいるということで、委員ご質問のとおり、品川シェルターをぜひお薦めしたいと考えてございます。そのような中、どうやってアプローチしていくかというところなのですけれども、先ほどもありましたけれども、福祉部門としっかり連携して進めていきたいということと、区民の皆様に、品川シェルターをどうしたらいいのかというところを１回お聞きしたいということがございます。前回、委員からありました増やしたらどうかとご質問があった、耐震ベッドについて、品川シェルターに限らず、東京都が認めている耐震シェルターでもいいのではないかなど、いろいろご意見がございましたので、幅広に考えていって、区民の命を守る施策をやっていきたい。そのためには、委員の皆さんデジタルプラットフォーム等で聞いて、どのように進めていったらいいのか、周知も含めて、進めていくべきか、しっかり考えていきたい、そのように考えてございます。","id":"exchange-042"},{"speaker":"ゆきた委員","kind":"質問","question":"ありがとうございます。昨年の決算特別委員会でも、私、質疑をさせていただきまして、耐震シェルターについて、状況により助成対象とするか検討していくと、ほかの耐震シェルター、品川シェルター以外の耐震シェルター。耐震ベットについても様々検討していくと答弁がありました。一方で、現状では、品川シェルターのみが助成対象となっているため、選択肢が限定されていることが、普及が進まない一因であると考えています。国の基本方針では、耐震改修を基本としながらも、実施が困難な住宅については、耐震シェルターや耐震ベッドの設置などにより、最低限、人命を守る対策を講じることが重要であると明確に位置づけられています。また、東京都の計画においても、こうした対策は耐震改修を補完する減災手法として整理され、市区町村における具体的な施策展開が前提とされています。その前提に立てば、選択肢が限定されていることで普及が進んでいない現状については、国や都の方針の関係から見ても、改善の余地があるのではないかと考えますが、改めて最後にお聞きしたいと思います。","respondent":"森建築課長、新妻委員長、立木品川区清掃事務所長","answer":"その部分につきましては、委員ご指摘のとおりでございますので、様々意見を踏まえながら検討してまいりたいと考えてございます。ほかにご発言がないようですので、以上で本件を終了いたします。──────────────────────────────────────────── (5) 区長会における「清掃事業の課題」に関する検討経緯等について私からは、区長会における「清掃事業の課題」に関する検討経過等について説明いたします。２３区のごみ量は、１人あたりの量は減少傾向でございますけれども、人口増に伴い総量は増加が見込まれています。加えて、今後、清掃工場の建て替え時期が集中することから、ごみの全量焼却体制を維持するため、東京二十三区清掃一部事務組合の第６次一般廃棄物処理基本計画の検討に当たり、現在使用していない灰溶融炉を、焼却炉として置き換え可能な５工場の焼却能力拡大に関する論点を中心に、２３区として議論を進めてまいりました。ごみ量の推計についてですが、計画の検討に当たり、施設整備費の高騰、ごみ減量への対応から、今後のごみ量の推計については、従来の手法による推計に加え、２３区一斉開始を想定した３つの施策、こちらに記載があるものでございますが、こちらの減量効果を含む推計と比較することといたしました。推計の検証に当たって、区長会は「清掃工場整備計画に関する検証委員会」を設置し、その答申を受け議論をした結果、２３区の実態を最も反映した「清掃一組推計」を用いた施設整備計画を策定する方針を確認いたしました。今後の対応方針でございますが、２３区一斉開始を想定した３つの施策について、資源化可能な事業系古紙の工場搬入規制および廃棄物処理手数料の増額の２つの項目につきましては、ロードマップを策定し着実に進めることとし、家庭ごみの有料化については、引き続き実現に向けた検討を進めることとしました。最後になりますが、東京二十三区清掃一部事務組合の第６次一般廃棄物処理基本計画の原案の概要版を添付いたしました。現在、清掃一組のホームページで、全文、概要版ともに公開されまして、令和８年４月１９日までパブリックコメントが実施されております。１ページ目に計画の概要、２ページ目にごみ量の推計がまとめられております。３ページ目に、施設整備計画がございます。原案の計画によりますと、令和１３年度より、建て替え計画および環境影響評価等の手続を開始いたしまして、令和１８年度をめどに建て替え工事の着手を計画予定としているところでございます。説明が終わりました。本件に関しまして、ご質疑等がございましたら、ご発言をお願いします。","id":"exchange-043"}]},{"id":"topic-05","title":"(5)区長会における「清掃事業の課題」に関する検討経緯等","agenda":"(5)区長会における「清掃事業の課題」に関する検討経緯等","exchanges":[{"speaker":"安藤委員","kind":"質問","question":"すみません、まず、報告事項の件名が「区長会における『清掃事業の課題』に関する検討経過について」となっているのですけれども、一枚目に続いて、資料として、第６次一般廃棄物処理基本計画の原案がついています。この関係はどういう関係になるのかということをお伺いします。これが都民が、区民が聞かれても少し分からないような資料になっているので、この資料でいうと、２番のところのごみ量推計というところの（４）辺りが、１ページ目に書いているような有料化を前提とした減量効果を含めて書いているという理解でよろしいのでしょうか、そこら辺を伺います。","respondent":"立木品川区清掃事務所長","answer":"こちらの今回の区長会のまとめの公表についてでございます。ごみの全量焼却、こちらを今後も続けていくというところを諮るに当たって、今後、清掃工場の施設の建て替え、整備計画のほうも、順次建て替えていかなければならないということを前提とした中で、ごみを全量焼却できるような形で進めていくに当たりまして、まずは今後のごみの推移、今後のごみの推計をしっかり出されなければ、整備計画も立てることができないというような前提の中で、２３区区長会の中でも、そういったところに取り組んで検討を進めてきたというような関係性でございます。今回まとめて公表になりました内容に関しましては、先ほど説明をさせていただきましたとおり、清掃工場整備計画に関する検証委員会、こちらも設置し、そちらに諮問した結果、どういった推計を用いて今後計画をしていくことが望ましいかというようなところの議論をした結果、今回このようなまとめの公表に至ったところでございます。","id":"exchange-044"},{"speaker":"安藤委員","kind":"質問","question":"続けて質問しますけれども、共産党としては、書いてあるような家庭ごみの有料化はやるべきではない、反対だという立場です。２点質問したいのですけれども、区としては、有料化によって、一時的なごみ減量効果はそのときは発生するかもしれないのですけれども、またリバウンドで戻るという、そういう指摘もあるのですよね。家庭ごみの有料化は減量効果があるのだと品川区としては考えているのか伺いたいのが１点と、それと、森澤区長は、ごみ有料化については、慎重に検討と発言していたと思うのですけれども、今日の資料を見ると、区長会としては、実現に向けた検討を進めると書いてあるのですよね。これは、やはり品川区としては、有料化に反対する意見を私は出すべきだと思うのですけれども、そういうような発言をすべきだと思うのです、それはいかがでしょうか。そういう発言をしたのだけれども、多数でこうした実現に向けた検討を進めることになったということなのか、その経緯についても伺いたい。","respondent":"立木品川区清掃事務所長","answer":"これまでもお話をさせていただいているとおり、家庭ごみの有料化につきましては、ほかの自治体でも導入されておりまして、ごみの減量が図られたというような事実もございますことから、導入することによりまして、ごみの減量化につながることを否定するものではないというようなスタンスでございます。あと、区としてのスタンスでございますけれども、今回、区長会のほうで出されたものに関しましても、有料化については、２３区一体で検討が行われていくことと認識しておりまして、導入に当たりましては、やはり日々の生活でしたりとか、区民負担につながるものでございますので、慎重な検討を十分重ねる必要があると考えているところでございます。","id":"exchange-045"},{"speaker":"安藤委員","kind":"質問","question":"２３区一体で進めていくべきことだというコンセンサスがあるのであれば、区民負担につながるということになりますので、やはり大本、それが本当に現状の根本対策なのかというのがすごく大きな疑問があるのですよね。生活している限りごみは出るわけだし、そもそも生産者拡大、生産者責任を問うことが筋なのではないですかとか、いろいろ言いたいことはあるわけですよ。ですから、２３区一体で進めていくべきことというのであれば、先ほど申し上げましたけれども、品川区が反対すれば進まないということではないですか。ですから、ぜひ反対の意見を述べてもらいたいと思うのですけれども、いかがでしょうか。","respondent":"立木品川区清掃事務所長","answer":"ごみの減量につきましては、今後も区、事業者、それから区民の方が一体となって、ごみを減らす努力、資源リサイクル等など、そういったような取組を、より一層推進していくことが重要であると考えております。そうした中で、繰り返しになってしまうのですけれども、家庭ごみの有料化につきましては、２３区一体で検討が行われていくと認識しておりますので、やはりこれ、導入については慎重な検討を重ねていくことが必要であるというスタンスでございます。","id":"exchange-046"},{"speaker":"中塚委員","kind":"質問・要望","question":"今のやり取りを踏まえて家庭ごみの有料化のことを伺いたいのですけれども、この資料のとおり、区長会での議論は、家庭ごみ有料化の減量効果を含む推計と比較することを行ったということです。家庭ごみの有料化の導入を検討したこととは違うということなのか、そこを教えていただきたいです。同じ意味なのですけれども、第６次一般廃棄物処理基本計画の原案が公表されてパブリックコメントが実施されているということですけれども、この原案には、家庭ごみの有料化を進める方向が示されているのか、いないのか、いないのであれば、家庭ごみの有料化については、どのように示されているのか、私自身、一つ一つ資料を追っていないので、よく分からないので、そこをご説明いただきたいと思います。","respondent":"立木品川区清掃事務所長","answer":"この第６次一般廃棄物処理基本計画原案に関しましては、特に家庭ごみの有料化を検討したというようなことは触れられておりません。ただ、最終処分場の延命を図るという意味では、やはりごみの減量化は、これはもう避けて通れない話でございますので、それに向けた３つの施策を区長会のほうでも検討はしているというようなところでございます。その中で、先ほど申し上げました２３区一斉改修を想定した３つの施策、こちらは区長会のほうでも検討しているというようなところで、資源化可能な事業系古紙の工場搬入規制および廃棄物処理手数料の増額、こちらはロードマップを策定し、着実に進めることとして、繰り返しになりますが、家庭ごみの有料化については、引き続き実現に向けた検討を進めることとしたというようなことが区長会の中での検討ということになってございます。","id":"exchange-047"},{"speaker":"ゆきた委員","kind":"質問","question":"まず、一枚目の資料の５番に書かれている第６次一般廃棄物処理基本計画についての一番最後の資料１は、パブリックコメントについての資料かと思われますが、これ、どこにあるのか教えてほしいのと、あと、パブリックコメントが一部事務組合で実施されていますが、これは広報しながわとかで周知がされているものなのかどうかお聞きしたいと思います。","respondent":"立木品川区清掃事務所長","answer":"項番５の資料１というのは、これは原案の間違いでございまして、すみません、こちらに添付させていただきました原案の概要版、こちらの４ページの資料のことを指してございます。あと、今のところは、パブリックコメントに関しまして、広報しながわ等での周知はしてございませんで、２３区清掃一部事務組合での周知という形になります。","id":"exchange-048"},{"speaker":"ゆきた委員","kind":"確認","question":"確認できました。練馬区で、確認させてもらったのですけれども、第６次一般廃棄物処理基本計画のパブリックコメントについて周知していますというふうになっていることも確認させていただきました。今回の広報を、品川区も構成団体の一員として意思決定に関与していると踏まえると、区民への情報提供というのも重要かと思いますが、ここについてお聞きしたいと思います。","respondent":"立木品川区清掃事務所長","answer":"委員おっしゃるとおり、確かにこれは２３区に関係することですので、今回は、広報に掲載させていただいてないのですけれども、そういったところを十分気をつけて今後取り組んでまいりたいと思います。","id":"exchange-049"}]},{"id":"topic-06","title":"(6)粗大ごみリユース事業の見直し","agenda":"(6)粗大ごみリユース事業の見直し","exchanges":[{"speaker":"中塚委員","kind":"確認","question":"１つだけお聞きします。粗大ごみとして回収されたもの、また、自分の車で持っていった粗大ごみの中で、まだまだ使えるものといいますか、ソファだったり、タンスだったり、ちょうど３月は引っ越しのシーズンですから、私のマンションの前にも様々粗大ごみがありましたけれども、まだまだ使えるものも当然あるわけです。見た目で何かリユース・リサイクルに回す仕組みとしては残っているのか、ここだけ確認させてください。","respondent":"立木品川区清掃事務所長","answer":"今までは、そういった形で持ち込まれたものを検査いたしまして、ピックアップしていたところでございますが、実はこちらのほうが年間１,０００万円ほどの経費がかかっていました。区民の方からに関しましては、粗大ごみとして持ち込む際にも処理手数料がかかってしまいますので、それをかけずに、まずは持ち込むかどうかというところの段階で、こちらのリユースのサイトをご利用いただくというようなことで周知をしてまいりたいと考えていることになります。","id":"exchange-050"},{"speaker":"安藤委員","kind":"確認","question":"今、ご答弁で、結局、今までは１,０００万円かかっていた事業経費が、効率化されて、書いてあるように７６万円余になるという理解でよろしいのかということが１つ確認と、それと、これは民間のサービスということなのですが、私はあまり詳しくないもので、当該民間サービスの信頼性というのですか、品川区がＷｅｂページも開設してご案内するということですのですが、信頼性みたいなものはどうやった担保するのか伺いたいと思います。","respondent":"立木品川区清掃事務所長","answer":"経費につきましては、委員が今おっしゃられたとおり、１,０００万円の委託経費がなくなりまして、今回記載している経費のみになるという形になります。信頼性につきましてでございますけれども、実はこちらのウェブサービスの「おいくら」も、「ジモティー」も、自治体連携を進めておりまして、既に何百自治体と利用しているところでございます。こちらは独自で調べたところですと、おいくらのほうでは、１１区が既に連携しておりまして、品川区で１２区目、ジモティーも１０区が連携しておりまして、こちらは品川区分で１０区という形になっております。","id":"exchange-051"},{"speaker":"ゆきた委員","kind":"質問・要望","question":"今回の見直しについて、我が会派で、昨年の決算特別委員会において見直しを求めていた内容が、今回しっかりと反映されたものと受け止めております。これまで委託料約１,０００万円に対し、売上げが数十万円規模にとどまっていた費用対効果の課題についても改善が図られるものであり、区民の利便性向上に資するものとして大変に歓迎したい取組だと捉えています。今回導入するおいくらとジモティーの活用により、委託料の削減が見込まれるものと、これは１,０００万円で認識していますが、単に委託料の削減だけでなく、経費や運用にかかる負担も含めて、事業全体としてどの程度の経費削減になるのか、具体的な試算があれば教えてください。","respondent":"立木品川区清掃事務所長","answer":"まずは委託料の経費の部分の１,０００万円になります。あとは、やはり事務処理の面での経費節減という部分になりますので、そちらは、すみません、例えば何人ですとか、そういったような形では試算してございませんで、相当数の工数削減にはなると見込んでいるところでございます。","id":"exchange-052"},{"speaker":"ゆきた委員","kind":"質問","question":"もう１点なのですけれども、今回の見直しで区民の利便性は向上する一方で、個人間取引が基本ということになると思いますが、トラブル防止に向けた周知と注意喚起も重要になると考えています。その辺の対応についてもお聞きできればと思います。","respondent":"立木品川区清掃事務所長","answer":"昨今、特殊詐欺等でいろいろ、先ほど信頼性という面でのご心配もご意見としていただきましたが、そういったところも、しっかりサイトと連携いたしまして、周知をしてまいりたいと考えております。","id":"exchange-053"}]},{"id":"topic-07","title":"(7)しながわ水族館リニューアル事業計画","agenda":"(7)しながわ水族館リニューアル事業計画","exchanges":[{"speaker":"安藤委員","kind":"質問・要望","question":"すみません、建設委員になって、しながわ水族館のリニューアルについては初めて質疑させていただきます。最初に、子どもがやはり多く訪れる施設だという観点から幾つかお伺いしたいのですけれども、概要版の２の４）開発理念とか５）展示理念とかを見ますと、開館当初は、結構水族館は子どもの教育施設としての側面が重視されていたという話も伺うのですけれども、今回そういった側面は後退しているように見えるのです。やはり引き続き重視すべき視点なのではないかなと思うのですけれども、今回のリニューアルに当たって、そこら辺は切り替えるということなのか、そこら辺をお伺いしたいというのが１点目です。２点目に、アイデア募集なのですけれども、とてもいいことなのではないかなと思います。来館者からアイデアを募集するということがあるのですけれども、具体的な募集方法はどういうふうにするのか。また、アイデアを募集するに当たって、やはり子どものアイデアとか意見を重視すべきだと思うのですけれども、特別に子どもたちから募集する方策、そういう方策を考えているのかというのが２点目です。３点目は、今回、新年度予算で導入されていくことになる区有施設の子ども料金無料化の中に水族館は入っていなかったわけですけれども、私たちは、予算修正案も出させていただきました。無料をすべきだと思っているのですけれども、せめてこのリニューアルを機に無料化すべきなのではないかなと要望したいのです。子ども料金の無料の検討は、今回、水族館で行われたのでしょうか。対象にならなかった理由などがあれば伺いたいのと、最低限、リニューアルを機に無料にしていただきたいのですけれども、いかがでしょうか。","respondent":"大友公園課長","answer":"まず、社会教育施設という側面に関してなのですけれども、リニューアルする水族館においても社会教育施設というところは、観光の視点と合わせて２つの大きな視点になっているところでございます。しながわ水族館においては、生物学的展示施設にとどまらず、品川の文化と歴史的展示、また、特徴を持ち人文学的な要素を展示する計画など社会教育施設としての役割をしっかりと果たしていきたいと考えているところでございます。こちらの募集、対象といたしましては、区内在住・在勤・在学で年齢不問、また、来館者によるアイデア募集をかける予定でございます。募集の内容といたしましては、部門を３つに分けて募集したいと考えているところでございます。アイデアを、展示部門、企画部門、サービス部門の３つに分けて募集を考えてございます。展示部門につきましては、展示したい生物であったり、水槽の特徴、また、企画部門は、特別展であったり、体験プログラムのアイデアをいただきたいと考えているところでございます。サービスの部門につきましては、オリジナルのグッズ、新しい水族館に欲しい設備などを募集したいと考えているところでございます。募集につきましては、品川区の電子申請サービスや郵送、来館者に限っては、水族館内に投函ボックスを設けますので、そこへ投函をしていただく形で考えてございます。子どものアイデアを重視していくべきという考えにつきまして、周知方法等々、区のＳＮＳやホームページ、広報しながわ、様々な媒体を通して周知をかけてアイデアを募集していきたいと考えているところです。学校には個別に、またこういうような募集をするということで伝え、募集・周知を考えているところでございます。特別に子どもだけの枠を設けることは、考えておりません。続いて、水族館の子ども料金無償化の件でございますけれども、今回、スポーツ・文化施設の子ども料金の無償化については、子どもの学びと育ちを支援することを事業の目的としておりまして、スポーツ、文化、歴史といった教育的価値の高い施設を中心に選定しているところでございます。","id":"exchange-054"},{"speaker":"安藤委員","kind":"質問・要望","question":"運営する側の事情はあるにしても、かなりの財政力を持っている区ですので、子どもの料金の無償化の理念がやはりあるわけですから、ぜひ、今からでもいいです、無償化していただきたいのですけれども、少なくともリニューアルを機に無料にはしていただきたいなということを、ぜひ検討してもらいたいと思います。来館者について、子どもがかなり多く来館するので、ぜひ呼びかけといいますか、子どもが意見を出しやすいような工夫などをしていただくなど、より子どもの意見をもらえるような工夫をお願いしたいと思います。社会教育施設についての性格は、２つの大きな柱だということでよく分かりました。今後もそういった視点は非常に大事な視点だと思いますので、よろしくお願いしたいと思います。続きまして、資料で、概要版について幾つかお伺いしたいのですけれども、２番の６）の近隣住民への配慮というところなのですけれども、これは具体的にどういうことなのか、後段の営業時間とも関わってくることなのでしょうか、伺いたいと思います。それと、現在のしながわ水族館の２次的な使用ということも書いてあるのですけれども、第３章の説明では、「既存水族館は公共サービス機能と飼育管理機能を集約」とあるのですが、これはどういったことなのかも伺います。それと、第３章の４の「ＺＥＢの実現」というふうなところがあるのですけれども、ぜひこれは進めるべきだと思うのですけれども、実現の見通しについては、いかがなのでしょうか。あと、いろいろ運営方式についての説明があったのですけれども、現在は、ここである４つのうちの何方式なのか、恐らく、今回選ばれる方式とは違う方式だと思うのですけれども、なぜそれを今回、変える必要があるのか、もう少し説明いただきたいと思います。最後、第５章の「区内の企業が事業に参加しやすい募集要件」とあるのですが、これはどういうことなのか、どういう要綱なのか伺いたいと思います。","respondent":"大友公園課長","answer":"何点かご質問をいただきました。まず１点目でございますけれども、近隣への配慮につきましては、委員よりお話しいただきました営業時間等々も含まれているところではございます。こちらは、マンション等々も近くにあるというところ、隣接している立地等々を踏まえまして、配慮事項を今後検討してまいるという内容となってございます。また、２番目、公共サービスの集約について、第３章の資料をご覧ください少々お待ちください。残す部分につきましては、公園にある施設というところもございまして、子どもが雨のときに一時遊べるような施設の構想であったり、様々な活用をいろいろなゼロベースで考えることができるのではないかということで、どういう形で有意義に使えるのかということを公共施設として考えていこうというところが、まず第一の考えとなってございます。その他といたしまして、飼育施設、予備の水槽とか、そのような展示として使っていくようなところはなかなかしんどいところはあるのですけれども、まだ予備スペース、その他施設の整備、水族館は、設備をかなりいろいろ、電気設備関係を置く場所が必要になってきますので、そういうような場所として確保するというところで考えている場所となってございます。続きまして、ＺＥＢの実現の見通しにつきましてなのですけれども、今回、一定、基本設計を実施しているところでございます。この基本設計を実施した中において、実現の可能性は検討したところでございます。今回、ＺＥＢの認証のランクは、既存の改修も含まれることや、設備の比率が高い建物であること、また、生物の生命維持を考慮する建物であることを考えると、高いランクでの取得は困難な施設ではありますけれども、いずれかのＺＥＢの取得は可能と考えているところでございます。","id":"exchange-055"},{"speaker":"安藤委員","kind":"質問","question":"ありがとうございます。先ほど、子ども料金の話もしましたけれども、品川区で、やはり公定でやっていることによって自由度も上がるようなところもあるのではないかというところで、今回のＤＢ方式プラス維持管理と運営、一括発注ということをとることのデメリットについては、率直にどういうものが考えられるのかということを最後に伺いたいと思います。","respondent":"大友公園課長","answer":"区が完全に一から設計すると、区がイニシアチブを持つ、全てこうしたい、ああしたいということが全部かなっていくというところがございます。しかしながら、今回のＤＢ方式、デザインビルド方式でございますけれども、民間の創意工夫ということで、こちらは魅力的な水族館をつくるメリットとして考えられるところになります。","id":"exchange-056"}]},{"id":"topic-08","title":"(8)下水道管老朽化対策事業（再構築事業）","agenda":"(8)下水道管老朽化対策事業（再構築事業）","exchanges":[{"speaker":"安藤委員","kind":"質問","question":"今回は老朽化対策事業とのことなのですけれども、この工事は、耐震化につながるものなのかどうかということを伺いたいと思います。それと、下にある管きょ更生工法は、道路を掘って開削しない工法なのかを伺いたいと思います。こういう老朽化対策事業を、今回は２か所ということなのですが、今後どこでいつまでに行うなどの区内の実施計画は、今後の状況はどうなっているのか、分かれば教えてください。","respondent":"関根河川下水道課長、新妻委員長、羽鳥防災課長","answer":"３点ご質問いただきました。ただ一方で、下水道管の耐震対策といたしましては、マンホールと下水道管の接続部、こちらの抜け出し等を防止すること、それからもう一つ、液状化等によってマンホールが浮き上がらないようにすること、この２点が非常に重要な対策となっております。こちらについては、別途、耐震化工事ということで、こちらも東京都より品川区が受託をして、今、それぞれの事業として進めているところでございます。２点目、管きょ更生工法というのは、道路を掘らないで済む工法なのかという点でございますが、委員お話のとおり、管きょ更生工法というのは、幾つか細かい工法はあるのですが、基本的にはマンホールの中から部材を引き込んで、下水道管の中で、新しい管、あるいは、それに相当する強度のものをつくるという工法になってございますので、ご指摘のその工法自体は掘らないで済む工法になってございます。冒頭ご説明申し上げたとおり、現在、品川区において対象となっているのが目黒川の北側だけでございますが、今年の３月に東京都下水道局が公表いたしました新たな計画の中で、品川区の大部分を占める目黒川の南側、こちらについて、今後５年間の計画の中で、そちらにも着手をしていくと示されてございます。ですので、今後そういった形で品川区全域が対象に含まれていくものと認識してございます。一方で、何年かかるのかといったところにつきましては、現状、具体的に示されているところではございませんが、区全体としては、東京都下水道局の中で、適切な補修等を行いながら、経済的な耐用年数である１００年程度を目標に効率的に再構築を推進していくという形で計画上も位置づけられているところでございます。ご発言がないようですので、以上で本件を終了いたします。──────────────────────────────────────────── (9) 気象庁による新たな防災気象情報の運用開始に伴う区の対応について私からは、気象庁による新たな防災気象情報の運用開始に伴う区の対応について、ご説明いたします。初めに、１番、趣旨についてです。気象庁が令和８年５月下旬から新たな防災気象情報を運用する予定であります。次に、２番、新たな防災気象情報についてです。（２）新旧比較表をご覧ください。左側の現行の体系では、例えば、紫のレベル４相当では、大雨の情報がなかったり、赤のレベル３相当の高潮が警報ではなく注意報であったりと、現状では分かりにくい体制になっておりましたが、これが右側の体制に整備されるというものでございます。続いて、ページをおめくりいただき、３番、区の対応内容についてです。まず、（１）番、避難基準や避難行動につきましては、特に変更はございません。新たに新設されました「レベル４大雨危険警報」につきましては、避難行動は「屋内安全確保（垂直避難）」といたします。続いて（２）番、防災行政無線による区民周知についてです。これまで河川水位が上昇した際にサイレンを鳴らしてまいりましたが、その際、サイレンの意味は何か、避難しないといけないのか、サイレンがうるさいなど、多くのご意見が寄せられていた状況でございます。そのため、1)のように、サイレンを鳴らす場合は、避難場所を開設するような「立ち退き避難」が必要な場合に限定させていただきます。なお、河川水位情報について、発生頻度の高い警戒水位につきましては、防災行政無線での放送は今後は廃止いたしまして、防災アプリやＳＮＳ、しなメール等での引き続きの周知をしてまいりたいと考えてございます。今後の予定につきましては、記載のとおりですが、本日付で気象庁のホームページが更新されまして、今回の気象庁の新たな防災気象情報の運用は、５月２９日の金曜日からと発表されたところでございます。説明が終わりました。本件に関しまして、ご質疑等がございましたら、ご発言をお願いいたします。","id":"exchange-057"}]},{"id":"topic-09","title":"(9)気象庁による新たな防災気象情報の運用開始に伴う区の対応","agenda":"(9)気象庁による新たな防災気象情報の運用開始に伴う区の対応","exchanges":[{"speaker":"中塚委員","kind":"質問・要望","question":"ご説明ありがとうございました。この新たな防災気象情報の運用開始に伴う区の対応ということで、具体的にサイレンを鳴らすタイミングのこと、これは区で何か独自に判断したものではなく、そうしてくれと言われているものなのか、どうかをご説明いただきたいと思います。今、説明がありましたけれども、サイレンが鳴ったら避難だよと、それだけ重大な事態が起きているということで、逆に言うと、警戒水位に達した場合には防災行政無線は放送しないでアプリということなのですけれども、去年の９月１０日の超短時間集中豪雨のときに、一気に水位が上がって、対応するいとまもなく店内や住宅に水が入ってきたということを経験しているだけに、事前の警戒してくださいと、必要な対応をとりましょうと、避難というよりも、例えば、物を上に上げるとか、土のうを置くとか、みんなで声を掛け合うとか様々、警戒の段階の大切さがすごく私は身に染みたのです。なので、警戒水位の段階で防災無線はしないと、サイレンが鳴ったら避難というふうに、正直言うと、疑問を感じてしまうのですけれども、冒頭言ったように、比べて、区独自の対応である、国の言われたとおりということであれば、それをご説明いただきたいのと、そうは言っても、警戒をするということは、ＳＮＳや防災アプリはもちろんですけれども、やはりサイレンの音で少し緊張感が出ますので、そういう役割は、やはり引き続き大事ではないのかなと私などは思ってしまうのですけれども、いかがでしょうか。","respondent":"羽鳥防災課長","answer":"サイレンを鳴らす運用についてでございますけれども、委員おっしゃるとおり、やはりサイレンが鳴ると、すごく危機感が高まるということです。ただ、９.１１、９月１１日の大雨のときに関しては、実際、目黒川は警戒水位まで上がったのですけれども、危険水位までは上がらない状況でした。それを裏返すと、区民の方は、サイレンが鳴ると、避難しようというふうに直感的に思われるのだなと認識いたしまして、今回の見直しをしたというところでございます。","id":"exchange-058"},{"speaker":"中塚委員","kind":"質問","question":"サイレンのタイミングや意味づけは、区の独自の判断だということです。要は、この内政氾濫が起こり得る、起こる危険性が高まっている、そのことを住民にどう知らせるのかというときに、今の運用だと、サイレンは使わずにアプリでということなのですよね。アプリはアプリでとてもいいと思いますけれども、体感的に内水氾濫が起こり得る状況だという危険性を伝えるサイレンなのか、何なら区の地域センターにある車、スピーカーがついている車なのか、やはり体感的に内水氾濫が起こり得る危険性を伝える手法も検討すべきではないかと思うのですけれども、いかがでしょうか。サイレンが流れると避難を直感的に考えて問合せが増える、このこと自体はいいではないですか、問い合わせるぐらい。このことをどう伝えるかということ自体が大事なのであって、問合せがあったからやめようというのではなくて、危機が迫っていることをどう伝えるのかということを前面に出すことが、実際の災害が起きたときにみんな分かってくれると思うのです。そう思うと、今回の区独自の判断は、様々な方の意見も聞きつつ、問合せがあったからやめてしまいますではなくて、やはり危機が迫っているということをどう直観的にも伝えるかという手法が、実際に災害が起きたときに、なるほどという理解につながってくると思うのですけれども、これで最後にしますけれども、区の考えを改めて伺いたいと思います。","respondent":"羽鳥防災課長","answer":"委員のおっしゃるとおり、サイレンを鳴らすことで、区民の危機感を、意識を高めるということは十分認識しております。これまでサイレンを鳴らすのは、水位の上昇のときのみだったのです。これを今回の見直しで、立ち退き避難しなければいけないときにサイレンを鳴らすという運用にしました。さらに、区民の皆様に危険が及ぶときにこそ鳴らすべきものだという判断で、そちらにサイレンを鳴らすということに見直しをしたというところです。実際、大雨のときは、なかなかやはり防災行政無線自体が聞こえないというお声もありますので、初期の段階でサイレンまで鳴らしてしまうと、やはりどうしても混乱をするという状況が、今までの区民の方の反応を見ているとそういう印象を受けたというところです。実際にそういったご意見もありましたので、今回見直して、立ち退き避難、まさに洪水ですとか、土砂災害ですとか、家屋が押し流されてしまうような危険性が高いときにこそ、サイレン鳴らすということで、今回見直したという状況でございます。","id":"exchange-059"},{"speaker":"中塚委員","kind":"質問・要望","question":"いよいよ身に危険が迫ったときに、立ち退きのためのサイレンだとするならば、やはり逃げるための準備期間を促す時間が必要だと思うのです。荷物をまとめるのか、家族と連絡を取り合うのか、足の不自由な方は事前にさらに準備するのか、その準備期間を促すお知らせを、ＳＮＳや防災アプリとともに、やはりサイレンで直接届ける、私は、そこでサイレンを使ってもいいと思っているのですけれども、そこはやはり準備をしてくださいと、準備で終わればそれでいいわけだけれども、準備の次に実際の行動につながるように、そういう仕組みもぜひ考えていただきたいと、最後に要望して終わりたいと思います。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-060"},{"speaker":"安藤委員","kind":"質問","question":"命に関わることだけに、やり取りもありましたが、なかなか大変な判断だなと私も思うのですけれども、いずれにしても、結構、今回、目黒川と立会川が違う位置づけになったりとか、あるいは、サイレンの鳴らし方を変えるというのは、今までのやり方をかなり大きく変えるということになるので、それは、きちんと周知がされないと、大変なことになりかねないなということもやはりあると思うのです。あと、先ほど、冒頭の課長の説明で、最後のほうで、サイレンが鳴ったときには、どういうことだということで、すごい分かりやすかったのですけれども、資料だけ見ていると、なかなか何が変わったのかということが分かりづらいということもあって、すごく周知の仕方というのも工夫が必要だとは思いました。広報しながわで、雨期に入る前に、少なくともきちんと周知しなくてはいけないのではないかと思うのですけれども、そこについては書いていないような感じがするので、周知の強化については、さらなる工夫が必要だと思うのですけれども、いかがでしょうか。","respondent":"羽鳥防災課長","answer":"周知の方法についてです。委員のおっしゃるとおり、周知はしっかり丁寧にやっていきたいと考えてございます。出水期が始まる前に、各町会長会議であったり、防災協議会の総会、そういった場を活用して丁寧に説明するとともに、５月２９日に気象庁も発表すると言っていますので、そういう情報を踏まえて、ホームページやＳＮＳ等でも周知はしてまいりたいと思います。その際、もう少し分かりやすいような内容で工夫してまいりたいと考えてございます。広報しながわに関しましては、毎年６月に発行します特集号を、風水害対策ということで特集号を組んでいますので、その中でもしっかり周知をしてまいりたいと考えてございます。","id":"exchange-061"},{"speaker":"ゆきた委員","kind":"意見","question":"すみません、今の広報の仕方についてなのですけれども、重ねてなのですけれども、広報しながわで６月１日にハザードマップの更新について、予算特別委員会のときに質疑させていただいたときの答弁で、特集を行うというご答弁があったと思いますので、その辺、これ、どういうふうに広報していくのか、同じところで広報されるのか、２回特集を続けて広報されるのか、その辺について、もし分かれば教えていただければと思います。","respondent":"羽鳥防災課長","answer":"広報しながわでの周知の方法ですけれど、委員おっしゃられたとおり、ハザードマップ、今回、雨水、出水ハザードマップが新しくできますので、そちらの周知と併せて、今回の防災気象情報の変更も周知させていただきます。あと、９月１１日の被害の状況をマップ上に落としたものがありますので、そういったものも併せて今年度の風水害に備えていただくように、しっかり周知してまいりたいと考えております。","id":"exchange-062"}]},{"id":"topic-10","title":"(10)品川区小災害見舞金等支給要綱の改正","agenda":"(10)品川区小災害見舞金等支給要綱の改正","exchanges":[{"speaker":"中塚委員","kind":"質問・要望","question":"議会でも議論があって、改正前から改正後の変化ということで、単身世帯の方も、全世帯同額というふうに改善されたと思います。端的に申し上げると、見舞金の制度は、今後ぜひ実態に合わせて充実、改善をしていただきたいと思うのです。言いたいことは、結局、被害の程度が、床上、床下、全壊、半壊の４段階で定額という仕組みになっておりまして、その上、いわゆる見舞金ということで、こちらはお見舞いの気持ちです。私が思ったのは、見舞金は見舞金で拡充、改善は今後も必要だと思いますけれども、これとは別に、住民の方には、生活再建支援金とか、事業者の方には、事業再建支援金、つまり、お見舞いとは別に、再建資金の制度を別建てで導入すべきではないかと思うのです。区の見解をいただきたいと思います。当面、お金を使うこともあるでしょうから、どうぞという気持ちはとても大事だと思います。しかし、９月１１日の水害もそうですけれども、住民であれ、事業所であれ、清掃やクリーニングや消毒、買換えなども、冷蔵庫、事業者の方だと、例えばコーヒーマシンとかだとすごく高価なものになりますし、畳、布団、カーペットは濡れてしまって使えない。特に、全壊と半壊では６万円と５万円ですから、再建には全く足りないわけです。規模が大きくなったら、別の仕組みがまた返ってくることにはなるわけですけれども、やはり見舞金と、別建てで支援金の導入、この１点だけ、質問したいのですけれども、いかがでしょうか。","respondent":"星災害対策担当課長","answer":"ご指摘のとおり、見舞金としましては、やはりお見舞いの気持ちを表すものというところでの金額になっております。生活再建につきましては、現在もある程度ある支援の体制等を、今回、９月１１日の際は、事業所や被害に遭われた方にお伝えしているところです。こちらにつきましても、関係各課と連携をして、これからどういった支援が必要かという検討は続けてまいりたいと考えているところです。","id":"exchange-063"},{"speaker":"中塚委員","kind":"質問・要望","question":"おっしゃるとおり、やはりお見舞いはお見舞いなのですよね。今、課長がおっしゃったとおり、生活再建策でいうと、９月１１日は、いわゆるエコな冷蔵庫への買換えの助成金で、災害を想定した事業ではなかったけれども、これが使えると。この実体験があるだけに、お見舞金とは別に、住民の方には生活再建支援金、事業者の方には事業再建支援金、実際の被害に遭った金額だったり、商品だったり、お金だったり、制度上、上限はつけるものの、実際の被害の程度に合わせた支援金、これをぜひ検討していただきたいと思うのです。大きい災害になると、その都度この議論になって、その都度制度がつくられたり、充実されたり、少しずつ改善されてはいるものの、水害も地震もいつ起きてもおかしくないというだけに、冷蔵庫の買換えは災害用ではなかったですけれども、使える制度は何でも使ってもいいとは思いますけれども、改めてこういう支援金制度を別建てで導入していただきたいと思います。最後にいかがでしょうか。","respondent":"星災害対策担当課長","answer":"先ほどと同じような話になりますけれども、住民の再建支援は、関係各課と連携をして、いろいろな支援策について進めていきたいと考えております。","id":"exchange-064"},{"speaker":"安藤委員","kind":"質問","question":"やはり品川区のこうした水害に見舞われる地域がたくさん発生するというような地域特性ですとか、あと、昨年の被災状況などを目の当たりにしますと、今、議論があったような支援金は私も必要ではないかなと思います。その上で、見舞金については、今回、改善が一定されたということなのですけれども、２点だけお伺いしたいです。１つは、昨年、戸越銀座をはじめとして、かなり多くの事業所が被害を受けたところなので、かなり事業所で高価な設備とかもやられてしまったわけです。見舞金とはいえ、事業所のほうは上がっていない、変更なしということになっているのですけれども、これはやはり引き上げる必要があるのではないかと思うのですけれども、そうした検討は、されなかったのかなというのが１つです。もう一つは、区分が床上と床下ということになっていますけれども、最終的には、運用のところで解決したのかもしれないのですけれども、当時、住宅の半地下の駐車場ですとか、あるいはベランダからの浸水などについては、見舞金の対象ではないみたいな話もあったのですけれども、そういったところも今回、対象に含まれるということになるのか、そこらについて、含まれるようにしたほうがいいと思いますし、ないのだったら、新たな区分みたいなものをつくる必要もあるのではないかと思うのですけれども、そちらについては、いかがでしょうか。","respondent":"星災害対策担当課長","answer":"２点質問をいただきました。また、事業所は大規模なところから個人経営と少し差がありまして、一律に引き上げると考えた場合、見舞金の目的からも逸脱してしまう可能性もあるので、少し丁寧にいこうかなというところがございまして、今回は、改正を行わず変更なしというふうにさせていただいているところです。２点目のご質問の半地下、ベランダが対象となっていなかったというところで、運用面なのですけれども、こちらも今回の災害の被害を踏まえまして、どういったものが支払いになるか、ならないかというところを整理して備えているところでございます。今、手元に資料がないので詳しくご説明できなくて申し訳ないのですけれども、例えば、半地下であれば、居住実態があれば、そのまま床上として判断していこうというようなところの基準を用意しているところです。","id":"exchange-065"},{"speaker":"安藤委員","kind":"質問・要望","question":"やはりかなり商店街には事業所が多いという地域特性もあるのです。生活基盤をつくるための事業、職住一体になっているような商店街も多いところなので、ぜひ改善を進めていただきたいなと思いますし、少なくとも住宅と同じ規模には引き上げていく必要があるのかなと思っています。なので、そういったところにも行き届くような制度にぜひ改善していただきたいと要望させていただきます。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-066"},{"speaker":"ゆきた委員","kind":"質問・要望","question":"まず、宿泊見舞金の２泊から３泊への変更については、公明党としても求めてきた内容であり、大変歓迎した要綱の改正であり、また、見舞金の支給額の変更についても、被災者の支援の観点から歓迎したい取組だと捉えています。見舞金については、事業者からも、様々な声も伺っています。引き上げてほしいとか、そういった声もあるので、ニーズを把握した上で、そういった声を反映する形で検討していただければと思いますが、ここについてお聞きしたいと思います。","respondent":"星災害対策担当課長","answer":"事業所への見舞金の支給につきましては、委員からのご指摘のとおり、ニーズを把握していきたいと考えてございます。","id":"exchange-067"}]}],"links":[{"type":"minutes","label":"公式の会議録を読む","url":"https://kaigiroku.city.shinagawa.tokyo.jp/index.php/680934?Template=document&Id=7361#one"},{"type":"official","label":"公式の会議録一覧","url":"https://kaigiroku.city.shinagawa.tokyo.jp/index.php/100000?QueryType=new&Template=list&Cabinet=8&TermStart=2026-01-01&TermEnd=2026-12-31"}],"sourceMeta":{"pages":0,"characters":81211,"voices":202}},{"id":"r08-20260414-9","meetingId":"r08-m0405","date":"2026年4月14日","dateIso":"2026-04-14","committee":"文教委員会","time":"午後 １時００分～午後 ３時４９分","status":"正式会議録","sourceType":"formal","overview":"文教委員会の会議録から、実質的な質問・確認・意見・要望と答弁・対応を61件整理しています。","topics":[{"id":"topic-01","title":"報告事項を聴取いたします。 (1)令和８年度品川区立幼稚園、小・中学校、義務教育学校、園長・校長・副園長・副校長異動者名簿","agenda":"報告事項を聴取いたします。 (1)令和８年度品川区立幼稚園、小・中学校、義務教育学校、園長・校長・副園長・副校長異動者名簿","exchanges":[{"speaker":"のだて委員","kind":"質問・要望","question":"そもそもの考え方というのでしょうか、仕組みを伺いたいと思います。これは東京都から配属されてくるのか、区としてこうしたいと要望してやるのか伺います。","respondent":"酒川指導課長","answer":"東京都の人事構想、それから、区の要望、双方がございます。","id":"exchange-001"},{"speaker":"のだて委員","kind":"質問","question":"それはそうだろうとは思うのですけれども、実際に、そうすると、東京都から何人品川区に入って品川区から出ていくと区に来て、区がその人たちをどこに配置するか、校長とか、副校長とか、園長とかを割り振っていくことなのか伺いたいと思います。なかなか校長、副校長が一遍に替わることもあるみたいなので、その辺の区の考えはどのように反映されているのか伺います。","respondent":"酒川指導課長","answer":"東京都から人材情報の提供がありまして、そういった提供を受けた上で、地域や学校の状況を踏まえて、区で配置校を決定しております。","id":"exchange-002"},{"speaker":"のだて委員","kind":"質問","question":"校長、副校長が一緒に替わってしまう。そうすると、結構、運営的に大変なところがあると思うのですけれども、区としてそういう判断をされているのですか。","respondent":"酒川指導課長","answer":"区でも、管理職２人を一遍に替えるのは、実際は行いたくないところではございますけれども、こちらで予期していなかった退職管理職がいて、様々な流動的な状況で、最適化という意味で、苦渋の判断をした部分もある状況でございます。","id":"exchange-003"},{"speaker":"高橋（し）委員","kind":"質問","question":"今、のだて委員からもあったのですが、関連して、今話題になった校長と副校長が同時にということですけれども、何年も、以前から私はその件については原則として避けるべきであると申し上げてきて、ご承知のとおり、学校にはそれぞれ地域との関係がありますから、学校はこういう課題がある。指導課長が今また少しおっしゃったのですが、一般論として、校長と副校長が同時に替わったときに、学校運営上、どんな問題が発生し得ると認識していらっしゃるのでしょうか。","respondent":"酒川指導課長","answer":"当然のことながら、４月からの配属ですので、学校の課題が把握しづらい。また、地域や保護者の状況がどういった状況なのかも把握しづらいという状況はあると認識しておりますけれども、その点については、前校長、これからの校長、それから、前副校長、これからの副校長へ引継ぎを行っていただき、今の時期、真っ最中かと思いますけれども、状況把握に努めていただくとともに、こちらとしても、そういった学校については、丁寧な状況把握に努めてまいります。","id":"exchange-004"},{"speaker":"高橋（し）委員","kind":"質問","question":"今お話にあったように、とにかく４月は学校の先生方も異動して大変な状況の中で、校長先生、副校長先生が替わるということですから、立ち上がりが非常に不安定になる。という状況がある中で、今、なるべく避けたい、できるだけ避けたいと課長はおっしゃっていたので、当然ですが、令和７年度は３つの学校、小学校１校に中学校２校が同時に替わっている。今年度は２校で、第一日野小学校は校内昇任ですので、把握できていますけれども、１校がそうなってしまったので、２年続けて起きた状況ですが、先ほど様々なところから苦渋の選択というお話があったのですが、その点についてもう一度、令和６年度はなかったのですよね。ですから、区教委として努力されたのだと思うのですけれども、そこを改めて、２年続けてというところをお尋ねします。","respondent":"酒川指導課長","answer":"一部繰り返しになりますけれども、やはり校長と副校長が２人とも同じ年度に替わるのは、学校、また、様々なところに負担、しわ寄せが行くことは承知しておりまして、これも繰り返しになりますが、なるべく避けたいと考えておりますけれども、昨年度と少し違う状況で、今年度、続けていただきたいと思っていた校長先生が複数名退職という状況が生じまして、この状況を何とか対応するために、こういった対応をさせていただいたところでございます。","id":"exchange-005"},{"speaker":"高橋（し）委員","kind":"質問","question":"そうすると、そこの今同時に替わったところは、個別の学校名は置いておいて、本当は残っていただける予定だった方が退職して同時になってしまったという認識でよろしいでしょうか。","respondent":"酒川指導課長","answer":"なかなか学校名まで挙げて申し上げるのは難しいのですが、そういった状況で、２人替えになった学校はございます。","id":"exchange-006"},{"speaker":"高橋（し）委員","kind":"質問","question":"では、いろいろ学校名はあれですので、そうすると、逆に言うと、先ほどのご答弁にあった人材の提供が東京都からある。それを区で配置していくというお答えだったのですけれども、品川区教育委員会としては、東京都教育委員会に対して、同時の異動はこちらとしては困る、そのような状況は、常時、いつも明確にお伝えしていらっしゃるのでしょうか。","respondent":"酒川指導課長","answer":"同時の異動は、今回、東京都の都合ではなく、先ほど申し上げましたが、本人の退職希望などによりますので、そういったいなくなった校長先生のところを埋めるべく、優秀な人材の要望はしております。","id":"exchange-007"},{"speaker":"高橋（し）委員","kind":"質問","question":"今年はそういう事情があったということで、ここでまた一般論になりますけれども、通常、品川区教育委員会としては、同時に替わることは、区としては、いろいろ大変な影響があるから避けたいと、都教委には通常伝えているのでしょうか。","respondent":"酒川指導課長","answer":"区として、当然、管理職２人を同時に替えるのは避けたいわけでございますけども、同時に替えるか替えないかというのは区の判断になりますので、東京都への要望というものではございません。","id":"exchange-008"},{"speaker":"高橋（し）委員","kind":"質問・要望","question":"同時に替えるかどうかは、区の判断ということですね。では、区が替えることには、非常に混乱やいろいろな影響があるので、避けたいという意思があるということは、区教委としては替えない体制でやっているということも１つ確認で、このようにして替わってしまうことは、やはり当然ながら、現場の混乱等、負担が生じますし、しわ寄せは子どもたちに行くので、先ほどもご答弁いただきましたけれども、同時に替わったところに対しては丁寧に教育委員会として支援、それから、前校長、前副校長の先生との密接な連携、その辺を取っていただきたいのですが、最後、その２つをお願いします。","respondent":"酒川指導課長","answer":"校長とは年３回ほど、ヒアリングを行っております。第１回目のヒアリングが４月の下旬から始まりますので、こういったところで状況を確認するとともに、今年度、管理職、主に校長ですけれども、替わった学校については、私自身が訪問して状況を伺う、把握していくことも考えております。","id":"exchange-009"},{"speaker":"高橋（し）委員","kind":"質問・要望","question":"そのようにして、課長が校長先生、そして、学校での混乱、そして、負担の軽減について進めていっていただきたいと思います。やはりなかなか学校も、まず１つは、先生方がそうなって大変だと声は上げにくいところがありますので、それを拾っていただくのと、あと、地域で、両方とも替わってしまったというところで、地域とのつながりが、継続性が止まるので、その辺りも含めて、今お話のあったような支援をお願いします。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-010"},{"speaker":"若林委員","kind":"意見","question":"今の続きで、管理職が替わったところについて、教育委員会のバックアップがされているということで、逆に、校内の体制として、校長先生、副校長先生を支える、今回、主幹教諭でしたか、主任教諭とか、新しいネーミングもあって、そちらの校内からの新しい体制を支える気遣いとか工夫は何かあるのか。あれば、教えてください。","respondent":"酒川指導課長","answer":"校内においては、ナンバー３に当たる主幹教諭が副校長、校長の経営を補佐する立場にありますので、主幹の立場にある教員については、こちらから毎年度言うまでもなく、そういった立場であることを理解して取り組んでいただいてございます。校内とは少し異なってしまいますけれども、こちらで退職校長、教育アドバイザーがいますので、そういった管理職が替わった学校には、教育アドバイザーの指導・助言も手厚くしていきたいと考えています。","id":"exchange-011"},{"speaker":"若林委員","kind":"意見","question":"今、主幹という言葉が一致しましたので、そこも含めて、この表でいう黄色のところで、そういう支える、ナンバー３ですね。主幹の方も替わっているところは、学校名でお話しするのか、ナンバーでお話しするのか、何か所という表現なのか、そういう事例があれば教えてください。","respondent":"酒川指導課長","answer":"校長、副校長の異動と、やはり主幹の異動というのもバランスを取らなければいけないところで、校長が異動した学校、副校長が異動した学校、そして主幹が異動した学校、それぞれに数字をお示しするのはできないわけですけれども、そういった学校を含めて、教育委員会としてもバックアップしていきたいと思っています。","id":"exchange-012"}]},{"id":"topic-02","title":"(2)令和８年度（９年度採用）品川区立学校教育職員採用候補者選考日程","agenda":"(2)令和８年度（９年度採用）品川区立学校教育職員採用候補者選考日程","exchanges":[{"speaker":"のだて委員","kind":"質問","question":"今回、若干名の採用ということで、目標は何人なのかを伺います。","respondent":"酒川指導課長","answer":"長期の目標としましては、全校配置を目標としております。","id":"exchange-013"},{"speaker":"のだて委員","kind":"質問・要望","question":"全校配置、今、３０人ぐらいいらしたと思うのですが、それを増やしていくということで、私たちも、区独自の教員として採用しているわけですから、少人数学級の実現とか、対応してやっていただくように求めてもおりますので、そうした前進ができるように、やっていただきたいと思います。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-014"},{"speaker":"高橋（し）委員","kind":"質問","question":"（３）の３年生前倒し通過者選考で、報告があったのかもしれませんけれども、すみません、私がそこの記憶が、申し訳ないのですけれども、令和７年度に実施したので何名の方が今、残っている、言い方が正しいのか分かりませんけれども、合格、通過したのでしょうか。","respondent":"酒川指導課長","answer":"前倒し選考、令和７年度については、２名が受験しまして、１名が通過しております。","id":"exchange-015"},{"speaker":"高橋（し）委員","kind":"質問・要望","question":"その方々は、受験するかどうかはこれからになるわけですね。ということは、逆に言うと、区としては、ぜひ受けてくださいと働きかけができるものなのですか。できないものなのでしょうか。受けていただきたいという意味においてです。","respondent":"酒川指導課長","answer":"昨年度受験して、一次の一部を通過しておりますので、本年度は一次の後半部分の試験から受けていただくことになるのですが、こちら、通知を行いますので、その通知を行うところで、ぜひ受験していただきたいということはお伝えできると思っております。","id":"exchange-016"}]},{"id":"topic-03","title":"(3)部活動の地域展開","agenda":"(3)部活動の地域展開","exchanges":[{"speaker":"のだて委員","kind":"確認","question":"まず、確認ですが、今ご説明いただいた協議会の回数をなぜ減らしたのか伺いたい。あと、しながわ地域ＴＥＡＭ ＡＣＴの中で、令和５年度はバトミントンをやられていましたが、それがなくなった理由を伺います。","respondent":"酒川指導課長","answer":"まず、協議会の回数を減らした理由でございますが、本日お示ししているしながわ部活動改革実行ビジョン２０３１という、２０３１年までのロードマップが策定できたことが１つ理由でございます。それから、バドミントンでございますが、令和５年度はどのような地域展開ができるかということで、幾つか取り上げた中にバドミントンを入れたわけでございますけれども、ダンス、ラグビー、ホッケー等々、地域展開の見通しが立ったことから、学校部活動にバドミントンはかなりたくさんあるということで、こちらをなくしてございます。","id":"exchange-017"},{"speaker":"のだて委員","kind":"質問","question":"つまり、協議会はロードマップの作成が１つの大きな仕事だということですね。位置づけ的に何か変わるものがあるのか伺います。","respondent":"酒川指導課長","answer":"役割を終えたわけではございませんで、一定、先のビジョンを協議会で共有することができた。当然ながら、地域展開ですから、地域移行は今後も考えていくものでございますので、国の動きや都の動きも把握しながら、この場は、今年度１回としておりますが、協議の場としては維持する考えでございます。","id":"exchange-018"},{"speaker":"のだて委員","kind":"質問","question":"いろいろ部活動の地域展開を進めている中で、この意見にも、２枚目で、校区教育協働委員会からも、子どもたちの活動機会への影響とか費用面の負担が懸念されると声が出ておりますけれども、費用で、部活だったら、基本的に部活に参加するための費用がかからないということで、地域に移行していったときに、費用面が発生してくると、参加できない子どもたちも出てくる懸念もあるのですけれども、今、区としてはどのようにしていこうと考えているのか。実際に地域移行を進めていくと、料金が発生してくるのかどうかも含めて伺いたいと思います。教育的な視点をどう今後担保していくのかも１つ重要と思うのですが、そこの考えを伺います。","respondent":"酒川指導課長","answer":"現在、部活動指導員と業務委託と教員で行っている学校部活動、それから、しながわ地域ＴＥＡＭ ＡＣＴ４種、共に費用はかかっておりません。当然ながら、これを全て、部活動という名前が適当かどうか分かりませんが、子どもの活動の場所を地域に移していくとなると、費用はかかってくるので、その辺りは行っていくとなったときには課題になると認識しております。","id":"exchange-019"},{"speaker":"のだて委員","kind":"質問・要望","question":"そうすると、地域に移していくとなると、料金も発生するし、今、学校とかが関わっているから教育的な視点はありますというお話でしたけれども、地域に移行していくと、教育的な視点はなくなってしまうのか、そこも伺いたいと思います。やはり部活動としてやっている中では、子どもたち、参加したいと思えば参加できる状況ですけれども、民間に移していくと、そういった課題が出てくるので、ぜひ生徒たちが選択してできるようにしていただきたいと思うのですけれども、いかがでしょうか。","respondent":"酒川指導課長","answer":"地域に完全に移行していったときには、教育的視点、費用、様々な課題があると思いますので、それをどう捉えるかもありますけれども、そういった課題整理は進めていきたいと思っております。","id":"exchange-020"},{"speaker":"のだて委員","kind":"質問・要望","question":"課題はあるということで、今まで何で学校でやってきたのかは、教育として必要な部分があったということだと思いますので、そうした教育的視点は残していただきたいと思いますし、いろいろこの間も協議会等で評価されてきたということだと思うのですが、実際、受け持ちたいという教員の方もいらっしゃると思いますし、あと、教員の負担も軽減していかなくてはいけない中で、保護者や生徒の意見もよく聞きながらやっていっていただきたいと要望したいと思います。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-021"},{"speaker":"まつざわ委員","kind":"意見","question":"先ほどのお話と一緒で、部活動の基本が、将来にわたって子どもたちが多種多様かつ継続的にスポーツ・文化芸術活動に親しむ機会を確保・充実とありますので、この目標のためには、やはり具体的な負担軽減策ですとか、セーフティーネットの役割にもこれからなっていくと思うので、そこら辺は協議する中でしっかりと話し合っていただけたらと思っています。そこで、あと、私、部活動が急激に完全地域移行にしないで、指導を希望する５０の部活と、業務委託１４０、これをこうやってしっかりと分けて継続的に運営を目指すということは、本当に現実的で、すごくすばらしいと思っています。その中で、校区協働委員会の人が、部活動を地域移行する場合、生徒理解などの技術的指導の部分が必要となるという一意見が出ていますけれども、やはり民間委託していくのはこれから絶対必要なことだと思っているのですが、でも、高い指導というメリットがある以外に、こういった指摘が出てくると思っていて、例えば、そういった外部指導員と教員、これが日頃の情報共有、そういった生徒の様子を共有して連結する体制とか、緊急的なルールの整備などはあるのか、教えてください。","respondent":"酒川指導課長","answer":"おっしゃるとおり、生徒指導上の問題ですとか、その日の生徒の課題を抱えたまま部活動に参加することがございますので、１００％教員が指導や関わりを絶つわけではなく、当然、そういった状況の場合は、観察といった形で指導に関わるという状況はあります。","id":"exchange-022"},{"speaker":"まつざわ委員","kind":"意見","question":"コーディネーターがその中を取り持つ。あと１点、地域部活動のラグビー、私もラグビーをやっていたので、興味があって、ＪＲ東日本東京総合車両センター、これをこうやって一緒にやっていくのは本当にすごい、とてもいい機会と思っていたのですけれども、お話を聞いていると、ここもだんだん使えなくなっていくとお話の中であった。そういった部活動で必要な活動場所、そういった誘致の課題はどうなのか、少し心配があるので教えてください。","respondent":"酒川指導課長","answer":"おっしゃるとおり、活動場所が昨年度と同様に確保できない状況が発生しております。昨年度から引き続き、一部の活動は区立学校の校庭を使って実施予定でございますが、残りをどこの場所を使ってやるかは現在検討中でございます。いずれにしましても、利便性と安全性の確保を、ラグビー協会とも情報共有しながら、最適な場所を見つけていきたいと考えてございます。","id":"exchange-023"},{"speaker":"まつざわ委員","kind":"質問・要望","question":"また、地域資源を活用するのは本当にすごくすばらしいことなので、でも、見ても、品川区はほかにあるかといったら、難しいと思いますけれども、ぜひこういった取組は引き続き検討していただきたいと思います。そこら辺も１個、地域移行、これからの今後のテーマとして、ぜひ検討していただきたいということ。結局、例えば、こういう部活動を地域移行すると、やる人数が少ない、やる人数が少ないからやらないのではなくて、やる人数が少ないからこそ、全体でこうやって集めることによって、１つの受皿ができる。だから、そういった部活動を、例えば中学生だけの部活動と捉えてしまうと、やはり中学生がやるべきことですけれども、そういう壁を取っ払えば、要は、地域の文化団体、すみません、長くなってしまった。地域のそういう文化や伝統芸能をこうやって中学生を介してまた地域がつながるというのは、すばらしい取組になると思うので、中学生の部活動は大事ですけれども、そこら辺の壁も取っ払うようなイメージをぜひこれからは検討の中にも入れていただきたい。要望です。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-024"}]},{"id":"topic-04","title":"(4)これからの市民科について（第２次案）","agenda":"(4)これからの市民科について（第２次案）","exchanges":[{"speaker":"まつざわ委員","kind":"質問・要望","question":"教員の意見の中で、地域の人材は眠っているという一方で、授業、行事が多いため、地域と連携する人探しをする時間がない、そういった現場の声がここに書かれています。だから、そういった地域の大人たちと中学生が触れ合う機会、これをぜひ教育委員会で組織的に構築していただきたいと思いますけれども、いかがでしょうか。","respondent":"高木教育施策推進担当課長","answer":"今言っていただいた地域人材の活用、非常に重要な内容であると認識しております。所管としましても、これを各学校に伝えていって、積極的な活用、充実を図っていきたいと考えてございます。","id":"exchange-025"},{"speaker":"まつざわ委員","kind":"意見","question":"まとめているという。国も特別の教科道徳、これをやっていきましょうというのと、品川区独自の市民科、これ、本当にすごい、すばらしいと思っているのですけれども、今言った道徳と市民科、やっているのでしょうが、市民科の中に道徳が入っているのでしょうけれども、これをどうこうやって抜き出して、道徳を充実させてほしいという教員の声を反映させて、考えていくのか。市民科はすごくすばらしいですけれども、いろいろなものが入ってくるので、その中での道徳はどのように再構築していくのか少し気になるので、教えてください。","respondent":"高木教育施策推進担当課長","answer":"品川区では、市民科の学習の中で、特別の教科道徳を進めているのですけれども、一般的な道徳の学習ですと、４５分の中で終えるのですが、市民科はそれを複数時間にわたらせるというのがまず１つ違うところです。複数時間で何が変わるかというと、道徳の教材等を使った授業をしないわけではなくて、道徳でまずそれぞれの価値を、自我関与というのですけれども、それぞれの考えを出させた後に、特別活動の考え方で、学級として合意形成をして、何らか全体の行動をするのが市民科の特質です。市民科を遡りますと、そういった理念の下に特別活動と合体させたところがありますので、市民科の全単元において、どこにおいても道徳的要素は入っていると指導しておりますし、その認識で教員も指導しておると考えております。","id":"exchange-026"},{"speaker":"まつざわ委員","kind":"質問・要望","question":"全て道徳が入る。そういうことは分かるのですけれども、全体の中でも道徳教育の大事なところは家庭教育だと私はすごく思っているので、ぜひ道徳教育の中から家庭教育、家庭で教えていく部分が私はほとんどだと思っています。ですから、ＰＴＡと連携するとか、私がＰＴＡ会長時代は、道徳教育ではないですけれども、学校が親や保護者に言えない部分はＰＴＡでやっていこうという心構えで３年間務めさせていただいたので、そういったＰＴＡとの連携もぜひ進めていただきたいと思います。要望です。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-027"}]},{"id":"topic-05","title":"(5)品川区いじめ防止対策推進基本方針の改訂","agenda":"(5)品川区いじめ防止対策推進基本方針の改訂","exchanges":[{"speaker":"のだて委員","kind":"質問・要望","question":"１つは、スクールロイヤーは名称を変えるだけですか。そこを確認させていただきたいのと、あとは、充実させていくためにスクールカウンセラーを全校に配置するということで、そうした取組はよいと思っております。やはりいじめは、子どもの成長過程でどこでも起きてしまうと思いますので、この基本方針の７番にいじめの禁止等と書いてありますけれども、こうした禁止をするものではないと思います。やはり教育の営みの中で解決していくことが基本だと思いますので、そこだけ押しつけても、どういう背景があっていじめをしているのか、いじめをしてはいけない理由とか、そういったところをしっかりと学んでいくのが１つ重要だと思いますけれども、いかがでしょうか。","respondent":"保土澤教育総合支援センター長","answer":"２点ご質問いただいたと思っております。まず、スクールロイヤーにつきましては、名称をこのように明記したことに加えて、今後も一緒に連携をして対応していく。専門的な知見からご助言もいただきながら、様々な課題の早期対応、早期解決を図ってまいりたいと思っております。もう１点、いじめの禁止についてですけれども、やはり行為を禁止すればなくなるということではないとのご指摘かと思っております。私も同様に考えております。ご指摘のとおり、やはりいじめについて子どもたちが学び、また、大人も共に学んでいくことで、いじめ行為を減らすことが可能になっていくと考えておりますので、これまでやってまいりましたいじめに関する授業、それから、教員の研修、そして、調査ツールの活用、この３本柱をしっかりと続けてまいりたいと思っております。","id":"exchange-028"},{"speaker":"のだて委員","kind":"質問・要望","question":"同様の考えだということで、そうすると、基本方針でも禁止というのを変更していただけたら、これは要望しておきたいと思います。そうした人権教育を行っていくことが必要だと思いますけれども、いかがでしょうか。そうした姿勢を基本方針にも入れていただきたいと思います。あと、やはりいじめが起こった後の学校の対応も、予防は予防プログラムで実施されているという中で評価しているのですけれども、起こった後の対応がたどたどしいという声も聞きまして、そこを実際、この間、いろいろな事例があると思いますので、どうやって対応していくのかを共有していただいて、しっかり仕組みをつくっていただけたらと思うのですけれども、いかがでしょうか。あとは、言葉が適切か分かりませんが、加害者がいじめをしなくなるまで、人間的に立ち直っていくまで徹底したケアを行っていくことが、やはり再びいじめを繰り返さないことにもなっていき、いじめを減らしていくことになると思いますので、いじめをした側への徹底したケアをしていくというのをぜひ位置づけていただきたいと思うのですが、いかがでしょうか。","respondent":"保土澤教育総合支援センター長","answer":"まず、いじめが起こってしまうという認識に立つ。これは本当に非常に一番大切な視点の１つと思います。法に照らせば、やはりいじめは、関わりの中で相手に不快な思いをさせてしまって、一定の人間関係があって、やはりいじめという認知をしていくものですので、起こらないという言い方ではなく、どこかで起こっている認識に立つことが非常に重要だと考えております。だからこそ、ご指摘のとおり、学校での風土づくり、それから人間関係づくり、こういったものを各学校で引き続き進めていく必要があり、そして、仕組みのご指摘もありましたが、いじめを予防するため、早期対応するためにどうするかだけではなくて、いじめがやはり認知された後、どのように学校として動くのか、また、教育委員会と連携して動くのか、その辺りをスピード感を持って対応できるように、今回この改訂をし、そして、各学校に専門職を配置していくと考えたものでございます。また、最後、加害者のケアにつきましては、やはりまずは被害の立場にある子のケアが最優先であることは言うまでもないと思いますけれども、その上で、教育的な観点から、双方、関わった子どもたちへの必要な指導、それからケアというものは必要だと考えております。","id":"exchange-029"},{"speaker":"のだて委員","kind":"質問","question":"それぞれ取り組んでいただけるという答弁だったと思います。実際にスピード感を持って対応していく、今回の変更だということで、スピード感を持って解決をしていく決意などがあれば、伺います。","respondent":"保土澤教育総合支援センター長","answer":"言うまでもなく、いじめの対応の本当に一番大切なポイントは、早期に把握して、そして、早期に対応を始めて、解決への道筋を見据えて対応していくことと考えておりますので、そういったことを各学校にも周知、また、指導しながら、この基本方針にのっとった対応を進めていくことが非常に大切だと考えております。本当にスピード感というところは各学校に引き続き指導しながら、教育委員会といたしましても、そこを重視した対応を進めていきたいと思っております。","id":"exchange-030"},{"speaker":"高橋（し）委員","kind":"意見","question":"今、スクールカウンセラーの全校配置とお話があったのですけれども、現状もというのは、令和７年度までもスクールカウンセラーは区立学校に配置されていたわけですが、それとどのように変わるのか、別の発表だと追加配置という表現になっているのですけれども、その辺、令和７年度とどのように変わるのか、お願いします。","respondent":"保土澤教育総合支援センター長","answer":"令和７年度までは、区内で８校に配置をしてまいりました。人数につきましては、４３名追加という形で配置を進めてまいります。","id":"exchange-031"},{"speaker":"高橋（し）委員","kind":"質問・要望","question":"８校だったのが全ての小・中学校ということですけれども、予算特別委員会でも質問したのですが、スクールカウンセラーの教育委員会としての要望が２億円ぐらいあって、それで、予算査定で１億１,４００万円ぐらいになって、スクールカウンセラー派遣時間数とあるのですけれども、これは先ほどのだと１週間に最大４日勤務と書いてあるのです。私は教育委員会の要求は正当なものだと思って、あれで言っているのですけれども、もっと勤務できるようにとか、あるいは、その日の中でいる時間を長くしようとしているのか、そういう構想があったのでしょうか、お尋ねします。","respondent":"保土澤教育総合支援センター長","answer":"スクールカウンセラーにつきましては、先ほどもお伝えしたとおり、これまでは都から派遣される週１日という体制の学校が多うございました。そういった実態から、１日でもそういった専門職と連携して、子どもの理解や様々な対応、こういったものに学校が対応できることが望ましいと考えておりました。今年度につきましては最大４日、それから、週１日プラスという学校もございますけれども、まずは追加していただいたところをしっかりと活用しながら、各学校での対応に活かしていきたいと思っております。","id":"exchange-032"},{"speaker":"高橋（し）委員","kind":"質問","question":"その４日は、いわゆる勤務時間９時から５時を４日という認識でよろしいですか。それとも、もう少し短いとか、その辺りはどうなっているのか。今、スクールカウンセラーが令和７年度に入っている学校だと、相談というよりも、特に支援が必要なお子さんとかについて、何曜日の何時間目はここ、何時間目はここという感じでやっている学校もあると聞いているのですけれども、そういう体制とはもう少し違って、いじめなどに関係して、現状、相談は都費でやって、区費の現状のスクールカウンセラーの方、また違った形で支援している認識なのですけれども、それは令和８年度もそういう感じでしょうか。","respondent":"保土澤教育総合支援センター長","answer":"今年度につきましては、これまでどおり、都のスクールカウンセラーは相談業務が中心です。そして、追加で配置する区費のスクールカウンセラーにつきましては、ご指摘のとおり、まずはいじめの調査ツール、これを学校と一緒に確認をして、そして、相談とか悩みがある子どもたちがいないかどうかを学校と一緒に把握をし、そして、早期の対応が必要な子はいないかどうかを確認をしていくという業務を区費のスクールカウンセラーには依頼をしています。あと、もう１点、時間は短いことはなく、全て同じ時間帯での勤務と認識しております。","id":"exchange-033"},{"speaker":"高橋（し）委員","kind":"質問","question":"私の認識が誤っていたのかもしれませんけれども、巡回して、クラスなどの支援をする子たちを見ていくという表現ですね。令和７年度の幾つかの学校では、支援ですか、そのようなところが主だった、いろいろな人としての素地、そういう部分もあったという意味なのですけれども、そういうのもやりながら、今みたいな、課長が説明していただいたようなこともやる感じでよろしいですか。","respondent":"保土澤教育総合支援センター長","answer":"今お話しいただいたイメージのとおりでございます。","id":"exchange-034"},{"speaker":"まつざわ委員","kind":"意見","question":"スクールロイヤーを明記された。１点、このスクールロイヤーは、例えば管理職が何かあったときに、相談体制ですよね。例えば、こういった課題があったときに、教員の方がすぐにこうやって直接つなげる、何かそういう仕組みを考えているのか、そこを教えてください。","respondent":"保土澤教育総合支援センター長","answer":"スクールロイヤーにつきましては、やはり学校管理職の判断をもって、そして、スクールロイヤーと連携して課題解決を図るという学校での判断の下に連携をしていくものでございます。","id":"exchange-035"},{"speaker":"まつざわ委員","kind":"質問・要望","question":"それは致し方ないのかもしれないですけれども、なかなかそういう一手間が実際に進みを悪くしている、進みづらい要因をつくっているということも、私は一部ではあると思っているので、組織の流れはよく理解していますけれども、ぜひ、そこら辺はもう少し柔軟にいろいろ教員の声を聞いていただきたいと思います。あと、１点、いじめの早期発見について、要は見えないＳＯＳというのですか。その子と話をしているときに、これを表面化することによって、被害者、加害者と明確に言えるのは、子ども的にも親的にもそうですかというお話を受けた案件があったときに、やはりそういった見えないＳＯＳを探していく、これを強化するのは本当にすばらしいことだと思っています。だから、例えば、スクールカウンセラーを全校配置していく中で、そういったアプリをどう使うのか、そういった見えないＳＯＳをどうやって専門家と結びつけて、見えないＳＯＳをどう見える化していくのかとすごく思うのですけれども、そこら辺を教えてください。","respondent":"保土澤教育総合支援センター長","answer":"まさにご指摘のとおり、なかなか表面化してこない。しかし、確実にあるＳＯＳを把握していくことが、早期対応、早期解決につながる大切なことだと思っております。実際には、先ほども少し触れましたが、各学校に追加で配置した区のスクールカウンセラーが、区で今取り組んでいる調査ツール、日々取り組むものと、月１回取り組むものなど様々ありますけれども、そういったものを学校と一緒に確認して、実際の加害、被害の訴え以外にも、少し気になる様子、気になることがありましたと、いわゆる当事者ではない、しかし、同じ集団にいるような、そういった子どもたちからのサインも投稿できるシステムになっておりますので、丁寧に学校と一緒に把握していくのが１つ対応の事例としてあると思います。","id":"exchange-036"},{"speaker":"高橋（し）委員","kind":"質問","question":"先ほどあれだったので、申し訳ありません。スクールカウンセラー、今、全校ですけれども、そういったスクールカウンセラーを見つけていくのが大変だと言われているのですが、複数を１人が兼ねるとしても、配置に関しては現状で整備されているのでしょうか。","respondent":"保土澤教育総合支援センター長","answer":"何とか配備をできたところでございます。","id":"exchange-037"}]},{"id":"topic-06","title":"(6)区立学校におけるいじめの重大事態の発生状況および調査結果","agenda":"(6)区立学校におけるいじめの重大事態の発生状況および調査結果","exchanges":[{"speaker":"のだて委員","kind":"質問","question":"令和７年度１３件目のいじめの重大事態が発生したということで、この間、一回増えて、また減った。今増えている状況ですけれども、増えている理由は、区ではどう考えているのか伺います。それと、この間、報告書が今回２つ出たということですけれども、公表希望なしになってしまって、この事案を今後に活かしていくことがなかなかできていないということを指摘させていただいているのですけれども、その中で学校では共有できるようにしていきたいとお話があったのですが、それが今どこまで進んでいるのか伺います。","respondent":"保土澤教育総合支援センター長","answer":"まず、令和７年度に１３件という件数でございますけれども、確かに令和６年度と比較すると、件数としては増えております。増えているのですが、これはあくまで重大事態として認知したのが令和７年度ということで、対応が令和６年度から続いているものも中にはございます。ですので、特段、令和７年度だけ突出して増えたというよりは、継続している案件も中には含まれて、いじめの重大事態として認知したのが昨年度のものも複数あるとご理解いただければと思います。また、重大事態をはじめとしたいじめへの理解、これが進んでいることも、やはり早期に、可能性の段階でいじめの重大事態として認知して対応するという件数も含まれておりますので、そういった意味でも件数が増となっていると見ております。また、公表の希望がない場合の対応ですけれども、こうしたホームページ等での公表ではなく、学校での、やはり学びと言うと適切ではないかもしれませんけれども、こういう事態は早期対応しないとこういったことになり得るというような、学校での共有についてご理解が得られているケースについては、実際に昨年度も校長・園長連絡会で、前任のセンター長からケースの紹介と、それから、学校での改めての早期対応、それから、丁寧な指導というものを全校長・園長に指導がありました。こうしたことを１つずつ続けていくことが大切だと考えております。","id":"exchange-038"},{"speaker":"のだて委員","kind":"質問・要望","question":"ぜひ今後の取組にも活かしていただきたいと思いますし、当然、保護者、本人の希望も尊重しつつですが、できるところで議会にも公表できるように、検討を進めていただけたらと思います。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-039"},{"speaker":"まつざわ委員","kind":"意見","question":"そうすると、私などが考えると、叩いた、暴力行為は事件だと思います。そうすると、警察の案件と思っていて、例えば、こういった暴力事件があったときの対応の中で、こうやって警察と連携して区としてやっていっているのか。例えば、どこまで警察が入ってくる基準があるのか。それを教えてください。","respondent":"保土澤教育総合支援センター長","answer":"明確にこれをしたら警察という基準はありませんけれども、ただ、やはり各学校で子どもたちの望ましくない、そういった例えば暴力行為等があった場合に、当然指導を行います。その指導で改善が見られず繰り返していくような場合には、保護者との面談も含めて指導を行って、そして、必要に応じて警察と連携することも考えられます。警察と連携する場合には、被害届等も出るかどうか。そういったところも１つポイントになると認識しております。","id":"exchange-040"},{"speaker":"まつざわ委員","kind":"質問・要望","question":"おっしゃるとおり、被害届を出されなければ事件にならないですけれども、こういうことが起こって、不登校になって、解決ではないですが、やはり被害、加害があって、被害者が学校に来なくなって、おしまい。こういった事案は、しっかりと警察の指導を入れるところは入れるという部分も含めて、厳しくぜひやっていただきたい。いろいろあると思いますけれども、そこら辺を厳しく、言い方はきついですけれども、ぜひしっかりやっていただきたいと思います。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-041"},{"speaker":"高橋（し）委員","kind":"質問","question":"少し細かい話で申し訳ないのですけれども、学校種で、小学校、中学校、義務教育学校とあるのですけれども、学校種は学校教育法第１条の学校の種類ですから、小学校、中学校、義務教育学校とか大学とかという表現でいいのですが、これ、いじめの重大事態の公表に関して、特に義務教育学校だと、前期課程なのか後期課程なのか出てこないのです。それを表現しないで発表するのは、区の条例とか国の法律にないと思うので、いわゆる小学校、中学校、義務教育学校の前期か後期かを分けるように公表するほうがよいと思いますので、もし何か条例なりを変えなければいけないのだったら、そこで変えるべきだと思うのですが、その点はいかがでしょうか。","respondent":"保土澤教育総合支援センター長","answer":"今ご指摘いただいた点については、どのような条例と関わるのか私も確認したいと思いますけれども、実際どのような公表、学校種以外の公表が適切なのかどうか含めて、私も勉強して、いろいろなところからも意見をいただきながら考えていきたいと思います。","id":"exchange-042"},{"speaker":"高橋（し）委員","kind":"質問・要望","question":"学校種で公表しなければいけないというルールがあるならばしようがないのですけれども、そうでなく、義務教育学校として公表して、これも決まっていないと思うので、そこをすることが可能であれば、ほかは小学校、中学校とあるし、現実が分からないですよね、義務教育学校のどちらで起きたか。これは要望で。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-043"},{"speaker":"筒井副委員長","kind":"質問","question":"先ほども一部関わって、出た質問だと思うのですけれども、重大事態の分類、１号に当たるのか２号に当たるのか、その分け方なのですが、私も、いじめの態様4)番、ひどくぶつかられたり、叩かれたり、蹴られたりするとあったら、これ、１号に当たると思ったのですけれども、挙げられている事案だと、事案番号１３でも２号になったり、事案番号４でも２号になったりするのですけれども、その点の分け方、１、生命、心身、財産の重大事態は、相当被害が大きくないと適用されないのか。１号と２号の分類の仕方、２号はもちろん不登校にならなければ適用されないと思うのですけれども、１号の適用の仕方はどのように扱っているのか、お知らせください。","respondent":"保土澤教育総合支援センター長","answer":"本件について、結果、様々な望ましくない関わりがあって、そして、不登校という状態になって、一定期間、学校にも通えなくなってしまったというところが、本件で最も保護者や本人にとっても苦しいといいますか、改善すべきところという判断で２号となったと認識をしております。","id":"exchange-044"},{"speaker":"筒井副委員長","kind":"質問","question":"今ご答弁を伺うと、やはり結局、プロセスはともかく、不登校になったことは結構大きなポイントで、そうすると、例えば、１号の要件を満たしていても、不登校ということで２号に吸収されてしまうのか、その辺りどうなのですか。逆に、重大事態１号と２号、同時に当たるという、同時適用はあるのですか。","respondent":"保土澤教育総合支援センター長","answer":"ご指摘のとおり、１号と２号同時に当たる事案もございます。","id":"exchange-045"},{"speaker":"筒井副委員長","kind":"質問","question":"あと、結局は今回、調査結果も出ているのですけれども、事案番号４と１、それで、結局、その調査結果が出たのはいいのですけれども、いじめの被害者の方は、要は、問題は解決したのですか。例えば、不登校が解消されたとか、生命、心身、財産の重大被害が収まったとか、解消されたとか、被害者の抱えている被害状況はもう解消されたのですか。","respondent":"保土澤教育総合支援センター長","answer":"様々なケースがございますので、個別にはお答えできないというところでございます。","id":"exchange-046"}]},{"id":"topic-07","title":"(7)令和７年度、就学・転学相談の結果","agenda":"(7)令和７年度、就学・転学相談の結果","exchanges":[{"speaker":"のだて委員","kind":"質問","question":"転学・通級相談が増えているということで、先ほど特別支援教室の利用が増えているというお話だったと思いますが、結果の受け止め、支援が必要な子が増えているということなのかどうかも含めて伺います。特に小学校で、プラス３２名ですか、特に増えていると思うのですけれども、そこの関係も伺います。","respondent":"新井特別支援教育担当課長","answer":"特別支援教室の利用者数、相談件数が増えているということの受け止めでございます。こちらにつきましては、やはり一般論として、いわゆる発達障害等と言われるお子さんが増えているのもあると認識してございますけれども、利用につながるためには、校内委員会という、学校内での支援の検討が必要になってきます。そういった意味では、学校内で支援が必要という判断、校内委員会がうまく機能している。つまり、きちんとステップを踏んだ上で、特別支援教室の利用が必要だといった判断を学校がきちんと行えているといったことの裏返しと私どもでは捉えております。特に小学校で増えているというところについては、比較的中学校に比べまして、いわゆる支援が必要という第一段階として、小学校生活は入り口になりますので、そういう意味で、中学校よりも小学校のほうが、そういった特別支援教室の利用という必要性を認知する機会としては非常に大きいのか、相談件数が増えているといった受け止めでございます。","id":"exchange-047"},{"speaker":"のだて委員","kind":"質問","question":"全体として増えているところでは、校内委員会がうまく機能しているということでしたけれども、今回、なぜうまくいったのか分かれば、理由を伺いたいと思います。","respondent":"新井特別支援教育担当課長","answer":"うまくいったといった受け止めでございますが、やはり各学校によって事情は様々あると思うのですが、私どもとしましても、これまでも特別支援教室を利用するためには、校内委員会で検討を、研修等でも継続して伝えてきておりますし、あとは、巡回相談員と言われる、私どもの特別支援担当の心理の職員がおりまして、各学校を巡回して児童・生徒の支援の必要性とか、あとは、今の様子の見立てを行っている心理の職員がおりまして、その者も学校からの求めに応じて校内委員会に出席するような形を取っております。そういった意味で、これまでの研修の継続による効果と、あとは、そういった地道な巡回相談員による側面支援が実を結んできていて、校内委員会がきちんと開かれて、より内容があるものになってきていることが１つ要因として捉えてございます。","id":"exchange-048"},{"speaker":"のだて委員","kind":"質問・要望","question":"今のご説明ですと、やはりしっかり手が届いて、必要な人に支援が行き出しているということだと思いましたので、ぜひそれは進めていただいて、子どもたちがしっかりと適切な教育を受けられるようにしていただきたいと思います。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-049"},{"speaker":"高橋（し）委員","kind":"質問","question":"大きな、数字の細かいことではないのですけれども、こういう相談を受けるという保護者の方のハードルが低くなった、心配することが就学前にいろいろ認識されることも、就学相談が増えている１つの原因だと思っているのです。それで保護者の方々への、実際は保育士たちに対するアドバイスですけれども、そういう巡回相談や、さらに、全くこれは違う所管ですが、５歳児健診をすることによって、保護者の方々のそういう認識が広がった、就学相談を受けることにつながったかどうかは、なかなか答弁しにくいと思うのですけれども、就学相談につながって、しっかりとした支援を受けるか受けないか、どうやって小学校生活を送ったらいいかを保護者の方で認識されている方が多くなってきたと思っているのですけれども、その点についてはいかがでしょうか。","respondent":"新井特別支援教育担当課長","answer":"委員ご説明いただきました、いわゆる保育園、幼稚園での巡回相談について、そういった相談の中で、保護者の方の受け止めですとか、そういった気づきは、やはり影響や関係が非常にあると思っております。そういったことを踏まえると、やはりそういった心理の方が園を巡回して、お子さんの様子を見てという事業、活動は非常に大事であると考えてございます。また、５歳児健診との関係ですが、これについては、令和７年度は保健センターにてモデル実施という形で実施をしているところがございます。私どもとしましても、保健センター等とも連携しまして、５歳児健診で健診を受けられた後のフィードバックに、１つ資料として、就学相談の区のホームページにつながるよう、二次元コード等を掲載してご覧いただくですとか、そういった取組はさせていただいております。また、実際にはまだないのですが、就学相談を受けるべきかどうか悩む保護者がいらっしゃった場合には、私どもにぜひ連絡くださいということもチラシでは書かせていただいておりますので、そういった意味で、保護者の方が、例えば５歳児健診の結果をどう受け止めるかということもあって、そこは保健センターを中心にぜひフォローしていただきたいところではございますけれども、私どもとしましても、就学では、やはり保護者からの問合せ等の相談があった場合には、ぜひ寄り添って対応していきたいと考えてございます。","id":"exchange-050"},{"speaker":"高橋（し）委員","kind":"意見","question":"所管がいろいろありますけれども、１人の５歳のお子さんをいろいろ支援する仕組みが区の中では整いつつありますので、しっかりと小学校へのつなぎ、うまく、特別支援をするしないに関わらず、その子たちがしっかりと小学校生活を送れるように、ぜひ連携して支援をお願いしたいと思います。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-051"},{"speaker":"まつざわ委員","kind":"意見","question":"特別支援教室の情緒が増えているという数字の中で、利用が多くなったときに、例えば、学校で専用のスキルのある巡回の方たちの配置が十分なのかというのと、教室がどうなっていくのか、教室の配置も心配なので、そこも教えてください。だから、そうすると、次、冨士見台中学校で開設するお話がありますけれども、やはりこういったのもある程度拡充する計画を考えていかないといけないと思っているのですが、そこら辺も教えてください。","respondent":"新井特別支援教育担当課長","answer":"まず、２点ご質問いただいておりまして、まず１点目の特別支援教室の教員数と、あと、教室の確保でございます。教員につきましては、やはり年度当初の４月時点の特別支援教室を利用している児童・生徒数に応じて教員が配置される形になってございます。制度的には、そういった年度当初の人数で教員数が決まってくるものですから、どうしても年度が進行するに当たって、年度途中から特別支援教室を利用したいというお子さんが増えてくると、人手の工夫がかなり必要になってくる事態は、制度的な要因としてあると認識してございます。また、教室のいわゆるキャパシティ、広さでございますけれども、こちらも人数が増えてきていますので、学校とも連携をしまして、いわゆる教室の使い方で、パーティションを使って指導を分けるとか、指導を円滑に行えるような工夫を行った上で対応していきたいというのがまずありまして、あとは、教室を増やすかどうかについては、通常の学級と言われる、通常の教育課程を受けているお子さんたちの教室の確保とのバランスもありますので、そこは就学人口の動向も踏まえながら、バランスを取って、教育委員会の横の連携もきちんと確認をした上で対応していきたいと考えてございます。２点目の自閉症・情緒障害の特別支援学級の、いわゆる固定の学級の今後の考え方でございますけれども、予算のご議決をいただきまして、令和９年４月に、中学校では３校目となる冨士見台中学校に自閉症・情緒障害の特別支援学級を開設する予定でございます。小学校につきましては、ちょうどこの４月に伊藤小学校に２校目となる自閉症・情緒障害の特別支援学級を開設してございます。今後につきましても、こういったお子さんの状況、人数の状況等を踏まえまして、実際にどこに配置できるかも含めて鋭意、増設の検討はできるかどうかを確認してまいりたいと思っております。","id":"exchange-052"},{"speaker":"まつざわ委員","kind":"質問・要望","question":"制度の要因があることは分かりました。でも、やはりこういったものは、大変になってからやる後手後手の施策だと駄目だと思っていますので、先手の施策というのも変な話ですけれども、こうなるであろうというある程度の方向性の中でやっていただいていると思いますけれども、引き続き、こうなるだろうという見込みの中での考え方もぜひ取り入れていただきたいと思います。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-053"}]},{"id":"topic-08","title":"(8)自閉症・情緒障害特別支援学級の開設","agenda":"(8)自閉症・情緒障害特別支援学級の開設","exchanges":[{"speaker":"のだて委員","kind":"質問","question":"今回、冨士見台中学校に新たに自閉症・情緒障害特別支援学級を開設するということで、そうすると、現状では、これは必要な子どもたちは入れる、足りているのか。あと、今、増加が見込まれるということで冨士見台中学校が増えるわけですけれども、さらに今後どうなっていくのか、この見通しを伺います。","respondent":"新井特別支援教育担当課長","answer":"２点ご質問いただきまして、まず、１点目の特別支援学級での支援が必要な子がきちんと入れているかについては、希望するお子さんは全員入れている状況でございます。また、２点目につきましては、さらに今後どうしていくか、特別支援学級を増設していくかについてですが、現在、過去５年の推移を見てみますと、浜川中学校と大崎中学校で５０名前後の在籍という形で推移をしています。比重としましては、浜川中学校が３０名後半で推移していて、大崎中学校が１０名から２０名の間で推移してございます。今後については、何とも難しいところでございますけれども、やはりいわゆる自閉症・情緒障害の特別な支援を必要とする児童・生徒の推移をきちんと見極めた上で、開設というのを先々を見据えて検討していきたいと考えてございます。","id":"exchange-054"}]},{"id":"topic-09","title":"(9)「品川区社会的養育推進計画」の策定","agenda":"(9)「品川区社会的養育推進計画」の策定","exchanges":[{"speaker":"のだて委員","kind":"質問","question":"パブリックコメント５番の意見で、障害相談が１割あるけれども、障害児に関する取組の記載が１か所しか見当たらないと書いてあるのですが、それに対して区は、別の障害児福祉計画で記載していると答えているのですけれども、実際、障害児が社会的養護を必要としたときにはどういった対応になるのかを伺いたいです。そうしたケースがあった場合、社会的養護での考え方もないと、しっかりやっていけないと思ったのですが、そこの関係を伺いたいと思います。あと、７番の意見で、先ほどもご紹介がありましたけれども、本当にこれは１つ重要なことだと思います。その中で、区としては、ケースとの関わりや業務の専門性に配慮した職員配置を行えるように努めるということだったのですが、具体的に言うと、何かそういう配慮ができる仕組みがあるのかどうか、所管の考えを伺います。あと、１８番の意見で、これ、保護が必要な子どもをどう見つけるかということだと思うのですけれども、今、見つける方法は通報に頼っていると見ているのですが、実際今、そういった仕組みがあるのか。回答では、しながわネウボラネットワークとかが書いてあるのですけれども、そうしたしながわネウボラネットワークでの事業、取組をやっている中で見つけていくのか伺いたいと思います。","respondent":"柴田子ども施策連携担当課長","answer":"ただいまパブリックコメント３件につきまして、ご質問いただいたと存じます。順番にお答えします。まず、No.５、障害相談に関して、今どのような運用になっているかでございます。こちら、児童相談所の統計上、障害相談、実際に１０％、１割計上されております。続きまして、No.７の人材配置、職員配置に対してどのような配慮ができるのかというところと存じます。それから、最後に、No.１８のご意見についてでございます。もちろん通報を受けてというのもあるのですけれども、通報を受けないで行っているケースとしましては、所管は保健部門になるのですが、新生児の赤ちゃん訪問を実施しておりまして、それは保健センターと、子ども家庭支援センターが協力して全家庭を訪問するような形を取っております。","id":"exchange-055"},{"speaker":"のだて委員","kind":"質問・要望","question":"様々やられているということで、ぜひ取りこぼしがないように、あと、職員配置についても意見を言う場はあるということですので、ぜひケースなど含めて、配置が考慮されるように力を尽くしていただきたいと思います。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-056"}]},{"id":"topic-10","title":"(10)品川区乳児等通園支援事業に係る子ども・子育て支援事業計画の代用計画策定","agenda":"(10)品川区乳児等通園支援事業に係る子ども・子育て支援事業計画の代用計画策定","exchanges":[{"speaker":"のだて委員","kind":"質問","question":"すみません、説明を聞き逃してしまったと思うのですが、別紙１の表で、必要定員数は、利用者数から割り出された必要な人数、枠ということなのか伺いたいと思います。私が見ていた中で、利用者数が令和８年４月１日でいくとニーズが５９２で、下の必要定員数が整備した数と思ったのですが、そこを伺いたい。どう見るのかを伺います。あと、子ども・子育て会議でも意見を聴取したということで、そこではどういった意見が出たのか伺います。あと、今回、代用計画を策定するということで、計画を策定すると補助金が出るとか、メリットがあるのかどうか。あるいは、デメリットはないかもしれませんが、デメリットがあるのかどうか伺います。","respondent":"佐藤保育事業担当課長","answer":"それでは、幾つか質問をいただきましたので、お答えさせていただきます。初めに、利用者数と必要定員数の関係性でございますが、委員お話しいただきましたように、就学前の児童数から様々利用率等を勘案して計算したのが、利用者数の５９２になります。この５９２名の方が１か月３０時間を上限として区としては利用をしていただこうと考えてございますので、その３０時間を掛けた数字が必要受入時間数になります。そこで１か月の利用、保育園の１名の定員などでは、基本的には１か月１７６時間の利用が基本となっておりまして、国の式においては、１７６時間でこの受入れ時間数を割りますと、必要な定員数が出てくるものでございます。ですので、令和８年度でいきますと、１０７名の定員数の空きが必要であるというのが分かるものでございます。続いて、子ども・子育て会議で出てきました意見についてでございますけれども、委員の方に子育てをされていらっしゃる方がいらっしゃいまして、そういった方から、実際に利用するまでの経緯、流れを伺いたいとご質問をいただきまして、国のシステムを活用してオンラインでご申請をいただいて、オンライン上で空きがあるかを確認しながら実施していただくことができるものであるという説明をさせていただいてございます。そうした説明をさせていただいた後に、ご意見として、保護者にとって使いやすいような方法になるように要望がございましたので、そうした要望を受けまして、区といたしましても、利用マニュアル等、しっかりとした周知でありましたり、事業者の方に関しましては、国のシステムへの登録の仕方等々、ＹｏｕＴｕｂｅ上で閲覧できるような働きかけをしたり、丁寧な対応をしっかりと行っております。","id":"exchange-057"},{"speaker":"のだて委員","kind":"質問","question":"そうすると、この必要定員数、４月１日時点では１０７人必要ということで、実際、定員がどれだけ埋まっているかで決まってくるので、具体的なところは分からないと思うのですけれども、現状として枠が足りるのかを伺います。この枠が１歳児、２歳児が１０人ずつで、ほかから見ると結構大きな枠で、ゼロ歳児はやらない、そうした内訳にした理由を伺います。","respondent":"佐藤保育事業担当課長","answer":"まず、現状、この枠で足りるのかというご質問にお答えさせていただきます。５月時点での空き枠が既に発表されてございまして、本事業を実施する事業所の空きの状況が、合計で２００を超える空きがございますので、算定させていただいている１０７の必要な枠に関しては足りると現状では認識してございます。続いて、ひがしやつやま保育園の実施についてでございますが、区立園ということで、区と事業者で意見交換をさせていただきながら、実施をしていくというのを決めたものでございます。ほかの園に比べて定員が多いというところでございますが、ひがしやつやま保育園に関しましては、今、５歳児クラスのみで運営をしておりまして、今年度で一応閉園をしていく園でございますので、空きのスペースが非常に多くあるといった背景がございまして、ほかの園に比べて多い定員となってございます。","id":"exchange-058"},{"speaker":"まつざわ委員","kind":"意見","question":"定員に限りがある中で、例えば、多胎児であったりとか、双子とか三つ子だったりとか、そういった家庭とか、親族の支援が得られない、近くに親がいなくて助けが必要、そういった支援の必要性が高い、そういったご家庭などが優先的に利用できるような、何かそんな枠組みはあるのか。","respondent":"佐藤保育事業担当課長","answer":"支援が必要なご家庭に対する支援の仕組みということでございますが、基本的に我々、試行的事業で令和５年度から実施してございまして、そうしたご家庭のお預かりというのも継続して実施してございますので、そこにつきましては、今後についてもしっかりと対応していきたいと考えているところでございます。","id":"exchange-059"}]},{"id":"topic-11","title":"その他","agenda":"その他","exchanges":[{"speaker":"若林委員","kind":"意見","question":"そうすると、そういう製造ラインは、よくテレビとかで見かけることがあるのですが、ノズルは１つではなくてたくさんありそうですが、そこら辺との兼ね合い、全てのノズルに付着していたのか、幾つもあるノズルのうちの１つだけれども、安全性を云々ということなのか、そこだけ。","respondent":"石井学務課長","answer":"安全性につきましては、雪印メグミルク株式会社からの報告を待っているところですけれども、全てのノズルについていたというよりは、消毒作業のために消毒液を噴霧するためのラインから出たものだと聞いております。ですので、現状は一部のノズルであると考えられます。","id":"exchange-060"},{"speaker":"のだて委員","kind":"質問","question":"明日からはきちんと届けられるということでしたけれども、それは別の製造ラインでやるのかをお伺いできればと思います。","respondent":"石井学務課長","answer":"まず、製造ラインについては、工場は複数ございまして、今回、１つのラインにおいて異物が見つかったということでございます。あとは、復旧作業ですけれども、先ほど消毒のための消毒液噴霧の部分において見つかったということで、異物自体は現在除去されているのですが、消毒のやり方を変更するような形で対応ができるということで、通常どおりの出荷体制が組めるとの報告でございます。","id":"exchange-061"}]}],"links":[{"type":"minutes","label":"公式の会議録を読む","url":"https://kaigiroku.city.shinagawa.tokyo.jp/index.php/631298?Template=document&Id=7359#one"},{"type":"official","label":"公式の会議録一覧","url":"https://kaigiroku.city.shinagawa.tokyo.jp/index.php/100000?QueryType=new&Template=list&Cabinet=9&TermStart=2026-01-01&TermEnd=2026-12-31"}],"sourceMeta":{"pages":0,"characters":44558,"voices":191}},{"id":"r08-20260414-5","meetingId":"r08-m0405","date":"2026年4月14日","dateIso":"2026-04-14","committee":"総務委員会","time":"午後 １時００分～午後 ２時５１分","status":"正式会議録","sourceType":"formal","overview":"総務委員会の会議録から、実質的な質問・確認・意見・要望と答弁・対応を46件整理しています。","topics":[{"id":"topic-01","title":"請願・陳情審査を行います。 初めに（１）令和８年陳情第１１号、身体の不自由な人がもっと投票しやすくなるよう現行制度の改善を求める陳情","agenda":"請願・陳情審査を行います。 初めに（１）令和８年陳情第１１号、身体の不自由な人がもっと投票しやすくなるよう現行制度の改善を求める陳情","exchanges":[{"speaker":"西本委員","kind":"質問","question":"この陳情理由の中に、「せっかく制度があるのに利用がしづらいのはとても残念です」という言い方をされているのですけれども、今のご説明だと、何が問題なのかよく分からない。制度があるのは分かっているのですけれども、この「利用がしづらい」というのは、どういう観点でというところを教えてほしいのと、それから、介護状況になっているときに自分の意思判断がどこまでできるのかと思っていて、周りは連れていきたいと思っていても、やはりこれは自分の意思がしっかりと反映できるのが選挙であるべきだと思うのです。なので、連れていくことは可能だけれども、周りがサポートすれば連れていける、在宅でできるのだけれども、その判断がきっちりできるか否かをどう判断されるのか。自分の意思だったらいいのですけれども、周りが「こう書くのよ」とかというような状況はよくないと思うのですけれども、その辺の区分けとか判断はどのようにされているのですか。","respondent":"東野選挙管理委員会事務局長","answer":"まず、制度の利用がしづらいという部分につきましては、先ほどもお話しさせていただきました、訪問介護の場合ですと、あらかじめケアプランに位置づけておく必要があるところで、急遽、選挙だから訪問介護で付添いをお願いしますといっても、「プランに入ってないですよ」と断られる場合があることが１つ挙げられると思います。また、社会福祉協議会のさわやかサービスなどにつきましても、事前に会員登録しておく必要がある、または月の会費を払っておく必要があるなどというような、事前にそういったことをしておかないといけないところで、なかなかそれが投票時に結びつかないところがあると考えられます。周りの人がどうこう言おうと個人の判断になりますので、選挙の投票所におきましては、連れてこられるのはご家族の方でも、その方が記載台で記載するところにおきましては、もし介助が必要であれば、選挙の事務長であったり、担当がそこに付き添ってということもありますし、または代筆も同じ職員でする場合がございますので、その点につきましては、選挙管理委員会としては十分に個人の意思が判断できる状態で投票いただくと考えているところでございます。","id":"exchange-001"},{"speaker":"西本委員","kind":"質問","question":"ありがとうございます。自分の意思が反映できるところが大切なので、そこはなかなか判断が、表から見てどう判断できるのかは難しいところではありますけれども、自分の判断でということを極力お願いしたいと思います。それと事前に申請するということなのですけれども、選挙がある場合には介助をしてほしいというのを、介護認定とか何か申請するときに、それは事前に申請はできるものなのでしょうか。介護認定するときに、自動的にお願いすることができれば登録できるのではないかと思うのですけれども、それはどういう仕組みになっているのでしょうか。","respondent":"東野選挙管理委員会事務局長","answer":"介護認定は、その人の要介護の状況を認定するものでございまして、個々によって要介護状況が違いますので、そこでケアマネジャーが入って、ケアプランを作る形になります。","id":"exchange-002"},{"speaker":"西本委員","kind":"確認","question":"ありがとうございました。なのでそこは、こういう陳情があったのも事実であるので、分かりやすく、また忘れないようにとか、介護認定とかいろいろ手続をするときに確認するとか、それももう少し周知できるかと思いますので、よろしくお願いいたします。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-003"},{"speaker":"須貝委員","kind":"質問・要望","question":"今、局長から話を伺って、品川区として、各自治体にも自治体なりにできるところはやっている状況だと私は思います。実際、投票の方法として、障害者が国に要望などを出していますけれども、郵便投票の対象拡大として、事前にケアプランに入れておかなければいけないとか、施設・病院での不在者投票の要件は、おおむね５０人以上の人数要件があるらしいですけれども、そういうこともあったり、あと代理投票補助の柔軟化と様々な問題があると思うのですが、実際、根本的には国の法律の改正といいますか、こういう方たちが選挙へ行きたいということに対する柔軟な投票方法を考えていかないと駄目かと私は思うのですが、その辺どうなのでしょうか。それで、あともし自治体でやるとしたら、相当個別に対応しなければいけないという大きな問題が今度はあって、それに対して対応し得るのかという心配もあるのですが、その２つについてお聞かせください。","respondent":"東野選挙管理委員会事務局長","answer":"まず、根本的なところに関しましては、こちらは公職選挙法に位置づけしてある、それから住民投票につきましては対象が決まっておりますので、現在は拡充に向けた議論がされているということでございます。これは全国的な問題であって、議論の俎上にのっていることでございますので、今後、拡充に向けた動きがあるのではないかと考えているところでございます。それから、自治体で個別にというところでございますと、個別に対応するパターンがかなり複雑になっておりますので、選挙時に全部対応することはなかなか難しいかもしれません。ただ、やはり身体に不自由のある方につきましても投票に関わっていただけるように、選挙管理委員会でも既存の制度の中で対応していきたいと考えております。具体的に、ほかの自治体で個別に対応している例もあります。品川区におきましては、４３投票所がございますので、歩いて行ける距離にはあるところを考えますと、なかなかそういう交通手段の補助は難しいかと思っております。","id":"exchange-004"},{"speaker":"須貝委員","kind":"質問・要望","question":"そうすると、今の局長の話をこちらで解釈すると、やはりこれからも体の不自由な人がもっと投票しやすくなるような現行制度の改善は、それぞれ自治体でも国に要望しているし、障害者協議会のほうも国にしっかり要望されているというその方向で、社会全体が今動き出していると考えてよろしいでしょうか。それだけ教えてください。","respondent":"東野選挙管理委員会事務局長","answer":"今おっしゃったとおりでございまして、やはり体の不自由な方対しての投票を、各自治体だけではなく、国全体として今考えているところでございます。","id":"exchange-005"},{"speaker":"澤田委員","kind":"質問・要望","question":"本日結論を出す。会派としても、ガイドヘルパーの人材を増やす取組について要望したりしていたのですが、それについても、区としてもより多くの人を支援していただけるように、ガイドヘルパーを増やす取組に力を入れてくださっていることもありますし、これからより使いやすくなるのではないかと期待しております。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-006"},{"speaker":"山本委員","kind":"質問・要望","question":"本日結論を出すで、不採択でお願いいたします。その中で、先ほどの区のご説明によれば、郵便投票は国の制度改正事項であって、区からは要介護５から要介護３に引き下げるよう、既に出しているということですので、まずはできることを行っていると思っております。これについては、引き続きその要望をしつつ、その動向を見守っていただきたいと思います。支援制度の分かりやすい周知・啓発の強化と、支援制度の使いやすさ、さらなるアップデートをお願いしたいと思います。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-007"},{"speaker":"塚本副委員長","kind":"質問・要望","question":"本日結論を出します。移動支援については、求めに応じて全て移動の支援をしていくのは、なかなか現実的には区の行政サイドの負担が大きいでしょうし、本当に郵便投票の拡充によって、移動支援ではなくて、郵便でできるという方も結構出てくるのではないかということもあると思いますので、そこをしっかりまずは拡充していくことによって、ひとまず陳情されている方の思いに応えられるかなというところが大事かと思いますので、不採択でお願いします。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-008"},{"speaker":"松本委員","kind":"質問・要望","question":"本日結論を出すで、不採択でお願いします。他の委員の皆さんもおっしゃっているとおり、問題意識としては重要かと考えますが、どのようにやるかは国の事項で、地方としては国に意見書の提出を求めるものでもないところでありますから、現実的には国にまずは変えていただきつつ、あとはできることを区でやっていくことになるかと思います。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-009"},{"speaker":"須貝委員","kind":"質問・要望","question":"私は、本日結論を出すことと、採択でお願いいたします。陳情理由の下のほうで書いてありますけれども、よりよい制度に改善していただけるように、国や各自治体に要望すると。「よりよい制度に改善していただけるように望みます」ということですから、社会全体がこの動きになっているならば、私は採択するべきではないかと思います。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-010"},{"speaker":"西本委員","kind":"質問","question":"本日結論を出すで、不採択でお願いします。今の適用範囲を広げるのは国のほうの制度ということで、国が今、検討しているということですから、それは待つしかないと思っています。現行制度の改善と言っているのですけれども、今いろいろと対処していただいているということで、私はやはり周知が足りないのではないかというところにあるので、周知をして、使っていただくのをまずはお願いしたいと思っています。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-011"}]},{"id":"topic-02","title":"（２）令和８年陳情第１２号、３３万円の公金を使って弁護士相談をしないと監査の実施の有無を判断できないなら、監査委員を法的専門性を有する弁護士等で構成するよう区に求める陳情","agenda":"（２）令和８年陳情第１２号、３３万円の公金を使って弁護士相談をしないと監査の実施の有無を判断できないなら、監査委員を法的専門性を有する弁護士等で構成するよう区に求める陳情","exchanges":[{"speaker":"須貝委員","kind":"質問","question":"地方自治体の一般的な監査委員ですが、監査委員は監査請求の内容が適法か違法か、不当があるかなどを一般的に監査委員は判断するわけですよね。一般的には弁護士や公認会計士経験者などの識見を有する委員がいて、その方たちが監査請求の内容が妥当かどうか、不当か違法かを判断するのが一般的だと私は思います。それが、弁護士が監査委員の中に入ってないですから、またわざわざ別の第三者に聞くのは、何か間違っているのではないかと思うのです。こういうことで今回はこちらのほうでは扱いませんとか、そういう判断をするのが筋道だと私は思うのですが、その辺について、どのようにお考えでしょうか。教えてください。","respondent":"黒田監査委員事務局長","answer":"まず、監査委員の役割といたしましては、先ほどご説明申し上げたとおり、区の事務事業の執行や財務について監査を行うものであり、監査委員の監査は、これらの事務の適法性・能率性の確保を図る観点から行われているものでございまして、これらの監査の事務に当たりましては、まずは一義的に事務局のほうで様々、定期監査もそうでありますし、特に決算の時期になれば決算審査、基金運用状況審査、財政健全化審査、今回陳情にあります住民監査請求もございますが、事務局のほうで資料を作りまして、そういった資料に基づいて、監査委員に協議いただいて、お諮りしているといった内容でございます。","id":"exchange-012"},{"speaker":"須貝委員","kind":"質問","question":"私の質問が悪かったのかどうか分かりませんが、監査請求の内容が妥当か違法か不当かなどをきちんと判断して、回答するのが役割ではないですか。それを、監査委員がいるのに、またさらに第三者に聞くなら、監査委員は要らないではないですか。どうなのでしょう、その辺、ご見解をお聞かせください。","respondent":"黒田監査委員事務局長","answer":"今のご質問にありました、監査委員が最終的にその監査の内容について判断は、ご指摘のとおりでありまして、その監査を判断するに当たりまして、資料の作成を事務局で行っておりますので、事務局の資料の作成の際に、先ほど申し上げた技術士でありますが、今回の陳情にあるような法的な助言を求めたものでございまして、監査に当たっては、監査委員が合議により決定しているものでございます。","id":"exchange-013"},{"speaker":"須貝委員","kind":"質問","question":"かみ合わないので、質問してもずっと繰り返しになってしまうので、でも何度も申し上げますけれども、監査委員は、区の方針だ、会計だ、決算だ、予算だ、そういう様々なものをしっかり監査する。そのために監査委員は置かれているので、それは日本全国自治体がそうやっているわけですから、私は品川区もそこはしっかり考え直すべきではないかと思います。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-014"},{"speaker":"松本委員","kind":"質問・要望","question":"ありがとうございます。先ほどの説明の中で、今回、弁護士費用を出しているということで、３３万ではなく１２万余という話だったと思いますので、これは法令の解釈を監査委員事務局のほうで確認するためにというお話だったのですけれども、そこの流れをもう一回、経緯をご説明いただきたいというか、どういう流れで弁護士に相談することになったのかをご説明いただければと思います。","respondent":"黒田監査委員事務局長","answer":"まず、住民監査請求が出されますと、まず請求書の内容に不備がないというところで要件を確認させていただきまして、そこに事実証明書という、いわゆる証拠が添付されているかといったような要件があります。これは一般的に形式的審査と申してございますが、その次に、住民監査請求は区が行う全ての事業が対象となっているわけではございませんで、いわゆる違法・不当な財務会計行為が行われた場合に、いわゆる損害の補填や措置を求めることができる制度でございますので、まずその要件に合致しているかといったところについて、過去に様々な判例などがありますので、そういったところについて、一義的には職員のほうで調べまして資料を作成するのですが、その際に法的助言を、今回は弁護士に助言いただきまして資料をまとめたところで、その資料に基づいて、監査委員の協議に付すといったような流れで進めているものでございます。","id":"exchange-015"},{"speaker":"西本委員","kind":"質問","question":"この陳情の趣旨のところに、３段目、「自ら調査・判断せず、外部弁護士への相談に３３万円もの公金を安易に投じています」と書いてあるのです。監査委員は何もやらないのですか。これは言い過ぎではないかと思うのですけれども、すごく誤解されているのかと思うのですが、実際は監査委員の方々は具体的にどのような活動をされているのでしょうか。私は監査委員になったことがないので、よく分かってないのですけれども、どういう調査をして、どれぐらいの頻度でされているのか。あと現地とかに行っていろいろと調査しているのだと思うのですけれども、それも含めて結構忙しいのではないかと思うのですけれども、いかがですか。","respondent":"黒田監査委員事務局長","answer":"監査委員の主な職務ですが、先ほどご説明いたしました、事務事業概要の３ページ、４ページをご覧いただきまして、３ページの一般監査にあります定期監査につきましては、前期と後期に、監査結果という形で議会に報告させていただいておりまして、そういったいわゆる細かい事務的なところは事務局職員が行っておりますが、その内容について、監査委員のほうで基本的には協議に付して、検討しているといった内容でございまして、外で監査するということであれば、こちらにあります工事監査では現場の確認などを行っておりますし、決算の時期ですと、決算審査ということで、こちらについては、区の事務事業について執行状況などを確認いたしまして、最終的に決算審査意見書としてまとめている業務もございますので、通年通して職務がありまして、そういったことを事務局のほうで監査委員の指揮の下で、進めているものでございます。","id":"exchange-016"},{"speaker":"西本委員","kind":"質問","question":"監査体制はということで、議員選出の監査委員が２人ですね。そして、行政ＯＢ、公認会計士の監査委員ということですけれども、多分この陳情で言っているのは、専門家の方を入れるべきではないのかということだと思うのですけれども、外部弁護士というのがあるのですけれども、弁護士さんとかの専門的な方が入ってもいいのではないかとおっしゃっている部分もあるのかなと思っているのですが、これは判断が難しい、この現４人ぐらいいるのかな、で判断がつかないものについては、外部の弁護士とか、あと事務局のほうでいろいろ資料を作るに当たって、法的な判例とかいろいろなものが必要だということで相談をするという感覚なのだろうと思うのですけれども、専門的な弁護士を監査委員の中に入れる必要はないのでしょうか。それはどういう役割、どういう仕事の範疇になっているのかなと思うのですが。","respondent":"黒田監査委員事務局長","answer":"監査委員につきましては冒頭、説明させていただいたとおり、区長が区議会の同意を得て、識見を有する者２名と、議員のうちから選任する監査委員２名を選任している状況でありますので、事務局といたしましては、選任された監査委員を支えて、指揮の下、議論を進めるといったところでございます。","id":"exchange-017"},{"speaker":"西本委員","kind":"質問","question":"やはり不安というか、弁護士などの専門家が委員であってもいいのではないかと言っているのではないかと思うのです。なので、私はこの別途３３万円を払っているというのは、別に不思議なことではなくて、必要があれば、外部の弁護士に聞いてというのは当然、報酬が必要だと思います。それは一応こういう決まりになっているからそうやっていますということは分からないではないのですけれども、それは現状は現状であって、でも弁護士とかそういう詳しい人たちに当初から入ってもらうことも必要な部分はあるのではないかと思うのですけれども、いかがでしょうか。","respondent":"中西総務課長","answer":"議選の監査委員の関係になりますので、私からお答えさせていただきます。また、財務管理における識見を有する監査委員のほうも選任してございますので、相互に連携しながら、それぞれの専門性を生かしながら、補完し合って今、監査を行っていただいている状況でございます。私どもとしましては、様々監査委員の在り方につきまして議論があることは承知してございますが、現在のところ、適正に監査が行われていると思ってございますので、引き続き現在の制度運用を継続してまいりたいと考えてございます。","id":"exchange-018"},{"speaker":"西本委員","kind":"質問","question":"ということは、弁護士等々の、本当にそういう方には、その都度、聞くだけでいいということですか。私は初めから入ってもらったほうがいいのではないかと思っているのですけれども、そういう検討はする必要はないという結論なのでしょうか。","respondent":"中西総務課長","answer":"現時点においては、この形で適正に運用されていると認識してございますので、この運用を進めてまいりたいと考えてございます。","id":"exchange-019"},{"speaker":"山本委員","kind":"質問・要望","question":"本日結論を出すで、不採択でお願いいたします。この陳情者の方が述べている弁護士費用３３万円は、ご説明によりますと、予算として計上されているもので、実際、本質的な内容の相談というよりは、回答における資料作成の法的な助言ということだったので、そういうのは必要なものだと私も思いますので、実質１２万円余ということで、必要に応じて、それは予算として使っているということで理解をいたしました。その上で、本陳情が求める内容、法的専門性のある外部委員のみで構成することについては、同意しがたいので、不採択と考えます。また、我が会派としては、監査の独立性や専門性を高める観点から、これまでの監査委員制度に加えて、外部監査制度の導入を政策要望として要望してまいりましたので、これは引き続き要望していきたいと思います。今回のこの判断は、監査の質の向上を否定するものではなくて、その進め方として、法律の専門家だけに頼るのではなくて、実態を理解した視点を含めて、監査体制をよりよいものに整えるべきだという考え方によるものでございます。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-020"},{"speaker":"塚本副委員長","kind":"質問","question":"本日結論を出すで、不採択でお願いします。陳情の内容では、ある１つの住民監査請求について、弁護士に意見を聞いたことをもって、監査委員が判断を全部、外部の法律家に委ねて、判断を丸ごと委ねたかのような認識をされているように理解しましたけれども、そういったことは、私も監査委員をやった中の１人としては、最終的にはやはりいろいろなご意見を専門家からアドバイスいただくようなことはあったとしても、そこは最後の責任は監査委員の中で結論を出していることには疑いの余地はないところなので、そういったところが１つ誤解があるなと思うところと、法律の専門家の方が監査委員になることを、ふさわしくないとは思いませんけれども、法律家だけで監査委員というのも、また適正ではないと。やはり行政に精通している者が、ある事業についての予算立て、執行が目的に沿っているのか、また、それは本当に区民の行政サービスとして必要なのか否か、そういったことの監査が通常業務の中では圧倒的に多いので、こういうことを判断すると、やはり行政に精通した人物を選定するほうが意味もありますし、法律的なことについては、今のように必要なときに個別に意見を伺うことが効率性はあるかと思いますので、不採択でお願いします。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-021"},{"speaker":"松本委員","kind":"質問・要望","question":"本日結論を出すで、趣旨採択でお願いします。先ほど確認させていただきましたけれども、この陳情は若干、誤解があるところもあると思うのですけれども、このほかの流れをお伺いしたら、事務局のほうで法令解釈とかを検討されて、さらに法律相談も行われたところかと思います。なぜ質問させていただいたかというと、これは監査委員ではないところで、附属機関の問題をこの間、いろいろ取り上げさせていただいたのですけれども、どこまで職員ではない外部の人たちが、区の監視というか、監視という言い方は強過ぎるかもしれないのですが、どこまで関与していくかは、透明性とか第三者性を高めていくという１つの重要なところだと思っています。その上で、品川区の場合は、先ほども西本委員から、弁護士を入れなくていいのかという質問がありましたけれども、入れられない理由としては、議員選出監査委員が２名というのが、これは条例に書いてあるからだと思います。２人いたら、もともとの行政職にあった方が１人で、会計監査をやらなければいけないから公認会計士１人と入れたら、あとは議員選出の監査委員しか入れられない構造が条例上あって、これを変えない限り多分、法律の専門家はなかなか入れられない状態だと思います。そのように考えていくと、政策的な観点から、議員選出の監査委員がいたほうがいいというご意見は分かるのですが、それは１人でいいではないですか。そしてもう１人は法律の専門家を入れていけばいいではないですかと私は思うところです。なので、この陳情の趣旨は、監査委員を法的専門性のある外部委員で構成するようにというところなので、必ずしもそれは全面的に、ではこうしましょうとまでは言えないのですけれども、やはりこの趣旨を考えていくと、これは何回も須貝委員が質問しているし、私も質問しているところですけれども、そろそろ変えていったほうがいいのではないかと思いますので、ここは趣旨採択とさせていただきたいと思います。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-022"},{"speaker":"須貝委員","kind":"質問・要望","question":"私は本日結論を出すことと、採択でお願いします。先ほども申し上げましたけれども、監査には、お金を勘定できる公認会計士と、それから弁護士、これは最低限、設ける。これはほかの自治体もそうですが、きちんとどんな区の施策に対しても、様々な法律的な問題に対しても、きちんと応えられる、それが監査であって、民間企業なら社長にまで意見できる、そういう地位にあります。その監査委員がいるにもかかわらず、またさらに外部の弁護士に相談するなどというのは、これはおかしな話で、こんなのだったら監査なんか要らないで、常に第三者でやればいいわけです。それをこれからも続けていこうということなのですが、こういうやり方は私はまずいと思うので、しっかり区としても私は対応を考えていただきたいと思います。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-023"},{"speaker":"西本委員","kind":"質問・要望","question":"本日結論を出すで、不採択でお願いします。別に４名ではなくて、５名にすればいいのではないですか。議員が１人となると、１人の人に負荷がかかってしまうので、やはり複数いたほうがいい。この陳情の後ろの２ページ目に、区長室長の答弁が書いてあります。下にラインを引いているところ、まさしくこの考え方は私は正しいと思っていて、議員は議員の活動をやっている中で判断すべきところ、やはり住民サービスはよく知っているという特性を持っている。いろいろな識見から見ていかなければいけないことを考えると、やはりいろいろな方が入っていただいたほうがいいと私は思っていて、弁護士はやはり今後、通常入れていく方向で考えていっていいのではないか、そのための条例改正はあってもいいのではないかと思っていますので、ぜひ検討していただきたいと思っております。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-024"},{"speaker":"松本委員","kind":"質問","question":"陳情書の読み方でいったら、善意に解釈すれば、もちろん法的専門性のある外部委員だけと読まないことも可能ですけど、これは行政の部分が基本的には大事なので、全部弁護士ですか。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-025"},{"speaker":"松本委員","kind":"質問・要望","question":"これは、でも須貝委員、読んでいただきたいのですけれども、監査委員を法的専門性のある外部委員で構成するよう区に求めてくださいなのです。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-026"},{"speaker":"松本委員","kind":"質問","question":"法的専門性のある外部委員で構成すると書いてあるんです。須貝委員の意見と陳情の内容は違うではないですか。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-027"},{"speaker":"須貝委員","kind":"意見","question":"そこまで深入りするとまずいかなと思って、私は発言はあえてしていませんが、本来なら監査委員に議員がなるべきではないのです。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-028"},{"speaker":"松本委員","kind":"意見","question":"伝わらないので、分かりました、私のほうの解釈は、監査委員の法的専門性のある外部委員で構成というのは、少なくとも法的な知識がある人たちで構成してくれという趣旨だと私のほうで解釈いたしまして、やむを得ず。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-029"}]},{"id":"topic-03","title":"（３）令和８年陳情第１４号、オンラインによる情報公開請求における受理通知等の仕組みの整備に関する陳情","agenda":"（３）令和８年陳情第１４号、オンラインによる情報公開請求における受理通知等の仕組みの整備に関する陳情","exchanges":[{"speaker":"西本委員","kind":"意見","question":"個人情報開示請求、個人情報なので、先ほどもご説明の中で結構難しいということもあるのですけれども、でも検討しているとおっしゃっていた部分があるので、どういう検討をなされるのか。私は個人情報開示となると、かなりハードルは高いのではないかと思っているのですけれども、その辺はどういう見解を持って今、進めようとしているのか教えてください。","respondent":"田口戦略広報課長","answer":"個人情報の開示の件につきまして、どのようなオンラインでの手続を検討しているかでございますが、今、品川区のほうでは電子申請のシステムを用意しておりまして、その中で、マイナンバーを使って本人確認をしてという手続の方法も取れる仕様になっておりますので、今後、マイナンバーなどを使った場合の手続の方法について、どのようにすれば実際の運用につながるかについて今、検討を進めている段階でございます。","id":"exchange-030"},{"speaker":"西本委員","kind":"質問","question":"すみません、私もあまり詳しくないかもしれません、個人情報というのは、これは自分に対して、いろいろな方々も、他人に対して、どこまで拡大されるものなのですか。","respondent":"田口戦略広報課長","answer":"こちらの保有個人情報の開示請求における個人情報についてでございますが、こちらはあくまでも申請者自身の情報に関することになりますので、ほかの人の情報は含まれない、自身の情報のみになります。","id":"exchange-031"},{"speaker":"西本委員","kind":"質問","question":"今、検討されているということで、これからめどというか、このぐらいまでにはできるかとかという計画は立っているのでしょうか。","respondent":"田口戦略広報課長","answer":"オンライン申請の、いつぐらいにというめどでございますが、今年度中もしくは来年度中のうちにはというところで今、進めているところでございます。","id":"exchange-032"},{"speaker":"須貝委員","kind":"確認","question":"実際、オンライン情報公開請求となると、相手方の本人確認や受付の仕組みづくりが本当に大変なことになると思うので、それがこれから構築されていくには、まだかなりの時間がかかるのではないかと思います。オンラインでやれば、利便性としては格段に向上するのですけれども、今度は逆に危険性も１つあるかと思うのですが、区としてこういう方向に、オンラインによる情報請求における仕組みの整備を今後、国の判断もあるのでしょうけれども、前向きに捉えてやっていけるのか、いくのか、その辺、見解だけ。駄目なら駄目なのか、考え方だけ教えてください。","respondent":"田口戦略広報課長","answer":"電子申請の関係で、どれぐらいのめどで考えているのかでございますが、まず受付するところについては、今年度もしくは来年度辺りで考えておりますが、ですが受理の通知ですとか、あとは期限の経過通知につきましては、導入されたとしても、対応の予定は考えておりません。","id":"exchange-033"},{"speaker":"塚本副委員長","kind":"質問","question":"大体ご説明いただきまして、区の対応をお伺いしたところですけれども、この陳情理由の４番のところで、品川区における開示請求の経過通知がされなかったというところがあって、ここについては、そのこと自体を直接的に、対応とかいろいろな今後の再発防止みたいなことは他の所管の範疇ということは一応承知しているのですけれども、戦略広報課として、いわゆる情報公開請求における一連の手続の中で、こういったことは起こってはいけないことだと思うので、今後の取組というか、しっかり運用されるということに対しての手の打ち方といいますか、それをお伺いしたいと思います。","respondent":"田口戦略広報課長","answer":"こちらの期間経過時の通知がなされなかったところについて、再発防止でございますが、こちらにつきましては、今年の３月２４日に戦略広報課長名で通知を出しておりまして、情報公開・個人情報保護制度の適切な運用についてというところで庁内に周知しておりまして、原則、公開義務があるところですとか、あとはしっかりと期限を守って通知をするようにと、改めて全庁に対して周知を行いました。こちらは、今年度は係長級に対象を拡大しまして、さらにこちらの個人情報の公開につきまして知識を深めて、適切な運用に努めてまいりたいと考えております。","id":"exchange-034"},{"speaker":"澤田委員","kind":"意見","question":"本日結論を出す、不採択でお願いします。理由としましては、保有個人情報開示請求に係るオンライン申請について、利便性向上に向け現在、検討中であること、期限経過通知については、個別対応されていくということですので、不採択でお願いいたします。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-035"},{"speaker":"山本委員","kind":"質問・要望","question":"本日結論を出すで、不採択でお願いいたします。まず、本陳情が問題提起している方向性そのもの、区民の利便性向上や行政手続の透明性向上を図るべきという考え方は、私も大変重要だと思っています。まず１つ目のところの、個人情報開示請求については、区の説明により、拡大を検討しているということで、進めているということで理解いたしましたので、既に陳情者の要求は進んでいると理解いたしました。ただ、方向性としては正しい一方で、ご説明にあったとおり、個人情報の開示については注意すべき点が結構あるということで、オンライン化を進めるとしても、成り済まし防止策や誤送付防止も含め、確実な制度設計をしていっていただいて、情報漏えいしない形で、急がずに、しっかりと仕組みをつくって進めていただきたいと思いますので、これはお願いさせていただきます。２つ目のところで、受理通知のところですけれども、現状、受付通知とかがなされているところを踏まえると、その仕組みを変えるのに、それなりに大変なところもあるとすれば、そこはそこまでせずに、通知を分かりやすくすることで代用するというやり方もあるのではないかと思っております。それから、期限経過時の通知ですけれども、これまで質疑がございましたけれども、区でしっかりと管理していくべきものであって、申請者に通知するのがふさわしいとは思っておりません。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-036"},{"speaker":"塚本副委員長","kind":"意見","question":"本日結論を出すで、不採択でお願いいたします。オンラインの請求については、前向きに検討するという状況にあるということなので、それはそれを進めていただければ、本陳情についてはよろしいのではないかと思います。期限経過通知については、先ほど課長からのご答弁があったとおりで、しっかり現行手続を過つことなくしていただければと重ねてお願いすることにはしておきたいですけれども、本陳情については不採択でお願いします。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-037"},{"speaker":"松本委員","kind":"質問・要望","question":"本日結論を出すで、採択でお願いいたします。本件については、４のところで、東京地裁の判決で、区が敗訴しているところがまず前提としてあるように思います。本日の区民委員会のほうで、こちらの裁判の結果について報告がなされているようでありますけれども、そちらを拝見したとしても、区のほうの対応について問題が指摘されている、それと今回の陳情の１、２、３の大本のところが必ずしも対応するかといったら、そうではないところもあるかもしれませんが、やはり陳情の要旨のところを拝見すると、利便性と申請手続の透明性というところを陳情の要旨として挙げていただいているので、これはやはり今回の判決を踏まえ、また従前から、本件は保有個人情報のものですけれども、情報公開請求について、当区の在り方について、もう一度見直してほしいという要望は、私も各種質問で上げさせていただいておりますので、こちらについては採択という意見を述べさせていただきます。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-038"},{"speaker":"須貝委員","kind":"確認","question":"本日結論を出すことと、今回は不採択でお願いしたいと思います。本人確認や個人情報に対する対応でありますが、やはりそういうのをしっかり国の動向を見極めた上で、私は実際、進まざるを得ないかと思います。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-039"},{"speaker":"西本委員","kind":"質問・要望","question":"本日結論を出すで、採択でお願いします。これはいろいろと対策を取っているということで、検討も進んでいるという趣旨、理由に即した形に今後なっていくのかなという思いと、やはり４番目のところはいろいろと今後、考えていかなければいけない、反省しなければいけないところだと思います。なのでまだまだ品川区としては、情報公開制度に対して改善が必要だなと強く思っていますので、ぜひこれをきっかけに、オンラインという方法もありますけれども、今回は、より区民の方が請求できて、やはり区民の権利だと思いますので、さらに積み上げて、いろいろ改善すべきところを改善してもらいたいということで、要望させていただきます。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-040"},{"speaker":"西本委員","kind":"質問","question":"これは受託という形ですけれども、令和８年度債務負担行為ということで、財政的なやり取りで、要は債務負担行為をして、それが委託という形になっていますから、お金は入ってくるのですよね。これは、期間も含めてどういう形のやり取りになるのですか。これは工期が令和９年２月４日という形になっているのですけれども、そのお金のやり取りがどういう形でやり取りされるのか。北品川二丁目と三丁目の同じ工事の内容だと思うのですけれども、これを別々にして契約を結ぶのはなぜなのか教えてください。","respondent":"加島財政課長、廣瀬経理課長","answer":"私のほうからは、最初のご質問の、お金のやり取りで、こちらに限らず一般的なというところになりますけれども、今回は７年度で支出科目を持っておりますので、まず７年度に必要な工事を７年度予算で組ませていただいております。ただ、工事が単年度で終わらないものにつきましては、８年度以降、債務負担行為を組ませていただいております。８年度の予算につきましては、債務負担行為を組んだものから８年度に支出するものを現予算として取り扱わせていただいているものになります。基本的に、こちらは東京都からの受託事業ですので、１０分の１０、お金が入ってくるものでございます。河川下水道課から聞いている限りでお答えいたします。一括で発注した場合、大規模かつ短工期の工事となり、不調リスクが高いことから、より確実に再構築工事を進展させるため、複数の工事で発注したと聞いております。","id":"exchange-041"},{"speaker":"西本委員","kind":"確認","question":"不調になるおそれがあるからということですけれども、該当する事業者がいればいいのでしょうけれども、まとめてやったほうが、能力もあるか、ないかというのはあると思うのですけれども、金額的に安くなるとかはないのですか。別々にやっていくと、それだけ負担がかかるというか、まとめてやるから安く上がるとかと考えがちなのですけれども、あえてばらばらになるのは、そういう不調とかというおそれがあるからということになるのですか。もう一度確認をさせていただきます。","respondent":"廣瀬経理課長","answer":"繰り返しのお答えなりますけれども、河川下水道課から聞いている限りでは、一括で発注してしまうと、大規模かつ短工期になってしまうので不調リスクが高いということで、複数の工事で発注したと伺っております。","id":"exchange-042"},{"speaker":"西本委員","kind":"質問","question":"今後、こういう工事は結構大きな金額が動くと思うのですけれども、そういう場合、不調を回避するためには、切り売りではないですけれども、分割して発注するという手法はこれからも起きてくる可能性はあるということですか。それによって、今いろいろ問題に違っていますけれども、不調の問題がありますけれども、それが解決されるという考え方になってくるのか、これからのこういう高額になってきた場合とか、法律とか、同じようなものでも、やはり分割してやる方向になっていくのか、そこはどうですか。","respondent":"廣瀬経理課長","answer":"規模や工期ですとかそういったところで、ケース・バイ・ケースにはなってくるものかとは思われますが、基本的には所管課のほうでご判断いただくものかと思います。","id":"exchange-043"},{"speaker":"須貝委員","kind":"意見","question":"北品川三丁目付近再構築その４工事ですが、報告事項なので、これで決まっているからいいのですけれども、これを総務委員会に出されると、入札金額が、落札したのは１億３,２００万円で、次点の１億３,２１１万円と１１万円の差なのです。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-044"}]},{"id":"topic-04","title":"（３）「品川区ジェンダー平等と性の多様性を尊重し合う社会を実現するための計画」の策定","agenda":"（３）「品川区ジェンダー平等と性の多様性を尊重し合う社会を実現するための計画」の策定","exchanges":[{"speaker":"西本委員","kind":"質問","question":"もう印刷してしまっているのですよね。すみません、細かいところで、次回ということで、概要の６ページとかで、「重点」と「ＮＥＷ」がオレンジ色で同じですよね。それで注釈のところも、６ページの下のところに重点取組という、ＮＥＷも書いてあるのだけれども、これは色が違ったほうがよかった、そのほうが分かりやすいかなと感じました。たくさんいただいた何かきっかけとか、どう評価されているかということと、やはりこれからですよねというご意見が多いかと思うのですけれども、あとこれの期待も結構あるのではないかと思うのですけれども、それについては、ただ単にホームページのほうで、こういうのがありますよと、それで周知できましたみたいなのだけだと、なかなかもったいないなという気持ちもあるので、何か周知するための工夫とか、こういうイベントをやるとか、そういう計画はあるのでしょうか。","respondent":"木村人権・ジェンダー平等推進課長","answer":"今回、確かに５５人の方からご意見をいただきまして、お１人様で複数の意見があるので、９６件という結果になっております。こちらにつきましては、パブリックコメント自体の周知も、ＳＮＳ想定を活用した形でも行いましたし、あとちょうどこの頃、ジェンダー平等推進講座があったりしましたので、そちらでもお知らせをさせていただいております。またその前に、地域の方々に対して説明をする機会をいただければ、まちに出て説明をさせていただいておりましたので、そういった形で周知が進められて、パブリックコメントについてもご意見をいただけたのではないかと推測しているところではございます。また、今後、計画の周知の工夫ということだと思いますが、こちらに関しても、今年、もう少したったら、まちの会議体ですとかそういったものにお邪魔させていただいて、少し短いお時間をいただいて、まとめた形で計画の内容を周知させていただきながら、取組についてお伝えしていければと思いますし、そこでまたジェンダー平等推進講座ですとか、フォーラムですとか、各課の取組について併せてお知らせをさせていただければいいかなと考えております。","id":"exchange-045"},{"speaker":"西本委員","kind":"質問・要望","question":"やはり関心度が高いのかなと思います。なので、いろいろなところでのアプローチを今後もどんどんしていただきたいなと思っています。文章では割と分かりやすいのだけれども、具体的な行動としてどう取っていくのかがなかなかリンクできない部分があるかと思うので、そこも含めて、今後いろいろなイベントとか機会があったら、ご説明もしくはそういう分かっていただくためのイベントなどをしていただきたいなと要望したいと思います。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-046"}]}],"links":[{"type":"minutes","label":"公式の会議録を読む","url":"https://kaigiroku.city.shinagawa.tokyo.jp/index.php/237549?Template=document&Id=7367#one"},{"type":"official","label":"公式の会議録一覧","url":"https://kaigiroku.city.shinagawa.tokyo.jp/index.php/100000?QueryType=new&Template=list&Cabinet=5&TermStart=2026-01-01&TermEnd=2026-12-31"}],"sourceMeta":{"pages":0,"characters":31185,"voices":149}},{"id":"r08-20260415-21","meetingId":"r08-m0405","date":"2026年4月15日","dateIso":"2026-04-15","committee":"子ども若者支援・共生社会推進特別委員会","time":"午後 １時００分～午後 １時２０分","status":"正式会議録","sourceType":"formal","overview":"子ども若者支援・共生社会推進特別委員会の会議録から、実質的な質問・確認・意見・要望と答弁・対応を7件整理しています。","topics":[{"id":"topic-01","title":"特定事件調査の、特定事件調査のまとめ","agenda":"特定事件調査の、特定事件調査のまとめ","exchanges":[{"speaker":"鈴木委員","kind":"提案","question":"もっと前に意見を出さなければいけなかったと思っていますけれども、新たに付け加えることが可能かどうかというところなのですが、私ははっきりと委員会の中で、こうしてくださいとまでは言っていないのですけれども、そういう趣旨で意見を言ったところで、特別支援保育についてなのですが、「保育園・幼稚園における特別支援保育の研修のさらなる充実を図られたい」と入れていただけないかと思ったのです。委員長からもいろいろと提言のご提案とかもいただいて、改めて読み直してみたりして、区立保育園では支援チームができていて、ベーシックの研修は９割の保育士が受けていて、園長先生から、それから様々チームのリーダーの方とか、５段階の研修があって、いろいろと研修を受けているということがあったので、私は、５歳児健診とかで初めてそのように指摘されたときに、その子どもの親にとってはすごく衝撃で、そういうところをフォローしてくれるとか、その子どもに対しての見方をしっかりとしてもらえるのは、研修とかで発達障害とか、障害の子どもたちのことを受け止めるものがあるのがすごく必要だと意見も言ってきたところなのですけれども、区立のほうはそこまで言っていたのですが、私立のほうはご答弁の中で、区の研修の中で私立の人も参加できるようになっているので、参加しているのではないかと思いますと、そんな形で私立の保育園の研修とかが、はっきりと区立のようなベーシックサービスがどこまでできているかを把握している状態ではなかったのです。区立にしても、ベーシックの研修を受けているとはいえ、さらにその研修を進めていくことですとか、私立のほうも、しっかりとそういう研修を進めていくことが必要ではないかと改めて思いましたので、保育園・幼稚園における特別支援保育の研修のさらなる充実を図られたいという文言が入れられたらいいなと思いましたので、ご意見を伺えたらと思いました。","respondent":"せお委員長","answer":"ありがとうございます。議事録等も確認していきたいと思いますし、あと、今の鈴木委員のご意見について、何かほかの委員の方でご意見あったりしますでしょうか。追加することに関して。最後、正副で調整したいとは思うのですが、ご意見はよろしいですか。","id":"exchange-001"},{"speaker":"鈴木委員","kind":"意見","question":"９月２５日のところで議論しているのですけれども、私立保育園に対してはどのようになっていますかということに対して、区で実施している研修にも私立保育園の職員も参加していただくことができますので、そのような研修を受けて、特別な支援が必要なお子様に対応されていると考えておりますという答弁でした。","respondent":"せお委員長","answer":"ありがとうございます。ほかになければ、今いただいたご意見を基に、正副委員長で再度調整させていただきまして、次回の委員会で改めて案文をご提示しまして、決定してまいりたいと思いますが、よろしいでしょうか。","id":"exchange-002"},{"speaker":"鈴木委員","kind":"質問・要望","question":"これも本当はもっと前に出せばよかったのですけれども、今になって申し訳ないのですが、ご検討いただけたらありがたいと思って、１番のところで、学校および教職員のヤングケアラーへの理解を深めるために、研修を通じて必要な知見の習得に努められたいと書かれているので、これはすごく大事なことだと思ったのですけれども、「ヤングケアラーを支援するために必要だと思うことはどのようなことですか」というのが、学校アンケートの中で取られたところで、教職員がヤングケアラーについて知ることというのはここに書かれているので、それでいいと思うのですけれども、それと、子ども自身がヤングケアラーについて知ること、保護者がヤングケアラーについて知ること、それから、子どもが教職員に相談しやすい環境をつくることというのが出されていたのですが、教職員のところはこういう形で出ているので、いいと思うのですけれども、子どもや保護者への啓発についての取組も充実させていただきたいということも入れていただいたらいいかなと思ったのですが、ご検討いただけたらありがたいところです。","respondent":"せお委員長","answer":"（１）の記述に付け加える形で考えていますか。","id":"exchange-003"},{"speaker":"澤田委員","kind":"質問","question":"啓発の取組については、既にやっていなかったですか。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-004"},{"speaker":"鈴木委員","kind":"質問・要望","question":"これについても様々取組はされている。少しずつされている部分はあるのですけれども、それをさらに進めていただきたいというところです。例えば小学校６年生が対象で、台場小学校と芳水小学校で、出前で寸劇をやったりとか、そのようなところでやっているのですけれども、まだ全ての学校でやっている状況にはなっていないし、そういう点ではまだ始まったばかりという感じなので、それをさらに進めていただきたいという感じです。まだ２校だけなので。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-005"},{"speaker":"鈴木委員","kind":"質問・要望","question":"そうですね。啓発についても取組を強化していただきたいという感じです。","respondent":"せお委員長","answer":"理解いたしました。こちらも先ほどと同様、今いただいたご意見を基に、正副委員長で再度調整させていただきまして、次回の委員会で改めて案文をご提示しまして、決定してまいりたいと思います。ありがとうございます。──────────────────────────────────────────── 3)重層的支援体制に関すること","id":"exchange-006"},{"speaker":"鈴木委員","kind":"質問・要望","question":"重層的支援体制は、本当だったらもっと充実をこれからしていっていただきたいところなのですけれども、区としてもすごく複雑な仕組みになっていまして、地域包括支援センターを来年度地域に設置していくということで、今年検討されるところですし、重層的支援体制をどのように充実、拡充していくのかというのは、今まさに庁内でも検討されている段階なので、こちらからこのようなことをしてくださいというのは、すごく難しい部分があるなという思いがしていまして、私は総合相談窓口をつくっていただきたいという思いはありますけれども、そのようなところも委員会の中で、まだ一致してみんなで求めていこうというところにまでなっているわけではありませんので、本来であれば、もっと１項目だけではなくて出したいところですけれども、今の時点ではこれでいいかなと思っています。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-007"}]}],"links":[{"type":"minutes","label":"公式の会議録を読む","url":"https://kaigiroku.city.shinagawa.tokyo.jp/index.php/256558?Template=document&Id=7369#one"},{"type":"official","label":"公式の会議録一覧","url":"https://kaigiroku.city.shinagawa.tokyo.jp/index.php/100000?QueryType=new&Template=list&Cabinet=21&TermStart=2026-01-01&TermEnd=2026-12-31"}],"sourceMeta":{"pages":0,"characters":5025,"voices":32}},{"id":"r08-20260415-20","meetingId":"r08-m0405","date":"2026年4月15日","dateIso":"2026-04-15","committee":"ＳＤＧｓ推進・行財政改革特別委員会","time":"午後 １時００分～午後 ２時２２分","status":"正式会議録","sourceType":"formal","overview":"ＳＤＧｓ推進・行財政改革特別委員会の会議録から、実質的な質問・確認・意見・要望と答弁・対応を24件整理しています。","topics":[{"id":"topic-01","title":"報告事項を聴取いたします。 中高生リバースメンター事業","agenda":"報告事項を聴取いたします。 中高生リバースメンター事業","exchanges":[{"speaker":"あくつ委員","kind":"提案","question":"課長も替わられたということなのですけれども、私も資料を拝見しました。例えば１番目の投票率の向上については、なかなか公正を保つというところの難しさから、模擬投票は難しいのではないでしょうかといった質疑をさせていただいたことをよく覚えています。それで、まず１番目にお伺いしたいのは、今報告を受けましたけれども、事業内容について、これは予算書のどこに載っているのか。２月に区長に事業化検討結果の報告があったと思います。例えば最初の、今回、公開討論会をご提言、ご提案され、事業化されたと書いてありますけれども、これは予算書のどこに載っているのか、まず教えてください。","respondent":"石川ＳＤＧｓ推進担当課長","answer":"こちらは、予算書にリバースメンター事業という形で記載はされてございませんが、各所管課において、予算審議の際に、こちらのリバースメンターの提案を受けてという形でご説明をさせていただいていると考えてございます。","id":"exchange-001"},{"speaker":"あくつ委員","kind":"質問","question":"そうすると、予算審議のときに説明をしたということですか。予算特別委員会の中で説明を受けたということでしょうか。","respondent":"石川ＳＤＧｓ推進担当課長、久保田企画経営部長","answer":"予算特別委員会の中でというよりは、各所管課がそれぞれ各委員会の中で、予算化の内容につきましてご説明をさせていただいているものと考えております。私からお答えさせていただきます。今回、政策提言を受けまして、その趣旨を踏まえた形で、それぞれの所管課の中で新規に予算計上したものもありますけれども、それぞれの予算、これまでやってきた既存予算の中で工夫して、その趣旨を踏まえたものを取り入れる形で事業化をしておりますので、特にこれについて我々から議会に説明したということはございません。我々が既存の事業の中で、こうした提言を受けてやっていったものもありますし、新規で行ったものもありますので、その辺りについては、明確に議会にはご説明はしていないということでございます。","id":"exchange-002"},{"speaker":"あくつ委員","kind":"提案","question":"明確なご答弁をありがとうございます。ということは、今回初めてこのＳＤＧｓ推進・行財政改革特別委員会の中で、どういったものを事業化したのか説明を受けたという確認をしたかったので、それがまず１つ目です。それで、その点に関して言えば、今年２月２７日に、事業化検討結果の報告会というものが行われている。であるならば、子どもたちに報告をすることもとても大事なのですけれども、議会に対してこういうものが決まったということは、予算審議の場で必要なことだと思うので、これはぜひ予算審議の前に、こういったものは事業化案として、私が見た書類の中には、どこかにまぶしてあったのかもしれません、全ての１０項目があったのかもしれませんけれども、私は申し訳ないですが、そこは確認できなかったので、審議のしようがなかったというのが私の個人的な感想です。その上でのこれからの質問になりますけれども、今回の１番目の、模擬投票は今回は行わないことは確認したのですが、まず主権者教育のパンフレットの制作、これは議会運営委員会等で報告は受けていますが、品川区役所側と首長サイドと何かやったという報告はなかったので、連動してやったのだろうと推測はできます。ここについて、議会とどういう形で調整をしたのか、ご説明いただきたいのが１点。それと、２番目のしながわシティラボを通じた課題発信で、提案企業・団体を募集して、令和８年度に実施される選挙の立候補者による公開討論会を実施するという事業が計画されていますけれども、これも先ほど確認したとおり、初めて聞きました。確認したいのは、主権者教育という名の下に、令和８年度、私が知る限りは区長選だと思うのですけれども、公開討論会を区が関与して行うことに疑義はないのか。シティラボを通じて行った場合、応募してきた企業とか団体に、品川区としては予算をつけるのですか。けれども、選挙というものに関しては、厳正であるべきだし、公平であるべきだし、公正であるべきだと強く思っていて、みんなフラットな状況で戦わなければ、これは区長選に限らず。所管部署に投げて予算化をしたということですが、これはどういう議論があったのか確認させてください。","respondent":"久保田企画経営部長","answer":"まず、１点目の議会との関係でございますけれども、これは区議会事務局から令和８年度予算の要求があって、それに基づいて我々は設計をしているところでございます。ただ、今お話をお伺いしていますと、議会側にまだご説明がないということも委員がおっしゃっていましたので、我々としては少し詰めが甘かった、配慮が足りなかったと、この点については反省をしてございます。２点目の子どもの討論会についても、これは直接区がやるわけではございませんので、こういったものをシティラボを通じて提案させていただいて、こういうことに賛同してやってみようという団体がいたら、そういう団体にやっていただくので、我々としてこれに予算をつけることは、今想定はしていませんので、イメージとしては、例えば各選挙で青年会議所等が討論会などをやられていますけれども、そういう中で、この政策提言をいただいた内容の趣旨を踏まえて、例えば子どもの質問の機会を少し設けてみるとか、もしそういうのがあれば、そこはご相談、やり方は今、私は例示で言いましたが、そうでなければいけないことではありませんけれども、そういった趣旨を踏まえてやってみようということがあれば、それはご提案をいただいて、我々が少し話をして、やってみるのはありかと思っているところでございます。それで、これに至るまでの経過ですけれども、選挙管理委員会などとは十分詰めて話をしてきておりまして、昨年もあくつ委員からの非常に機微な内容だから十分配慮するようにということを踏まえまして、選挙管理委員会と十分に打合せをした上で、公職選挙法に違反しない範囲の中で、この政策提言の趣旨を踏まえてできないかと検討した結果、こういう形で、今回のシティラボについては事業化ではございませんけれども、こういう手法を取らせていただいたところでございます。","id":"exchange-003"},{"speaker":"あくつ委員","kind":"提案","question":"今の内容から私は読み取れていなかったのですが、公開討論会は子ども向けということですか。先ほど例えば子どもの質問ができる場を設けるという話がありましたが、今、４年ごとの区長選挙等では、経験された方もこの中にいますけれども、公開討論会は夜、たしかオンラインでやりましたよね。そういうものを想定するのか、子どもが参加しやすい形での公開討論会を、今のお話だと例示で、別にそうでなければいけないことではないとありましたけれども、子ども向けのというニュアンスでのご提案、事業化ということでよろしいのでしょうか。","respondent":"久保田企画経営部長","answer":"少し私が先走って例示をしてしまいましたけれども、リバースメンターの方たちからこどもせんきょ、また討論会等の提案もありましたので、こういった趣旨を踏まえた、子どもたちにも選挙とかを身近に感じていただけるような取組ができる提案があれば、それについてはやっていただければということでございますので、例えば夜に子どもが参加しなければいけないとか、そういうことを縛っているわけではございません。それと、法律等に違反しない形で、きちんとそれが大丈夫なのか、あくつ委員からの指摘も踏まえて、きちんと捉えてやっていきたいと考えています。","id":"exchange-004"},{"speaker":"あくつ委員","kind":"提案","question":"私は提案、応募してきた企業なり団体なりに、品川区からもし何かの助成金なり補助金が出るのであれば、申し訳ないけれども、これはかなり厳しい話だと思いました。区主催でないにしても、民間を通して区がもし出資をするということであるならば、それはどうしても関わってくる話。先ほど公職選挙法等の法令に違反しないというお話がありましたけれども、法令に違反しない形でも、どうしても特定の候補に有利になることがあるのです。それと、十分に配慮していただいた上で、特定の候補に何か有利に働くようなことが絶対にないように、今回は予算の審議では、これは審議できなかったので、そこについて既に事業化されているということですから、ここについては今から撤回、子どもには報告があって我々には報告がないということで、これは日にちが２月２７日でしたか、ここについては報告しようと思えばできたはずなのです。そこについては、この場で言ってももう事業化されているわけですから、丸ごとリバースメンター事業を含んだ予算に賛成しましたよねと言われることになってしまうので、そこは議会人として、それは違うでしょうと私は思うので、子どもたちへの報告が先なのか、我々への報告が先なのか、そこはお任せしますけれども、筋で言えば、事業化をした、事業化案を入れたのであれば、我々にもきちんと報告をしていただきたいと言わざるを得ないことだけはご理解いただければと思います。あと最後に、１０番目の子ども食堂のところです。ここは相当配慮した表現になっていて、１０種類全部見ましたけれども、かなり濃淡があって、事業化の踏み込み方の濃淡もあって、この１０番目も、かなり運営者の方に配慮した、まさに所管課がいろいろ考えていただいた跡がすごくよく見えるのですが、私の感覚でいうと、第三の居場所ということ自体でも、恐らく反発する人たちも出るのだろうなと、正直、危惧を抱いていますが、ぎりぎりという感じはあります。そういったことも含めて、まず、最初の話に戻りますけれども、議会への報告をぜひお願いしたいと思います。","respondent":"久保田企画経営部長","answer":"議会への報告につきましては、我々も、どのタイミングでこれを報告しようか正直言って悩んだところはございます。昨年の９月に区長へのプレゼンテーションが終わった後に、議会に一旦報告をさせていただきまして、その後、予算化をしていく中で、これは我々の言い訳になるかもしれませんけれども、例えば２月に中高生リバースメンター事業を個別に報告したとなると、予算の事前審議になるのではないかとか、そういったことも少し配慮がありまして、予算特別委員会の中でご審議いただこうと、今回は議会への事前の報告を行わなかったというところでございます。ですが、今いただいたご意見もございますので、今年度につきましては何か工夫をして、議会の事前審査など、そういったものもいろいろ配慮して、どういった形で議会にもきちんと報告ができるかは、我々も検討して対応していきたいと思ってございます。","id":"exchange-005"},{"speaker":"あくつ委員","kind":"質問・要望","question":"事前審査になるのであれば、例えば予算のプレス発表が終わった後であるとか、我々が予算審議の前にそれができるような形で、ぜひお願いしたいと思います。先ほどご答弁もいただきましたけれども、そこはすごく難しい、子どもの思いを潰したくないのもよく分かりますし、そこでいろいろ物言いがつくことがどのように反映するかもあると思うのですけれども、２月に子どもたちには伝えている。そこは十分にご配慮いただきたいと申し上げざるを得ないということでご理解いただければと思います。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-006"},{"speaker":"安藤委員","kind":"提案","question":"中高生リバースメンター事業ですが、実際に子どもたちの意見を聴いて、聴くだけではなくて政策化まで持っていって、社会は自分たちの行動で変えられるという実感を持ってもらう事業なので、大変意義がある事業だと改めて思いました。今後も継続して実施して、品川区は子どもの意見を聴いて政策をつくっている自治体だと、当事者の子どもたちにも、区民にも広く評価、認知されるところまで続けていただきたいという思いはあります。選挙の関係は本当に難しい、今のやり取りを聞いていて思ったのですけれども、難しいと思うのですが、子どもたち自身が政治にいかに関心を持ってもらえるような社会をつくるかという点で、問題意識を持って提案をするのは非常にすばらしいことだと思うので、もちろん法律との兼ね合いは最重要になりますけれども、ぜひそういった思いも活かせるような、重視するような、そういうぎりぎりのところがあると思うのですけれども、考えていただきたいと思います。それで、質問ですけれども、（２）拡充内容についてお伺いしたいのですが、昨年度１年間行ってきた経験を踏まえた上で、今回検討会を６回に増やすということですけれども、もう少しその理由を伺いたいと思います。それと、区内企業から事業化のプロセスを学ぶ機会を設けるとありますが、具体的には、いつどのように行うのかを伺いたいです。これについては、なぜ拡充しようと思ったのかという点もお伺いします。","respondent":"石川ＳＤＧｓ推進担当課長","answer":"まず１点目の、今年度の検討会の拡充理由についてお答えいたします。昨年度の課題といたしまして、事業化に当たりまして、所管課との連携がかなり難しかったとの実感がございました。いかにリバースメンターからの提言内容の実現に向け、所管課を巻き込んでいけるかが重要であると考えてございます。その対応といたしまして、所管課を交えた検討機会を充実させる必要があるということで、検討会の回数を６回に増加させていただきました。所管課の検討会への参画につきましても、昨年度より早い段階、１回目から参加してもらうような形で、最初はアイスブレイクという形で関係構築から入っていただく考えでございます。もう１点の、民間企業を参画させる理由といたしましては、昨年度は、区でいかに事業実現ができるかという趣旨で、区の財政課ですとか各所管課といった区のメンバーでフォローしていたところがありまして、そこは民間企業の知見も活用して、区でできない部分もありますし、民間でできる部分もあるので、リバースメンターの方々があまり視野が狭くならないように、民間の考え方も取り入れる必要がありまして、今回、民間の方々も検討会に参画してもらう形で考えてございます。具体的には、検討会の２回目に民間企業の事業化プロセスを学ぶ予定でございます。","id":"exchange-007"},{"speaker":"安藤委員","kind":"質問","question":"所管課には、この事業はすごく手厚い事業、様々な苦労もあると思うのです。ただ、様々な気づきもあると思っていまして、先ほど所管課との連携が難しかったという話もありましたけれども、この間１年間やってきたわけですが、子どもの声を聴いて、伴走しながら政策化に至るまでの過程で、担当としての気づきとかメリットはどのように感じたのか、現場からは率直にどういう意見が出ているのか、もし分かれば伺いたいというのが一つです。それと、これは非常に周知が重要だと思うのですけれども、結果的には１０人の枠しかないので、区内の中高生の全ての方には、こういう事業をやっているのだと知ってもらいたいと思うのですけれども、先ほどチラシ配布という話もありましたが、どういう配布の仕方をするのか、できれば一言添えて担任の方が全員に配付をすると同時に、こういう事業があるのですよという感じで、そういった形が一番丁寧で望ましいと思っているのですけれども、チラシの配布の仕方について伺います。","respondent":"石川ＳＤＧｓ推進担当課長","answer":"まず１点目の質問で、所管課、現場の感覚でございますが、実際かなりＳＤＧｓに理解を示していただいて、中高生リバースメンター事業に対して理解を示していただいている所管課につきましては、かなりリバースメンターの方とも直接連絡を取って、前向きに事業化に向けて検討していただいてございます。なので、そちらにつきましては、今後は提言の内容、提言を考える部分から、所管課との連携を密に取りながら、リバースメンターにとってすばらしい内容が報告できるように、提言内容が作成できるように、こちらはフォローをしていきたいと考えております。もう１点の、今年度のチラシの配布方法でございますが、区内公立の中高生につきましては、１人１枚チラシを配付してございます。私立の中学校・高校につきましては、私どもが直接訪問してチラシ配布をお願いする予定でございます。","id":"exchange-008"},{"speaker":"安藤委員","kind":"質問・要望","question":"これから２年間かけて、子どもの権利条例も定めていくわけですけれども、こういう事業自体がある意味、その体現、子どもたちは、自分たち子どもの声を聴いてくれる、それを聞きっ放しにするだけではなくて、一緒に社会を進めようとしてくれているということ自体が、非常に重要なメッセージになると思うので、かなりきめ細かくチラシ配布みたいな話もあったと思うので、ぜひその辺りについては丁寧にやっていただければと思います。そういった意味では、かなり質的にこれまでの事業とは違う意味を持つ大事な事業だと思うのですけれども、現場の負担には目を配らせながら、ぜひ相互に学びが多い事業にしていただければと要望させていただきます。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-009"},{"speaker":"新妻委員","kind":"質問・要望","question":"昨年から始まって、私も大崎の品川産業支援交流施設ＳＨＩＰでのプレゼンテーションも拝見させていただきました。自分の子ども時代から比べると本当に立派だと思いながら、それが区の事業となっていくことについては、子どもたちの意識が本当に高まってくるだろうと受け止めておりますが、先ほどあくつ委員からもありましたけれども、確認を１点させていただきます。まず、今回選ばれた１０テーマの中での１番目につきましては、私もそのときの説明を受けた時点で、どういうところができるのか心配な項目もありました。今回、事業化するに当たりまして、このような公開討論会等が他の自治体でされている事例があるのか、また、参考にした事例があるのか、もしあれば、そこを教えていただきたいと思います。以前、この委員会の中でも確認をさせていただいたのですけれども、当初、リバースメンターの募集に当たっては、６００字程度の作文の審査が第一段階であり、作文の内容が、イコール出してきた生徒の問題・課題点であるので、そこが当日のプレゼンテーションにつながっていく流れだと確認をさせていただきまして、その検討会を経て、テーマを少し絞っていったり、少し角度を変えたりということがあるとは伺っていますけれども、そもそも、まず応募があります。この選定をする中で、そこで第一弾、全員ではないので、課の中で検討されて、ふるいにかけられると思うのですが、その段階でのテーマ決めですとか、その辺りの視点は、要は区の事業として、これはできるかという視点も持ちながら、応募の中から選ばれていく基準、その辺りを教えていただきたいと思います。もう１点、少し前後します。なので、今回チラシを全ての公立の中高には配られているということですが、チラシの配付だけではなくて、もう一歩その辺りの工夫ですとか、区立の中学生が参加できるように当たっての工夫が何かされているのか、そこを教えていただきたいと思います。","respondent":"石川ＳＤＧｓ推進担当課長","answer":"まず１点目の、この事業関連の他自治体の事例でございますが、こども選挙につきましては、自治体や議会が主導して実施した事例はございません。近年、民間の実行委員会、全国こども選挙実行委員会が主体となって、こども選挙を実施する事例は増えてきてございます。ただ、あくまで民間団体による実施事例のみでございます。公開討論会の事例といたしましては、自治体が主体となって公開討論会を実施しているのは１つありまして、愛知県の新城市で行ってございます。こちらにつきましては、青年会議所が解散となった状態でして、公開討論会ができない状態になって市長選を迎える中で、住民が参画する会議体の中で、討論会の開催をまず条例化いたしまして、実施をする。今年も行いません。中学１年生から高校３年生までと年齢がかなり幅広いので、文章能力だけで見てしまうと、どうしても高校生が高い点数になってしまうこともありますので、あくまで作文の形式よりは、中身、熱意を重点的に配点するような形で考えてございます。配布先といたしまして、先ほど申し上げましたが、中学生ですとか高校生で、区立のお子様が行くであろう施設、図書館ですとか児童センターについては、今年は配架を考えておりまして、作文の採点の中で、区立学校だから重きを置くのはなかなか公平性の面から難しいとは思っておりますが、こちらは校長会でも案内をさせていただきまして、１人、既に区立学校から問合せ等も入ってございますので、今年度期待をしております。","id":"exchange-010"},{"speaker":"新妻委員","kind":"質問・要望","question":"そうしますと、まず他自治体の事例ですが、愛知県の新城市が条例化をして、しっかりと公平性が保たれるようにやっているとありましたので、品川区はここを参考にしてやるのですか。条例化した内容についての公平か、公正かについては、品川区でもここはしっかりと必要だと思いますので、そういう意味では、公開討論会を行うに当たっての、しっかりとこういう意味でやります、また、この辺りの視点は注意しなければいけないことを明確にして、当然やっていただくと思いますけれども、ここの条例化になっているところは参考にされているところがあるのか、もう１点確認したいと思います。前回は１名しか応募がなかったので、１名の応募の方が残念ながら選ばれなかったという流れになりましたけれども、そもそもたくさんの方がいろいろな課題感を持って応募していただくことが大事だと思いますので、校長会等でも働きかけをしていただきながら、たくさんの方が応募して選ばれるように、またお願いしたいと思います。検討会の中でつくり上げていくところもあったと思いますので、今回は４回から６回に増えるということでありました。所管課とも連携をするということなので、昨年度よりも今年度のほうが事業化しやすくなるようになっていくと思われますが、今回１０名で、全員の方が事業化になったのですよね。多分これは、子どもたちの意見はしっかりと受け止めていきたいという思いもあってのことだと思うのですけれども、また、検討会の中で事業化にできるような流れをつくっていく視点もあると思うのですが、その辺りは基本、子どもたちの意見は、全員の意見をしっかりと受け止めていくことが前提としてあるのか、その辺りをもう一回確認させていただきたいと思います。","respondent":"石川ＳＤＧｓ推進担当課長","answer":"まず１点目の、もし公開討論会を実施した場合の留意点で、おっしゃるとおり、新城市の条例内容、規定内容は当然、私どもも留意しなければいけない内容と思っておりますので、他自治体の事例がここしかないというのもありますので、当然ここの内容を参考にしながら、ただ、公職選挙法に抵触しないように最大限考慮が必要と思っておりますので、参考としつつ、丁寧にこちらは進めてまいりたいと考えております。もう１点、事業化に当たって、事業化前提ではないかですが、私どもといたしましては、リバースメンター事業は提言するというところが、１つそこで区切りと思っています。その後は提言を受けて、事業化していくのは区側の責任と考えておりますので、事業化前提で検討会がふるい落とすような、アイデアをそいでいくようなことはございませんので、そこは明言をさせていただければと思います。事業自体が、常識にとらわれないお子様が日頃から、ふとした疑問でいいと思うのですが、区の職員では考えられない課題認識、課題提示を期待するところではございますので、私どもといたしましても、子どもたちの考え方、課題については、むげにすることなく丁寧に進めてまいりたいと考えております。","id":"exchange-011"},{"speaker":"山本委員","kind":"確認","question":"本事業は、中高生自身が地域課題や社会課題への問題意識を深め、政策提言を行い、その内容を事業化にもつなげていく取組であって、次世代の担い手育成と、子どもたちとともに区政を創っていくという点で、私も大変意義のある事業であると受け止めております。その中で、今までも様々な動きもありましたけれども、私からお聞きしたいのは、事業化検討結果の報告会を聞いた、まさにリバースメンターの皆さんのご感想です。自分たちが提言したものが区政でどう取り上げられたかを聞いたときの感想などはいかがでしたでしょうか。アンケートとかで確認されているのか、何かインタビューしているのか、その辺りをお聞かせください。","respondent":"石川ＳＤＧｓ推進担当課長","answer":"２月２７日の報告会の様子ですが、リバースメンターの方は、一緒に検討を１０人でやってきたというところもありまして、事業化の報告についてもとても喜んでいただきましたし、あとはお互いに横の連携ができたのもありまして、卒業式のような形で、とても穏やかな雰囲気の中で、提言者の方も、自分の考えが事業化されてうれしいと、あとは区側も、提言していただいた内容の事業化を報告できた喜びで、とても幸せな時間になりました。リバースメンターの方々につきましては、自分の提言内容が区に事業化をされて、社会を少しでも変えることができたということで、ご満足いただけたと考えております。","id":"exchange-012"},{"speaker":"山本委員","kind":"質問・要望","question":"参加したリバースメンターの皆さんがとても満足していた様子がお聞きできて、本当によかったと思っています。最後の感想をもし書いてもらっておけば、それがまた次の参加者に、参加した人たちがこんな感想を持って、よかったみたいなことで、募集をかけるときのいい材料にもなると思いますので、今回まだ、少し時間が過ぎていますけれども、それをお願いすることもできるかもしれませんので、改めて、そういう感想を残しておくのもできたらいいと思いましたので、ご検討いただきたいと思います。それからもう少し、横のつながりができたのもとてもすばらしいことだと思っておりまして、私たちの会派で、先ほども出ました新城市の若者議会を視察に行ったのですけれども、これも１０年ぐらいやっている中で、横のつながりがさらに縦に伸びていって、ＯＢ会みたいなのができて、そういうまとまりの中で、主権者教育がさらに深まっていったところもございますので、ぜひ横のつながりを行政としてもサポートする、そしてそれを今年度、来年度とつながっていくように、横と縦が両方つながっていくような取組をご要望いたします。それから、これまでの質疑にもあったのですけれども、子どもたちならではの発想を区政の実現に活かしていただくことが、今後お願いしたいところでもあるので、所管課の連携を考えていただいているように、４回を６回にすることでぜひ深めて質を高めるようお取り組みいただきたいと思っております。あとは、リバースメンターの提言が１０件で、それぞれすばらしいと思うのですけれども、最終的にリバースメンターとして携われた方は１０人になるので、その１０人のすばらしい経験を、ぜひより多くの区内中学生の人に知ってもらうことが、ほかの委員の方も言われていましたけれども、とても大事だと思うので、周知をぜひしていただきたいと思っております。これは、周知と今年度の募集とは、とてもリンクするものだと思いますので、先ほど申し上げた参加者の感想もうまく使いながら知っていただき、そして同時に、今年度の募集に出し、進めていただきたいと思っております。","respondent":"石川ＳＤＧｓ推進担当課長","answer":"先ほどの先輩とのつながりというところですが、今年度の検討会につきましても、先輩リバースメンターとして検討会の１回目にご登壇いただいて、体験談とかをご披露いただく想定で考えております。あとは、他の子どもたちへの周知ですが、昨年度実施した検討会の様子ですとか報告会の様子は、動画を作成しておりまして、こちらにつきましては区のホームページで公開してございます。","id":"exchange-013"},{"speaker":"山本委員","kind":"質問・要望","question":"映像を使って伝えるのは、すごくすばらしいと思います。あとは、新妻委員からもありましたけれども、区内中学生の応募を促す工夫で、私も以前の委員会で申し上げたので、区立学校に通う皆さんにもぜひ多く参加していただけるように工夫して、学校での周知等も進めていただきたいと私からも改めて要望させていただきます。ぜひ参加した中学生が、自分たちの声が区政に活かされたと実感できる事業として、さらに発展させていただきたいという思いでございます。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-014"},{"speaker":"筒井委員","kind":"確認","question":"先ほどから人数の話も出ていますけれども、応募は１６人でしたか、その確認と、採用された１０人のうち１名が区内の学校の方で、応募の１６人のうちの区内１名ということですか。","respondent":"石川ＳＤＧｓ推進担当課長","answer":"昨年度の応募状況でございますが、応募１６名のうち、区内公立学校につきましては５名、私立につきましては１１名という内訳となってございます。","id":"exchange-015"},{"speaker":"筒井委員","kind":"質問","question":"分かりました。それで、割合的に区内の方が少なかったと思いまして、少し残念だと思っておりますけれども、結局１６名応募されて、区立学校の人が少なかったのですが、今回、１０人の方が提言されて、その結果は、提言された方の感想を一人一人聞いたわけではないので、分からないのですけれども、十分なもの、不十分なもの、様々あると思うのですが、結果的に全て事業化になったということなので、今後の周知に当たっては、非常にこれからの子どもたちにとっても励みになりますので、その点、周知の工夫もぜひお願いしたいと思います。あと、募集に当たって作文で選考されるということですけれども、先ほど新妻委員からもご質問がありましたが、私も作文の段階で、あまりに突拍子もないことははねてしまうと思ったのですけれども、それもはねずに、中身とか熱意を見るということで、これもすばらしいと思っています。提言した生徒も、お互いすり合わせて納得した上で進めていく形なのでしょうか。そのときに、提言した生徒は、もう少しこのようにやりたかったのに、区からいろいろアドバイスを受けて修正せざるを得なかったときに、その生徒から何か不満の声とか、おかしいという声はなかったのですか。検討会の状況というか、その辺りを教えてください。","respondent":"石川ＳＤＧｓ推進担当課長","answer":"最初の作文テーマから、検討会を通じて提言内容につながるプロセスの中で、区側ですとか委託事業者で、提言内容を意図的に変えることは本当にございませんので、その点については改めて否定をさせていただければと思います。どちらかといいますと、寄り添って、まさに伴走支援で、中学生と高校生で進捗状況は人によって変わりますが、あくまで委託事業者が一対一で寄り添って、その子が本当に何をしたいのかを突き詰めて、一緒に考えていくというプロセスの検討会となっております。","id":"exchange-016"}]},{"id":"topic-02","title":"特定事件調査を行います。特定事件調査のまとめ","agenda":"特定事件調査を行います。特定事件調査のまとめ","exchanges":[{"speaker":"安藤委員","kind":"確認","question":"確認なのですけれども、今日も中高生リバースメンター事業について議論をしたのですが、本日の議論はどのように反映させる流れなのか、そこだけ伺います。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-017"},{"speaker":"あくつ委員","kind":"確認","question":"確認で、今日、いろいろな質疑がありましたけれども、そこについては新しいものを、今まとめていただいたのは、委員長と副委員長でまとめていただいていますけれども、今日の議論は委員長と副委員長でまとめていただくということでいいのですか。それを次の委員会にという話ですか。当日配られるものを確認するということでいいですか。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-018"},{"speaker":"あくつ委員","kind":"質問","question":"その上で、また別のことについても、今日この中であればということですか。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-019"},{"speaker":"安藤委員","kind":"質問・要望","question":"公共施設等総合計画についての（１）ですが、ＰＦＩ等については、共産党としては意見として、当委員会では反対の意見を述べてきたものです。今の状況だと、十分な区民理解を得ることという文言で終わっているのですが、こうなりますと、ＰＦＩ等の導入を認めることが前提というのが固定化する表現になっているように見えるので、できれば慎重かつ丁寧に検討を行うで終わってほしいと、これは要望です。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-020"},{"speaker":"安藤委員","kind":"質問・要望","question":"行政評価の（５）ですけれども、ゼロベース査定やサンセット条項等の仕組みを活用しとあるのですが、これらについては、共産党としてもろ手を挙げて賛成する内容でもないですし、委員会として意見は出ましたけれども、十分に議論されたわけではないと思うのです。ゼロベース査定というのも、既存の前提や過去の実績にとらわれず、全てをゼロから見直すこととされていますけれども、私たちの感覚でいうと、過去の実績はむしろ考慮されるべきだと思いますので、単純によいことだとも言えないと思うのです。したがいまして、この文言については外していただきたいと思うのですけれども、いかがでしょうか。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-021"},{"speaker":"筒井委員","kind":"質問","question":"行政評価について、（２）番で、全事業を対象とする事務事業評価は作業量が多く負担が大きいことから、制度見直しも含めとあるのですけれども、見直しも含むという話も出ていたのですか。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-022"},{"speaker":"こんの副委員長","kind":"提案","question":"議事録をきちんと記憶しているところではないですが、この部分については、皆さんがこの委員会で発言した議事録の中から、こういう趣旨の発言、こういう提案があって、ここに載ってきているので、当然、見直しもというご提案、ご要望があったところでの文言になっております。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-023"},{"speaker":"あくつ委員","kind":"確認","question":"今の件で確認ですけれども、これは一番最後に書いてあるとおり、本委員会での議論で委員より出された意見とかを本まとめに活かしてという内容になっていますから、別に議会の総意として出すとか、何か合意をして出すものではないということでいいですよね。議論してきた内容を、議長を通して区長に出すということでしょうから、さっき安藤委員からもありましたけれども、安藤委員の会派としてのお考えは会派の意見として、合意して出すわけではないのだから、ただ、こういうものでいいですかという合意は当然必要だと思うのですけれども。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-024"}]}],"links":[{"type":"minutes","label":"公式の会議録を読む","url":"https://kaigiroku.city.shinagawa.tokyo.jp/index.php/643711?Template=document&Id=7371#one"},{"type":"official","label":"公式の会議録一覧","url":"https://kaigiroku.city.shinagawa.tokyo.jp/index.php/100000?QueryType=new&Template=list&Cabinet=20&TermStart=2026-01-01&TermEnd=2026-12-31"}],"sourceMeta":{"pages":0,"characters":24795,"voices":88}},{"id":"r08-20260416-22","meetingId":"r08-m0405","date":"2026年4月16日","dateIso":"2026-04-16","committee":"まちづくり・公共交通推進特別委員会","time":"午後 １時００分～午後 ２時３９分","status":"正式会議録","sourceType":"formal","overview":"まちづくり・公共交通推進特別委員会の会議録から、実質的な質問・確認・意見・要望と答弁・対応を28件整理しています。","topics":[{"id":"topic-01","title":"特定事件調査","agenda":"特定事件調査","exchanges":[{"speaker":"田中委員","kind":"質問・要望","question":"ご説明、ありがとうございます。前々からお話ししておりまして、今、やや具体的なことはご説明いただいたのですが、学識経験者が６名ということです。以前の学識経験者の方々は法学部の先生が３人だったのですが、その３人の先生は今度の学識経験者６名の中に入るのか。庁舎跡地の活用なので、私、個人的には法学部より、今も少しご説明がありましたけれども、まちづくりの専門的な知見のある方にお願いしたいと思っているのですが、そこの確認をさせていただきたいと思います。","respondent":"泉広町事業調整担当課長","answer":"委員構成のお話でございます。まず、令和５年から開催してまいりました品川区庁舎跡地等活用検討委員会には、委員からご案内いただきましたように３名の学識経験者に入っていただいてございましたけれども、その３名の方が今回の委員会にも入るかというところのご質問につきましては、今回は入らないことを想定してございます。もう１つ、委員構成について、もう少し詳細なところでございますけれども、かねてから広域的な目線を持ってというようなところでご指摘もいただいておりました。そういったところのご指摘も踏まえまして、今回考えてございますのは、例えば民間活力を活用したような公有地活用事業におきまして、計画策定等の実績を有するような方、いわゆるまちづくりであるとか都市計画の専門の方。また、今回は官民連携事業を想定してございますので、そういった民間活力を導入する仕組みにつきまして経済的な観点からもご意見をいただけるような方など。または、幅広な区民ニーズを取り入れてございますので、そういったところの関係の皆様をお呼びしたいと考えてございます。","id":"exchange-001"},{"speaker":"田中委員","kind":"質問","question":"これまでの検討経過として、ずっとご尽力いただいて様々な議論を重ねてきたことと、今後この策定委員会で話し合われることとの整合性といいますか、今までの議論は当然踏まえた上での検討だとは思いますが、ややまちづくりの視点よりは違う住民生活というか、そういう層に重点を置かれたような答申といいますか、今まではそうだったと思うのです。要はこれまでの検討経過を踏まえつつなのですが、どの程度拘束を受けるのでしょうか。それはそれで、議論は議論で置いておいて、また新たな視点で、特にまちづくりの視点あるいは官民連携の経験がある方が入られることから大きく方向性は変わってくるような気もするというか、今後のことですのでそういうところには期待をしているのですけれども、これまでの検討結果との整合性といいますか、関係性として、新たな策定委員会ではどのようになるものなのでしょうか。","respondent":"泉広町事業調整担当課長","answer":"これまでの検討の経過と関わり方のお話でございますが、令和５年から策定してまいりました庁舎跡地等活用検討委員会のそういった成果の報告みたいなところにつきましては、これはやはり区民アンケートでありますとかワークショップなどを重ねまして、いただいてきた貴重な意見でございますので、そういったところはしっかり踏まえての議論になっていくと考えてはございます。けれども、このたびＯＩＭＡＣＨＩ ＴＲＡＣＫＳが開業いたしまして、かなりたくさんの人が訪れている中で、また新たな視点も加わってくるのだろうと我々も考えてございますので、そういったところの視点も新たに加えながら検討していくことになってございます。","id":"exchange-002"},{"speaker":"塚本委員","kind":"質問","question":"委員構成のところで私もお伺いしたいのですけれども、これまでの品川区庁舎跡地等活用検討委員会の構成メンバーから比べると大分人数も減ったし、委員の構成も学識経験者と区議会議員に絞られているということです。学識経験者が６名いらっしゃるような検討委員会は、過去にもあったかもしれないですけれども、私の知る限りでは、なかなか今までとは少し毛色の違う、学識経験者が大変多い委員会かと思いました。こういう構成になったことに対する考え、どうしてかを聞きたいです。あと、学識経験者というところで、どうしてもアカデミックなお話が得意というか専門とされる方々ばかりになりはしないかと少し思っていて、やはり現場というか現場経験というか、まちづくりとかにぎわいとかいろいろなことについて、まちづくり全般の現場経験を有しているみたいなことも、やはりすごく大事なのではないかなと思うのですけれども、そういった視点についてはこの構成員の決定の中でどのように扱われているのか、位置づけられているのかをお聞きしたいです。","respondent":"泉広町事業調整担当課長","answer":"委員構成に関わるお話でございます。まず、今回の庁舎跡地活用プラン策定委員会は９名と少しコンパクトな委員会であることに加えて、学識経験者の方が６名なので比重的に大きいというところのご質問かと思います。今回、こういった委員構成になりましたのは、先ほどの説明とも重なりますけれども、今後都市計画に関わるような少し専門性の高いお話も入ってくることに加えまして、非常に幅広い区民ニーズをこれまでいただいているところから、そういったところの専門の方もお呼びしたいというところで、学識経験者の方が比重として大きくなっております。ただ、アカデミックな話というお話も今ございましたけれども、今後また詳細の調整が入ってまいりますが、同じような地域性を持ったところで、公有地活用事業でこういった委員会を行っている自治体がありますので、そういった実績を有しているような方をお呼びして議論を深めてまいりたいということで、アカデミックな話ばかりにならないように、そういったところについては留意をしながら今調整を図っているところでございます。いずれにしても、ここは専門分野であるとか導入機能を議論する中では、中立性であるとか公平性が非常に重要なことになってまいりますので、今はこういった委員構成とさせていただいています。","id":"exchange-003"},{"speaker":"藤原委員","kind":"意見","question":"庁舎跡地活用プラン策定委員会の設置に関しては分かりましたけれども、この品川区庁舎は品川区民お一人お一人の財産です。今ぱっとできたのではなく、先代、先々代とずっと品川区に住民税を払っていただいて、代々区民であられた方をはじめ、そういう方たちがつくってきたというか、そういうものであると私は思っています。つまり、何が言いたいかというと、庁舎跡地活用プランを策定するのは分かりますが、やはり議会の重視です。というのは、私たちは区議会議員一人一人、公正、公平な選挙で民意をいただいて議員になっているわけです。住所でいうと広町、地域では大井ですけれども、区全体ということを考えると、区民の代表が議会なのでやはり議会、議員の意見は必ず重視していかないといけないと思うのです。その辺については、どのように考えていますか。","respondent":"泉広町事業調整担当課長","answer":"現庁舎の今後の活用検討でございますけれども、今回は庁舎というところで、古くから区民の皆様に親しまれてきた庁舎、また、敷地であると区としても認識をしてございます。また、一方で今回３名という形で計画をしてございますけれども、今後特別委員会になるのかはこれからかもしれませんが、こういった区議会の場でも要所要所でご説明、ご報告を差し上げながら、皆様方の様々なご意見を頂戴いたしまして、区民間のバランスがしっかり保てているかどうかの視点でぜひ確認をしながら双方進めていきたいと思ってございます。","id":"exchange-004"},{"speaker":"藤原委員","kind":"質問・要望","question":"特別委員会が設置されれば、またそこで１年いろいろなお話が出ると思いますが、私の要望といいますか、庁舎跡地活用プラン策定委員会でこういう話が出ましたからと決めていただかないで、区議会議員がこの中に入っている３人からだけではなく、改めて跡地に関してはこれからいろいろな場所で議員が要望、質問をしていくと思います。ですから、区議会議員が３人入っているでしょうということではなく、議会全体として、また議員として、その辺のことをしっかり考えていただいて、施策として進めていっていただきたいと思うのですけれども、その辺について改めて答弁ください。","respondent":"泉広町事業調整担当課長","answer":"今回、庁舎跡地活用プラン策定委員会に３名の議員の方に入っていただきますけれども、これをもって区議会にご報告をしたですとか、しっかり意見交換がなされたと扱うことは、我々もそういうふうにするつもりはございません。先ほどと重なりますけれども、しっかり委員会の場などを用いまして議論をさせていただきながら、共に進めてまいりたいと考えてございます。","id":"exchange-005"},{"speaker":"えのした委員","kind":"質問","question":"ご答弁、ありがとうございます。ＯＩＭＡＣＨＩ ＴＲＡＣＫＳができて大分にぎやかになって、私たちも視察に行かせていただきましたけれども、先ほど課長から説明があったように学識経験者、都市計画ですとか区民ニーズの専門の方、その中で他の自治体での経験があるというところで、他の自治体でも同じような駅、そして区庁舎、複合施設、そういったものが一体として再開発されたような自治体は、現実事例があるのですか。","respondent":"泉広町事業調整担当課長","answer":"私たちの調べによれば、こういった区分におきまして庁舎に関わらず公有地を活用いたしまして、今回は定期借地の形を想定しているところでございますけれども、そういった制度を活用しながらそういったニーズをかなえるために複合の機能を考えてきた事例は様々あると認識をしてございます。また、計画づくりの過程の中でそういった委員会を立ち上げて検討されてきた自治体も複数ございますので、そういったところを参考にさせていただきながら委員構成の調整を図っているところでございます。","id":"exchange-006"},{"speaker":"えのした委員","kind":"確認","question":"ありがとうございます。確認が取れました。今、人流というか人の流れというか、隣がＪＲ東日本ですから調査などはされているとは思うのですけれども、庁舎跡地活用検討委員会のときにはフリーワークショップやアンケート、対話型市場調査について。","respondent":"泉広町事業調整担当課長","answer":"今後の庁舎跡地活用プランの計画の進め方でございますけれども、これは先ほど委員からございましたとおり、策定委員会の中での議論とともに進めてまいりたいと考えているところでございます。現段階の考えといたしましては、何か今この計画の中で人流データを取って検証を図るみたいなところまでは考えてございません。一方で、ＯＩＭＡＣＨＩ ＴＲＡＣＫＳが開業したというところで、大きくまち全体が変わってきてございますので、区民から意見をいただくような、そういった場面は機会を設けながら進めていかなければならないと思ってございます。また、ＯＩＭＡＣＨＩ ＴＲＡＣＫＳも区民だけではならず、広域的なところから人がいらっしゃっていると思いますので、そういったことの情報をＪＲからもらっていくのか、また、区のほうからしっかり取りに行くのかはこれからの検討になりますけれども、いずれにしても隣接するＪＲ東日本とは連携を重ねながら、この計画の中もつくって突っ込んでいきたいと思っています。","id":"exchange-007"},{"speaker":"石田（秀）副委員長","kind":"提案","question":"全体の話だけ聞きます。跡地の解体を始めるのは、今の予定ではいつとお考えなのか。そうすると、逆算をすると正式な基本設計に入っていくのは令和１０年なのか令和１１年なのか。そこら辺の日程的なことを教えていただきたいということが１つ。それから、学識経験者の方６名においでいただくのであれば、その方々にやはりいろいろなことを考えてきていただきたい。また２００億円の話はしたくないけれども、定期借地の前提というと２００億円の話が出てきてしまう。そうすると、今どこのデベロッパーもゼネコンも提案をしてくるのが、タワーマンションが多くなっている。それから、１つこちらへ離れているだけだけれども、これは相当いろいろなことを考えて計画をしないと、やはりまちは活きてこない。これからどういう評価なるか分からないけれども、非常に駅から完結型です。人流をいかにつくっていくのかが、庁舎も含めて下神明くらいまでの人流をどうつくるかは、重要です。道路を挟んだ反対側の再開発も一緒に考えていくことが必要になってくると思っているので、これは何度も言っているからいいのだけれども、そういうものを１回提案してもらう。そこには、経済効果、学識経験者の方はそういうことも理解している方が来られると思うので、この委員会の中で様々そういうキャッチボールができるような委員会なのかどうなのかが分かれば教えていただきたいと思います。ここで１回止めます。","respondent":"泉広町事業調整担当課長","answer":"１つ目でいただきました全体のスケジュール感のお話でございます。解体がいつ頃からかのお話でございましたが、新庁舎の開庁は令和１１年９月と今お示しをさせていただいていると思います。その後、解体に入りますので、令和１１年度のうちには解体に着手してまいりたいと、大きなスケジュール感としては考えてございます。以後、解体となっていくわけでございますけれども、今度は官民連携事業で選定した民間事業者の計画の進め方でございますが、令和１０年度に事業者を選定してまいりたいと考えてございます。そうしますと、令和１１年度には通常で考えれば基本計画レベルのものが進んでまいりまして、翌年度の令和１２年には基本設計、令和１３年には実施設計までという流れになるのかと考えてございます。ただ、その中では今回都市計画の変更も実施していかなければならないところもありますので、都市計画の手続も踏まえながら、大きくは今のスケジュール感で進んでいくのではないかと見立てているところでございます。もう１つ、庁舎跡地活用プラン策定委員会の進め方、学識経験者のお話でございます。または、もしご存じなければこちらから一定お話を差し上げて、それを踏まえた上での委員から今いただきましたようなあるべき姿と申しますか、理想的な姿みたいなところはお伝えをして、ぜひご意見を頂戴したいというところはやってまいりたいと考えてございます。また、委員会の進め方といたしましても、今キャッチボールのお話がございましたけれども、やはり非常に多くの学識経験者にいらっしゃっていただきますので、そういった方々との意見交換をその中でもしていただく、当然事務局も入りながらしていくと考えてございます。なので、そのような形での議論の深め方ができていけばよいと考えてございます。","id":"exchange-008"},{"speaker":"のだて委員長","kind":"質問・要望","question":"ほかに、いかがでしょうか。私から１点だけ。この会議は公開されるのかどうか。あと、会議録はぜひ全文公開をしていただきたいということで、区民の皆さんにもしっかりとどういった議論がされているのかが分かるようにしていただきたいと思うのですが、いかがでしょうか。","respondent":"泉広町事業調整担当課長、のだて委員長、中道都市開発課長","answer":"まず、会議体について、公開かどうかのお話でございますけれども、今は基本的に公開と考えてございますし、資料も会議が終わりましたらホームページに公開をしたいと考えてございます。ただし、対話型調査のサウンディング調査の結果など、内容によっては慎重に考えなければいけない内容もあるかもしれないと考えられますので、そういったところにつきましては委員会の委員長などとも相談をしながら、考えてまいりたいと考えてございます。しっかりと区民の皆さんも分かるように進めていっていただければというふうに思います。私からは、特定事件調査、新庁舎および大井町駅周辺地区に関しまして、大井町駅前中央通りにおける社会実験の実施についてご報告いたします。広町地区の開発を契機に、来街者に既存市街地の魅力やよさを知ってもらうため、日常のにぎわいを創出し、大井町全体の回遊性を向上させることを目的として実施をしております。内容といたしましては、車道の一部を歩道化し、人工芝またはベンチなどを配置し、道路の新しい使われ方を確認するとともに、地域の活動が継続的に実施できる仕組みを検討するものになります。調査方法といたしましては、歩行者交通量、人流調査、利用者の滞在状況、周辺道路の駐停車利用状況、社会実験エリアの利用者へのアンケート、沿道店舗、キッチンカー、マルシェなどの出店者の方に対してのアンケートなどを行いました。実施日程や場所、周知方法については記載のとおりでございます。１、にぎわいコンテンツ実施概要についてでございます。スケジュールについてですが、左側に記載のとおりで、平日にはお昼のキッチンカーを２台または３台設置し、ランチコンサートを開催いたしました。休日にはキッチンカーを設置するとともに、右側に記載しているような様々なイベントを開催することで、遊ぶ場または買物をする場として道路を活用いたしました。２、居心地のよさの評価についてでございます。ＡＩ解析でございますけれども、調査用のカメラで撮影した映像を用いまして、様々な架空の人物像を設置して、各エリアで何を行いどのような状況か、表情などを含めまして居心地のよさを指標に照らして解析をし、評価を行いました。５つの各エリアの評価でございます。エリア１でございますけれども、にぎわい、滞在を特徴として、大井町に最も近い場所でキッチンカーを設置し、音楽イベントを開催したエリアとなってございます。エリア２は、休憩、にぎわいを特徴として、平日は椅子とテーブルを設置し飲食する場、または休憩する場として活用していただいてございます。","id":"exchange-009"},{"speaker":"松本委員","kind":"質問","question":"ご説明、ありがとうございます。８ページですけれども、休日の通行者数の結果で、通常時に比べると１１月１日については１３％増えたかと思うのですが、一方で同じ休日である１１月２日を見ると少し減っている状況かと思います。イベントをやっているので、通常時と比較すると２日も増えるのかと思ったため、何かあったのかというところで天気も調べてみたのですが、過去のデータを見ると別に雨は降っていませんでした。そこの分析については、今どのようにお考えでしょうか。","respondent":"中道都市開発課長","answer":"まず、周知の方法です。様々な周知を行ったのですけれども、アンケート結果といたしましてはこの社会実験を狙ってここに来た方が非常に少なかったという結果でした。たまたま歩いていて見かけたので、何をやっているのかと立ち寄ったという方が非常に多かったというところで、そうするといわゆる増える、減るもなかなか安定しなかったという実験の結果になってございます。一方で、やはりイベントをやっていると通常よりも増える場面が多かったので、一定程度イベントはやはり効果があると実験等で確認しております。","id":"exchange-010"},{"speaker":"松本委員","kind":"質問","question":"ありがとうございます。先ほど周知方法は２ページでご報告いただいていたかと思います。周知について、原因分析をされていて、この周知方法の中で、今回はどちらかというと比較的に２０代から５０代くらいをある程度想定されていたかと思うので、そうするとインターネット上の周知が結構重要になってくるかと思い、その中でＳＮＳ、Ｘ、Instagramをやっていただいたと。そことの関係で、Ｘだったらいわゆるリツイートと言われているものとかをどのくらいやられたのかを少しお伺いできればと思います。","respondent":"中道都市開発課長","answer":"今委員が言われているとおりＳＮＳで新しくアカウントを設置したので、そうするとゼロからスタートになります。そこに対して、様々なＮＰＯなどもそうですし、商店街とか地域と、区とかも連携しながらやってきて、そこで拡散されたというところで、すみませんが具体的な数字は今手元にないのであれですけれども、そういった形でゼロからスタートはしたのですが、そもそもアカウントを持っている媒体、何と言うのでしょうか。アカウントを既存のアカウントと連携して急に広げていき、また、いわゆる発信も毎日数回やるような形で広域的な発信を試みました。","id":"exchange-011"},{"speaker":"松本委員","kind":"質問","question":"ありがとうございます。多分、ゼロからつくったアカウントでは、短期間ではなかなか伸びにくいのがＳＮＳなのかと思います。そうすると、例えば区長がどのくらい、当日は恐らく区長も投稿されていたりすると思うのですけれども、そういう意味では我々もかと思います。区議会議員とかも含めてどのくらいこのアカウントをリツイートしたり引用したりして、ＰＲをやっていくかが今後多分進めていく上では、重要というか。せっかくやっていることを皆さんに周知していく。それで、取りあえずやったけれども人が増えなかった、人が増えたが多分効果的な後の検証につながっていくのかと思いますので、私もその辺りは今後気をつけておきたいと思います。もう１個気になるところで、今回の考察のところです。やはり、こうしたイベントを住居も含めたエリアでやっていくと、いろいろなお声が上がっていくのは当然なのかと思います。少し気になるのが、喫煙です。ここで喫煙に関する意見がそんなに出るのは、あまりよろしくない。喫煙への嫌悪が意見として上がってきているのは、これはあまりいい状況ではない。少なくとも、いろいろな意見がある中でもここは特によろしくないところだと思うのですけれども、喫煙への嫌悪はもともとここで喫煙している人がいることへの嫌悪なのか、今回のイベントによってこうした喫煙をしている人が見られたのか、この辺りはどのようにお考えでしょうか。","respondent":"中道都市開発課長","answer":"今回のこの喫煙は、やはりそういった椅子やテーブルの空間を設けたところで、そこでいわゆるゆったり休んでいる方が吸われていることに対しての嫌悪ということでいただいております。","id":"exchange-012"},{"speaker":"松本委員","kind":"質問・要望","question":"ありがとうございます。これは要望です。もう１個、その上のにぎわいのところです。今回の１０ページの考察のところで、にぎわいはＴＲＡＣＫＳ、日常的な生活環境の向上は大井町駅前中央通りという役割分担が求められると書いてしまっているのですけれども、果たしてそれでいいのかは考えないといけないのかと思っています。ここの部分はどのようにお考えでしょうか。もっと言ったら、大井町駅前中央通りの周辺の商店街の方たちはむしろにぎわいをこちらにもという思いがあっていろいろと動かれていると思うのですが、ここは区としての認識はいかがなのかを伺えればと思います。","respondent":"中道都市開発課長","answer":"すみません。ですので、いわゆる生活していく中で少しここでひと休みをするような、軽い日常の憩いの空間みたいな形で、大井町駅前中央通りに機能を設けていきたいと考えてございます。一方、今回は委託の中でこういったイベントを様々やってきましたけれども、まずは周辺の商店街の方にも道路空間でこういうことができるのだと知っていただくのも１つの目的でございます。その中で、地域の方が実際にそれを見てどのように今後考えていくのか、そういった機運調整も今回の実験の目的になってございます。","id":"exchange-013"},{"speaker":"松本委員","kind":"意見","question":"最後は１件だけにしておきますけれども、商店街の皆さんへの伝え方も気をつけていただければと思います。お祭りとか何でもそうですけれども、お祭りをやろうとすると実行する側は盛り上げていきたいし、でもそれに対して夜勤で昼は寝ているからやめてくれという側も両方いて、これはどちらの意見も出てくるだろうと思います。その中で、どこかで落としどころを見つけることが行政のすごく難しいところだとは思うのですけれども、こういう考察の書き方をしてしまうと商店街の方たちもびっくりされる可能性もありますので、そこはうまく伝え方も考えていただきつつ、また、商店街の皆さんの声も聞いていただきながら、今後の社会実験をやっていただければと思います。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-014"},{"speaker":"えのした委員","kind":"確認","question":"ご説明、ありがとうございます。地域の方たちのお声が一番だとは思いますが、なかなかバランスが難しいと思いつつも、４ページのエリア１で音楽イベントによる観客同士の交流を期待したが、評価としては見られなかったと入っています。ですが、２ページ目の実施したコンテンツの内容を見ると、ランチビレッジ、スポーツフェス、路上でチョークアートといろいろありますけれども、その中でやはりランチビレッジのキッチンカー購入者が約７００人で、人数的には一番多く示されておりますし、コンサート鑑賞者も約２００人と、路上アートと同じくにぎわっていたと感じます。交流を期待したがあまりなかったというのは、キッチンカーでアルコールは販売されていたのですか。最後の考察のところにも、逆ににぎわい、音、夜間、飲酒には強い拒否と記載があり、本当に松本委員がおっしゃったとおりで、にぎわいをつくりたい方と、やはりにぎわいがあるとどうしてもそういった音ですとかアルコールで何か問題がというのも、強い拒否という書き方がせっかく期待をしていたのに、その拒否はどこが拒否をしているのか。こちらを確認したいです。","respondent":"中道都市開発課長","answer":"アルコールは、販売してございません。当初、区といたしましても夕方から夜８時くらいまでアルコールのキッチンカーを出して、こういった夜の涼んでいるときにそこでお酒を飲むみたいな、そういった交流の場もあってもいいのかと考えて計画を進めていました。ですけれども、地元民にそういったお話をしたときに、そういった夜の道路の使い方に対して非常に強い拒否がありまして、様々時間をかけて調整はしてきたのですけれども、第１回というところもございまして、今回はそういったキッチンカーの設置は取りやめて実験を開催いたしました。","id":"exchange-015"},{"speaker":"えのした委員","kind":"意見","question":"アルコールの販売がなかった。私も音楽イベントが好きですし、外のイベントも個人的にも好きですし、やはり夜間でなくてもお昼に他の自治体での大きな公園ですとか音楽イベントでやはりアルコールが出されていますし、過度に飲まれるのはまた別かもしれませんけれども、適度であれば交流を促す作用があるのかと考えます。私は、昨日もある一般社団法人のお披露目会と企業の新しい商品のパーティーみたいなものにも参加してきたのですが、やはりアルコールで乾杯した後に交流が始まって、皆さん名刺交換をすごく活発にされていて、このイベントとは違うとは思いますけれども、企業もそういったことを重要視しているからこそ出しているのではないかと今改めて実感をしています。例えば、反対の声がどのくらいあったですとか、そもそもアルコールを出していないのに強い拒否感と、これは実験もしてないわけです。今後、実験をする可能性があるのか。また、今はアルコールの話だけになりましたけれども、こういったイベントをやると喫煙以外に騒音だけではなくてごみの問題も入っていなかったのですが、やはりごみとか清掃について地域の方はこういったイベントで気にしますので、その辺は今回どのようなお声があったのか、そちらもお聞かせください。","respondent":"中道都市開発課長","answer":"まず、ごみとか清掃の件でございますけれども、そちらはやはり非常に気にされている方が多いと実験する前にも意見交換の場で分かりましたので、今回の委託の中でそういった清掃活動、またはごみ箱の設置で毎日のごみの取替えみたいなことは行ってきました。アルコールの件でございますけれども、区といたしましてもやはりアルコールがもたらす人と人との交流の効果みたいなところはもちろん認識はしている中で、今回実験でもそういったことをしていきたかったところでございますけれども、時間をかけて様々そういったご説明をしたのですが、やはりご理解をいただけませんでした。行政としてそういった声が強くあった中でも開催することはもちろんできたとは思うのですけれども、今回、第１回なのでそのように開催するかどうか悩んだ結果、私といたしましてはまずは地域のそういったお話もございましたので、そこはそこで受け止めて、まずは道路でどういったことができるのかを見ていただく。そういった形でまずご理解をいただければと、今後につなげていきたいと考えたところでございます。","id":"exchange-016"},{"speaker":"えのした委員","kind":"意見","question":"ありがとうございました。最初に導入するとき、どんたく祭りの関係者にやはりどんたく祭りでトイレを借りているのだと、レンタルしているからそのレンタル代も結構するから、そういったときに使用できませんかとお話もあったので、その辺をどのようにお考えなのかお聞かせください。","respondent":"中道都市開発課長","answer":"まず、トイレのお話でございますけれども、特にどんたく祭りとかそういった大型イベントをやるときにトイレの問題がいつも出てくることは、区としても認識してございます。今回の社会実験では、特に仮設トイレを設置するとかそういうことはなくて、駅前のトイレを使っていただくことを促してきました。今、委員からご提案がございましたトイレトラックのそういった利用につきましては、また関係所管と検討いたしまして、今年度そういったことに取り組めるのか。常時トラックを置くとなると空間スペースが減ってしまうというバランスもございますので、そういったところも検討しながらいきたいと考えてございます。","id":"exchange-017"},{"speaker":"田中委員","kind":"確認","question":"重ならないように質問していきます。８ページの周辺道路への影響についてですが、これは今回の実証実験をする場所にパーキングがあったけれども、それを外したことに伴って周辺にどう影響があるかという視点だと思います。この憩いの場所に来るために外から車でということの要素は入っていないという意味で捉えていいのでしょうか。まず、そこを確認したいと思います。","respondent":"中道都市開発課長","answer":"今、委員からお話がございましたとおり、このイベントに対して車で来場された方は特段いらっしゃいませんでした。","id":"exchange-018"},{"speaker":"田中委員","kind":"質問","question":"歩行者といいますか、徒歩や公共交通機関を使って来られる方は問題ないと思いますが、例えば車でこのイベントに来ようとか、また、もっと言うと自転車で来ようとしたときには、先ほどのトイレの課題も１つあるのですけれども、やはりこの場所に来るに当たっての駐車場、駐輪場のことも課題になるのかと思います。まず、８ページのこのイベントをやるに当たって、周辺に新たな駐車場なり駐輪場が必要だという視点での調査ではないですか。そういう意味合いは含まれていないのでしょうか。","respondent":"中道都市開発課長","answer":"まず、この大井町駅前中央通りには警視庁のコインパーキングがございまして、非常に毎日このパーキングの利用者が多いことは社会実験前に認識している状況でございます。今回、こういったイベントをするに当たりまして、そこを約３週間利用停止ということで警視庁と協議いたしまして、周知いたしました。いわゆるここのどんたく通り、大井町駅前中央通りの道路の機能といたしましては、非常にコインパーキングが重要な要素になっている、日常生活の中でなくてはならない機能であることは事前に把握もしてございまして、それがどういう影響を及ぼすのかを調査いたしました。結果といたしましては、やはり店舗に配達をするとか、または車内で休憩をする営業職の方もいらっしゃいましたし、中でパソコン作業をするとかそういった車内でお仕事をされているというような使われ方も把握してございます。それがなくなったときに、どういうふうな影響を及ぼすのかがこの調査です。結果として、周辺にそういった機能を、いわゆる駐停車について、コインパーキングとかに止める形でもなく、この時期も今ＯＩＭＡＣＨＩ ＴＲＡＣＫＳの工事車両で満車の状態のコインパーキングが非常に多かったところもあるとは思うのですけれども、周辺に影響を及ぼしてしまったことが分かりました。","id":"exchange-019"},{"speaker":"田中委員","kind":"質問・要望","question":"そういう意味でも実験の意味合いをすごく理解しましたが、例えばこのイベント、人を呼び込むという視点で今後事業を行うに当たって、有効活用できる部分があると思います。それと、１０ページですけれども、こういう実験をする本来の目的は、やはり大井町全体のにぎわいを創出する上での役割として、こういう公共交通空間を有効に活かすことが求められると思うのです。そういうところとの連携もうまく、三ツ又商店街含め連携していけるような、今後点と点を線にするだけではなく、もっと面に向けた取組もぜひ心がけてやっていただきたいと思います。一番下に２月からのスケジュールがあります。８月に大井どんたく夏祭りがあったり１０月にハロウィンがあったりということですけれども、こういうふうに書いているということはもう今年もどんたくなりハロウィンで前回のような形で開放するようなものにするのか、たまたまこういう期間と実証実験の期間がこういう関係性がありますとだけを示しているのか。ここの意味合いをお伺いしたいと思います。","respondent":"中道都市開発課長","answer":"まず、令和７年度の社会実験でございますけれども、初日にハロウィンのイベントと合わせて社会実験を開始いたしました。令和８年度につきましては、大井どんたく夏祭りと社会実験の連携をしていきたいと考えてございます。そういった祭りでの課題もあったり、逆に言うとそこをきちんと歩道として区画をしていることによって、うまく効率的に運営ができるのかどうかも見ていきたいと考えているところもございます。今回はどんだく夏祭りと連携してこの社会実験を行っていきたいと考えてございます。","id":"exchange-020"},{"speaker":"藤原委員","kind":"質問・要望","question":"実証実験の結果を拝見しました。まずそもそもですけれども、この実証実験をするのに１回の実証実験で５,０００万円近く予算を使っています。そうすると、この実証実験だけで１億円近く税金を使うわけです。私は、今年度の実証実験でもう方向性を決めていくと思っているのですけれども、実験２回で１億円。だから、方向性を今年度の実験で決めていただきたいと思うのと、ＡＩを使って人の気持ち、やってきた人の心と言いますか。今年度実証実験をするとまたいろいろな分析が出ると思うのですけれども、するべきかという思いも少しあるのです。１億円もかけてという思いも実験に関してはあるのですが、その辺についてはいかがでしょうか。","respondent":"中道都市開発課長","answer":"まず、予算、お金、費用の件でございますけれども、昨年度は５,０００万円、今年度も５,０００万円で合計１億円の支出になります。今年度は、東京都からこういった都市計画道路の再編に向けた検討というところで、半額補助が入る形での調整ができましたので、歳入といたしましては２,５００万円入る予定となってございます。それにしても、計７,５００万円という大金でございますけれども、そこはしっかりとこういった実験を行って、その結果を今後に反映していきたいと考えてございます。そういったところで、皆様の税金をきちんと使っていきたいと考えてございます。あとは、イベントを令和７年度は３週間行ってきまして、確かに委員の言われたとおり毎日にぎわっていたかというと、そうではないときももちろんございました。一方、休日はイベントを開けばやはりそこに人が滞在して何か飲食をするとか、２時間、３時間いらっしゃる方は少なかったのですけれども、やはり１時間くらい道路に滞在して、そこで子どもと遊んだりとかして帰られる方は多かったのかと思ってございます。ここの大井町駅前中央通りの将来的な使われ方として、道路の在り方もあるのですけれども、そういった長時間滞在することを目的とするのか、それとも軽い滞在という形で、でもあそこに行くと休めるから散歩のルートとして使おうかみたいな、そういった回遊性の向上みたいなことも考えられるかと思いますので、そこは今後また今年度の社会実験も踏まえて考えていかなければいけないところかと思ってございます。今後の方向性といたしましては、ＯＩＭＡＣＨＩ ＴＲＡＣＫＳの開業前、開業後という形で令和７年、令和８年で実験をいたしますので、まずはそこで実験結果を踏まえて方向性を出していきたいとは考えてございます。","id":"exchange-021"},{"speaker":"藤原委員","kind":"質問・要望","question":"これは民間のことですが、ＯＩＭＡＣＨＩ ＴＲＡＣＫＳができて、そしてどんたく通りまでの間に大きい民間の駐車場はあるわけです。ただ、分からないですけれども、その民間の大きな駐車場が再開発とかでどうなるかということもありますし、永遠にあの駐車場が確保されているかもしれないし、されていないかもしれないということもあります。その辺も次の実証実験、２,５００万円が都から入ってくる、それでも合計で７,５００万円です。区の全体のと考えたら、７,５００万円は割合的には大きくないかもしれませんけれども、やはり７,５００万円も使って実験するわけですから、改めて方向性だけは出していただきたい。そして、実証実験をしてしまったのだから、必ずやらなければいけない施策なのだではなくて、実証実験をした結果をきちんと踏まえてどういう方向性にするかをしっかり考えていただきたいと思うのですが、いかがでしょうか。","respondent":"中道都市開発課長","answer":"まず、今後の考え方といたしましては、実験を２回やってそれに対してやったから必ず今後に結びつけるかではなくて、今回は実験ですのでやはり実験の結果を踏まえて今後の方向性をきちんと検討していくものかと考えてございます。","id":"exchange-022"},{"speaker":"石田（秀）副委員長","kind":"質問・要望","question":"社会実験について１つ聞きたいのは、せっかくこれだけやったのですけれども、回答は１３５件ということをどう捉えていらっしゃるのか教えていただきたいです。あと、１０ページ目に非常にいいことがたくさん書いてあります。例えば、小さい子どもがいたら、公園の水が流れているところで、小さい子どもなんかはそこにつかったり浴びたり、公園なんかは憩いの場という感じが夏なんかは特にあるではないですか。大井町全体と書いてあるのだけれども、駅周辺の地元の魅力的な場所というのですが、これは飲食だとかいろいろな、歩くということは散歩道のことなのかどうかよく分からないけれども、散歩をしながら歩いても景色がよくていいなんて思える場所、これをつくっていくのは相当大変です。もちろん役所がやることだから、一歩前へ出ることは非常に難しいのかもしれないけれども、せっかくこれだけいいことが書いてあるので、それに向かって何を具体的にどうしていこうと、今の段階でも結構なのでどう思われているかだけ話を聞きたいと思います。","respondent":"中道都市開発課長","answer":"まず、大井町のまちですけれども、やはりまちの特徴とすると業務もあって商業もあって住宅もあって、それが混在しているのが大井町なのかと思います。昨年度、その気持ちで望んだのですけれども、それと同等くらいの非常に強い気持ちをお持ちの方もいたというところで、ちょうど協議の結果、ご説明したような対応をしてきたところでございます。令和７年度には様々な意見をいただきまして、今年度につきましては、いわゆるこういった猛暑の中でのどんたく通りのこういったイベントの中で、実験の中で何ができるのか。いわゆる日陰みたいなところとかミストみたいな、今、水のお話が出ましたけれども、ミストとかそういったところはいろいろとやって、そういう形で子どもに来ていただけるような道路空間にするよう挑戦していきたいと考えてございます。また、最後の１０ページに掲げている内容につきましても、やはり今後ＯＩＭＡＣＨＩ ＴＲＡＣＫＳもそうですけれども、それ以外の部分にもまちづくりの機運があるのが今の大井町の状況でございます。そういったところの状況も見ながら、やはり既存のこういった道路空間、また、公共施設といったところを考えていくことが重要かと思っています。なので、まずは、私としましては、まちの状況もきちんと見ながら、こういった公共空間の考え方を整理していきたいと思っています。","id":"exchange-023"},{"speaker":"石田（秀）副委員長","kind":"質問","question":"社会実験なのでお願いだけしておきますが、ほかの地域でも、例えば１か月に２回とか、１か月に１回でもいいのだけれども、社会実験が終わった後にこういうところを使って定期的にイベントをやっていこうという考えもあります。歩道とかしゃれたお店をつくっていくとか、社会実験があった後にこれを具体的にやっていくには相当必要性を持って検討していかないとと思うけれど、そこにちょっとしたカフェみたいなものをつくったら、もしかしたら周りの方からはすごく怒られるとか、いろいろあるわけではないですか。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-024"},{"speaker":"若林委員","kind":"意見","question":"先ほど、都の助成金が２,５００万円とありました。これは都の助成金が入ることによって今年度何か縛りが出てくるのか教えてください。","respondent":"中道都市開発課長","answer":"実験の内容について、特に何か東京都の条件等があるものではございませんので、昨年度と同様に様々区としまして検討していきたいと考えてございます。","id":"exchange-025"},{"speaker":"若林委員","kind":"質問","question":"都市開発で見る、いわゆる社会実験の中での大井町駅周辺全体のエリアは、どういうイメージなのでしょうか。","respondent":"中道都市開発課長","answer":"まず、大井町駅周辺地区ではまちづくり方針を策定してございます。そこに合わせまして今後都市開発課並びに都市計画課、そういったところで対応していきたいと考えてございます。","id":"exchange-026"},{"speaker":"若林委員","kind":"質問","question":"都市開発課と都市計画課で検討して、今のお話だとさらに広げていくお考えだと認識をいたしました。今回東京都の補助も入るみたいですが、取りあえずさっき１０ページでご紹介がありましたけれども、今は大井町駅前中央通りに特化したお話の実験だけで、２年目も同じ大井町駅前中央通りのみをある意味ではメインとした実験を都の補助金も使って５,０００万円でやる。今年度は何をするかというと、１０ページに書いてあるとおり居心地のよさとか涼しさをプラスするとか技術的検証や社会的検証をして、ここにも書いてある理想のイメージを目指すと。さっき藤原委員からこの２年で１億円かかっているのだから、方向性がこれで見えるのですよねと、見えるようにしましょうというお話で、問いかけがあったのですが、これは何年実験したらいいのでしょう。どうもこのプラスは取ってつけたような、言葉遣いがすみません。私個人的には、回遊性は本当に大事なのだけれども、先が見えないというか、１０ページを見ていて本当にこれから何年かかって何がゴールなのだろうか。最終的には地域の担い手が増えるのはどういうことなのだろう。商店街が発展することなのか、町会が発展することなのかが見えないので、どういうことなのですかという聞き方を僕はできないような気がするのですけれども、これは意見として言わせていただきます。質問にはいたしません。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-027"},{"speaker":"のだて委員長","kind":"質問","question":"ほかに、いかがでしょうか。なければ、私から幾つか伺いたいと思います。まず、いろいろアンケートを行われており、来街者のアンケートは出ておりますけれども、事業者の方からのアンケートの声ではどんな声があったのかを伺いたいです。あと、６ページの来街者アンケートの結果ですけれども、エリア４の満足度が一番高いです。でも、ＡＩの評価指標で見るとあまり変化がなかったということで、これをどう見ていらっしゃるのか伺いたいと思います。一方で、エリア２は青空図書館とかがあって満足度が高かったと思うのです。この評価の仕方についての区の考えを伺いたいと思います。","respondent":"中道都市開発課長","answer":"まず、事業者のアンケートでございます。事業者は、周辺の飲食業等の方につきましては、やはりこういったキッチンカーを出すことに対して、自分のところの営業にもつながるので期間限定でやっていただきたいというお声もいただいています。また、もちろんこういった空間ができることによって、自分が今後出店できるのかみたいな前向きな回答もいただいており、こういった新しいことをやることに対しては非常に様々な声をいただきました。続きまして、来街者のアンケートでエリア４が非常に好評になっているところでございますけれども、区といたしましてはエリア４でのアンケートの結果が少なかったので、非常に高かったけれどもアンケート数も少なかったので、そこの部分は控えた評価をしてございます。ＡＩと実際のアンケートによる評価の差につきましては、グラフの中で緑色の線につきましては実際にアンケートでお声をいただいたもの、赤色の部分につきましてはイベントのときのＡＩの評価で、グレーの部分につきましては平常時、平日のＡＩの評価といった形で示してございます。そうすると、やはり差が出ておりますので、ここの部分につきましてはどのような差があったのか、実際の声とＡＩの差も見ながら行政として捉えています。まず、そこについてはいわゆる１つの、コンピューター上の一定の基準とした評価になっていますので、ここに対してエリア１からエリア５の差分みたいなところはきちんと評価がされているものなのかと考えてございます。あとは、実際に人が書いたアンケートとＡＩとの差も、もちろんありますので、そこはそこで、その差の考え方でＡＩの評価を見ていく、ひもづけて評価を確認しています。","id":"exchange-028"}]}],"links":[{"type":"minutes","label":"公式の会議録を読む","url":"https://kaigiroku.city.shinagawa.tokyo.jp/index.php/931508?Template=document&Id=7373#one"},{"type":"official","label":"公式の会議録一覧","url":"https://kaigiroku.city.shinagawa.tokyo.jp/index.php/100000?QueryType=new&Template=list&Cabinet=22&TermStart=2026-01-01&TermEnd=2026-12-31"}],"sourceMeta":{"pages":0,"characters":29037,"voices":89}},{"id":"r08-20260423-10","meetingId":"r08-m0405","date":"2026年4月23日","dateIso":"2026-04-23","committee":"議会運営委員会","time":"午後 １時００分～午後 １時０７分","status":"正式会議録","sourceType":"formal","overview":"議会運営委員会の会議録から、実質的な質問・確認・意見・要望と答弁・対応を4件整理しています。","topics":[{"id":"topic-01","title":"特別委員会の調査事項等","agenda":"特別委員会の調査事項等","exchanges":[{"speaker":"安藤委員","kind":"質問・要望","question":"１点、まちづくり・公共交通推進特別委員会の備考で、大井町駅周辺地区の回遊性とあるのですけれども、私たちとしては回遊性という名の下に、例えばＣ地区や下神明など、周辺地区の新たな再開発を、そこに住む地域住民の頭越しに議会のほうで進めるようなことがあってはいけないと思っているのですが、特別委員会の運営に当たってはその点、留意していただきたいと思うのですけれども、いかがでしょうか。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-001"}]},{"id":"topic-02","title":"議会選出委員の推薦","agenda":"議会選出委員の推薦","exchanges":[{"speaker":"安藤委員","kind":"質問","question":"合わせると５名ということですけれども、共産党としては、１番の庁舎跡地活用プラン策定委員会のほうにぜひ立候補したいと思っているのですが、例えば１番と２番を分けるというよりも、合わせてそちらで考えていただいて、庁舎跡地活用プランのほうに共産党を入れていただくとはいかないでしょうか。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-002"},{"speaker":"あくつ委員","kind":"質問・要望","question":"配分はそれで結構かと思いますけれども、細かいことを教えてください。区の庁舎跡地活用プランの策定委員会については、ここ何年間かずっと議員を入れてくれという話をいろいろなところでしてきて、ようやくこういう形で出てきたのですが、もし何か執行機関から全体の構成が何人で議会として何人出してほしいというご説明があったのであれば教えていただきたいと思います。","respondent":"大澤区議会事務局長","answer":"４月１６日のまちづくり・公共交通推進特別委員会で説明があったと聞いておりますけれども、委員の構成は９名、学識経験者が６名、区議会議員が３名となっております。","id":"exchange-003"},{"speaker":"あくつ委員","kind":"確認","question":"分かりました。そのときどういう質疑があったのか分かりませんけれども、学識経験者が６名、大学の先生なのでしょうか、ちょっと分かりませんけれども、区議会議員が３名ということで、私が思っていた形とは違うのかなというところもあるのですが、入れていただいたところは敬意を表しますので、なぜそのような構成になったのかというのは特別委員会で質疑があったのかもしれないので、またそれは確認させていただければと思います。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-004"}]}],"links":[{"type":"minutes","label":"公式の会議録を読む","url":"https://kaigiroku.city.shinagawa.tokyo.jp/index.php/677927?Template=document&Id=7375#one"},{"type":"official","label":"公式の会議録一覧","url":"https://kaigiroku.city.shinagawa.tokyo.jp/index.php/100000?QueryType=new&Template=list&Cabinet=10&TermStart=2026-01-01&TermEnd=2026-12-31"}],"sourceMeta":{"pages":0,"characters":2783,"voices":21}}]);
